-- Migration 1723: Food overrides for Guam (GU)
-- 965 traditional dishes, street food, beverages, snacks, staples
-- All values per 100g. Source: research (nutrition databases, manufacturer data)

INSERT INTO food_nutrition_overrides (
  food_name_normalized, display_name,
  calories_per_100g, protein_per_100g, carbs_per_100g, fat_per_100g,
  fiber_per_100g, sugar_per_100g,
  default_serving_g, default_weight_per_piece_g,
  source, variant_names,
  food_category, restaurant_name, default_count, region, notes, is_active
) VALUES
('hineksa_agaga_guamanian', 'Hineksa Agaga', 178, 3.5, 38.2, 1.2, 1.8, 0.4, 180, NULL, 'research', ARRAY['hineksa agaga', 'plain white rice version', 'achote powder version'], 'traditional', NULL, 1, 'GU', 'CHamoru red rice is the cornerstone of Guam''s cuisine, colored and flavored with achote (annatto) seeds. It is served at nearly every fiesta, gathering, and daily meal.', TRUE),
('bringhe_guamanian', 'Bringhé', 210, 3.8, 32.5, 8.5, 1.5, 3.2, 150, NULL, 'research', ARRAY['bringhé', 'banana leaf wrapped', 'baked version'], 'traditional', NULL, 1, 'GU', 'A festive CHamoru dish of glutinous rice cooked in coconut milk and turmeric, wrapped in banana leaves and steamed or baked. It is considered the CHamoru version of paella and is central to fiestas.', TRUE),
('titiyas_mais_guamanian', 'Titiyas Mais', 218, 4.5, 42.0, 3.8, 3.2, 1.5, 60, 60, 'research', ARRAY['titiyas mais', 'sweet titiyas', 'thin crispy version'], 'traditional', NULL, 1, 'GU', 'Traditional CHamoru corn tortillas made from masa harina, a staple bread of Guam passed down through generations. They are cooked on a buduk (cast iron griddle) and served with butter or fina''dene.', TRUE),
('titiyas_harina_guamanian', 'Titiyas Harina', 290, 7.2, 52.0, 6.5, 1.8, 2.0, 70, 70, 'research', ARRAY['titiyas harina', 'sweet flour titiyas', 'large fiesta size'], 'traditional', NULL, 1, 'GU', 'Flour tortillas, the wheat-based counterpart to corn titiyas, adopted after Spanish colonial influence. Soft and slightly chewy, often eaten as a snack or with soup.', TRUE),
('kelaguen_mannok_guamanian', 'Kelaguen Mannok', 165, 24.5, 3.2, 6.0, 0.8, 1.5, 150, NULL, 'research', ARRAY['kelaguen mannok', 'spicy version', 'mild coconut version'], 'traditional', NULL, 1, 'GU', 'Grilled chicken marinated and ''cooked'' in freshly squeezed lemon juice with grated coconut, green onions, and hot peppers. One of the most iconic CHamoru dishes, often served at fiestas.', TRUE),
('kelaguen_guihan_guamanian', 'Kelaguen Guihan', 138, 22.0, 2.8, 4.2, 0.5, 1.0, 150, NULL, 'research', ARRAY['kelaguen guihan', 'tuna kelaguen', 'yellow-fin version', 'reef fish version'], 'traditional', NULL, 1, 'GU', 'Raw fish cured in lemon juice with fresh coconut, onions, and donne'' (hot peppers), similar to ceviche. A refreshing CHamoru preparation that showcases the island''s abundant seafood.', TRUE),
('kelaguen_uhang_guamanian', 'Kelaguen Uhang', 112, 18.5, 3.0, 2.8, 0.6, 1.2, 150, NULL, 'research', ARRAY['kelaguen uhang', 'large shrimp version', 'small reef shrimp version'], 'traditional', NULL, 1, 'GU', 'Shrimp kelaguen prepared with lemon, coconut, green onions, and hot peppers. A lighter variation of the classic kelaguen that highlights locally sourced shrimp.', TRUE),
('kelaguen_babui_guamanian', 'Kelaguen Babui', 182, 20.5, 2.5, 9.8, 0.4, 0.8, 150, NULL, 'research', ARRAY['kelaguen babui', 'lechon kelaguen', 'roasted pork version'], 'traditional', NULL, 1, 'GU', 'Pork kelaguen made from grilled or roasted pork marinated in lemon juice with coconut and hot peppers. A rich and savory version of kelaguen showcasing the CHamoru love of pork.', TRUE),
('finadene_guamanian', 'Fina''dene', 45, 1.8, 5.5, 1.5, 0.5, 3.2, 30, NULL, 'research', ARRAY['fina''dene', 'spicy donne'' version', 'coconut milk fina''dene', 'tomato fina''dene'], 'traditional', NULL, 1, 'GU', 'The quintessential CHamoru condiment sauce made with soy sauce, vinegar, lemon juice, onions, and donne'' peppers. Every CHamoru table has fina''dene, used as a dipping sauce and marinade.', TRUE),
('estufao_guamanian', 'Estufao', 248, 26.5, 8.2, 12.5, 1.0, 3.5, 200, NULL, 'research', ARRAY['estufao', 'pork estufao', 'chicken estufao'], 'traditional', NULL, 1, 'GU', 'CHamoru braised beef dish slow-cooked with vinegar, soy sauce, garlic, and onions until tender. The tangy-savory flavor profile reflects Spanish colonial influence blended with local CHamoru tastes.', TRUE),
('chalakiles_guamanian', 'Chalakiles', 145, 14.2, 15.8, 3.5, 0.8, 1.0, 250, NULL, 'research', ARRAY['chalakiles', 'thick porridge style', 'thin broth style'], 'traditional', NULL, 1, 'GU', 'A hearty CHamoru chicken and rice soup that is a beloved comfort food, especially served at funerals and community gatherings. Often made with leftover rice and chicken in a flavorful broth.', TRUE),
('kadu_guamanian', 'Kadu', 65, 6.8, 4.5, 2.0, 0.5, 1.2, 240, NULL, 'research', ARRAY['kadu', 'chicken kadu', 'pork kadu', 'beef kadu'], 'traditional', NULL, 1, 'GU', 'Traditional CHamoru broth or soup, often a simple clear stock made from chicken, pork, or beef with vegetables. Kadu is a foundational dish in CHamoru home cooking.', TRUE),
('lemmai_guamanian', 'Lemmai', 132, 1.8, 28.5, 2.2, 4.5, 5.0, 200, NULL, 'research', ARRAY['lemmai', 'ripe breadfruit version', 'green breadfruit stew', 'roasted lemmai'], 'traditional', NULL, 1, 'GU', 'Breadfruit stew prepared in coconut milk, a pre-Spanish staple of the CHamoru diet. Lemmai (breadfruit) was historically a primary carbohydrate source and holds deep cultural significance.', TRUE),
('chamoru_bbq_chicken_guamanian', 'CHamoru BBQ Chicken', 235, 28.5, 6.5, 10.5, 0.2, 5.5, 180, NULL, 'research', ARRAY['chamoru bbq chicken', 'fiesta marinade', 'spicy version', 'wings version'], 'traditional', NULL, 1, 'GU', 'Marinated chicken grilled over coconut husks or charcoal with a sweet-savory marinade of soy sauce, vinegar, lemon, sugar, and garlic. The signature dish of CHamoru fiestas and backyard barbecues.', TRUE),
('chamoru_bbq_ribs_guamanian', 'CHamoru BBQ Ribs', 295, 22.5, 8.0, 19.5, 0.2, 6.5, 200, NULL, 'research', ARRAY['chamoru bbq ribs', 'back ribs version', 'country-style ribs'], 'traditional', NULL, 1, 'GU', 'Pork short ribs marinated in a CHamoru-style blend of soy sauce, vinegar, lemon, garlic, and sugar then grilled. A fiesta essential that combines Spanish, Filipino, and indigenous CHamoru flavors.', TRUE),
('adobo_guam_style_guamanian', 'Adobo Guam Style', 255, 24.0, 5.5, 15.5, 0.3, 1.8, 180, NULL, 'research', ARRAY['adobo guam style', 'chicken adobo', 'pork adobo', 'chicken and pork combined'], 'traditional', NULL, 1, 'GU', 'CHamoru-style adobo with chicken or pork simmered in vinegar, soy sauce, garlic, and bay leaves, distinct from Filipino adobo by regional spice variations. A daily staple in many Guam households.', TRUE),
('chicken_adobo_chamoru_guamanian', 'Chicken Adobo CHamoru', 242, 26.5, 4.8, 12.5, 0.2, 1.5, 180, NULL, 'research', ARRAY['chicken adobo chamoru', 'boneless version', 'dry adobo flakes'], 'traditional', NULL, 1, 'GU', 'Chicken pieces braised in vinegar, soy sauce, garlic, bay leaf, and black pepper until the sauce reduces to a rich glaze. A comfort food staple reflecting Filipino culinary influence on CHamoru cuisine.', TRUE),
('pork_adobo_chamoru_guamanian', 'Pork Adobo CHamoru', 310, 22.0, 4.5, 22.5, 0.2, 1.2, 180, NULL, 'research', ARRAY['pork adobo chamoru', 'pork belly version', 'pork shoulder version'], 'traditional', NULL, 1, 'GU', 'Pork belly or shoulder slow-braised in vinegar and soy sauce with garlic and spices until tender and glazed. Rich and deeply flavored, this dish is served over red rice at family gatherings.', TRUE),
('suni_guamanian', 'Suni', 112, 1.5, 26.0, 0.2, 3.2, 0.5, 150, NULL, 'research', ARRAY['suni', 'boiled taro', 'taro in coconut milk', 'mashed taro'], 'traditional', NULL, 1, 'GU', 'Taro root, known as suni in CHamoru, is one of the oldest cultivated crops on Guam with significant cultural importance. Boiled, roasted, or used in soups, taro was a pre-colonial dietary staple.', TRUE),
('suni_finadene_guamanian', 'Suni Fina''dene', 125, 2.2, 27.5, 1.2, 3.5, 1.0, 170, NULL, 'research', ARRAY['suni fina''dene'], 'traditional', NULL, 1, 'GU', 'Boiled taro root served with fina''dene sauce, a simple but beloved CHamoru combination. The earthiness of taro contrasts beautifully with the tangy, savory condiment.', TRUE),
('roasted_lemmai_guamanian', 'Roasted Lemmai', 118, 1.5, 27.0, 0.5, 4.8, 4.5, 150, NULL, 'research', ARRAY['roasted lemmai', 'fire roasted', 'oven roasted'], 'traditional', NULL, 1, 'GU', 'Whole breadfruit roasted directly over open fire or coals until the skin chars and the interior becomes soft and starchy. A traditional preparation that was a daily staple for ancient CHamorros.', TRUE),
('boiled_breadfruit_guamanian', 'Boiled Breadfruit', 103, 1.2, 24.0, 0.3, 4.2, 3.8, 150, NULL, 'research', ARRAY['boiled breadfruit'], 'traditional', NULL, 1, 'GU', 'Young green breadfruit boiled in salted water until tender, eaten as a starchy side dish similar to potato. A nutritious traditional food that sustained CHamoru communities for thousands of years.', TRUE),
('aga_guamanian', 'Åga', 89, 1.1, 23.0, 0.3, 2.6, 12.5, 120, 120, 'research', ARRAY['åga', 'latundan variety', 'saba cooking banana', 'señorita banana'], 'traditional', NULL, 1, 'GU', 'Banana, known as åga in CHamoru, is widely cultivated in Guam with many local varieties. Eaten ripe as fruit or cooked green as a vegetable, bananas are integral to CHamoru food culture.', TRUE),
('coconut_crab_preparation_guamanian', 'Coconut Crab Preparation', 145, 22.5, 2.0, 5.5, 0.0, 0.5, 150, NULL, 'research', ARRAY['coconut crab preparation', 'boiled preparation', 'roasted preparation'], 'traditional', NULL, 1, 'GU', 'Ayuyu (coconut crab), the world''s largest land crab, was a prized delicacy in traditional CHamoru culture. Now protected, historical preparations involved boiling or roasting with local seasonings.', TRUE),
('pancit_bihon_guam_style_guamanian', 'Pancit Bihon Guam Style', 195, 10.5, 32.5, 4.2, 2.0, 3.5, 200, NULL, 'research', ARRAY['pancit bihon guam style', 'chicken bihon', 'shrimp bihon', 'mixed meat bihon'], 'traditional', NULL, 1, 'GU', 'Rice noodles stir-fried with vegetables, chicken or shrimp, soy sauce, and calamansi, adapted from Filipino pancit bihon. A fiesta staple in Guam reflecting the strong Filipino cultural influence.', TRUE),
('pancit_canton_guam_style_guamanian', 'Pancit Canton Guam Style', 210, 11.5, 30.5, 5.8, 2.5, 3.0, 200, NULL, 'research', ARRAY['pancit canton guam style', 'pork and shrimp version', 'vegetables only version'], 'traditional', NULL, 1, 'GU', 'Egg noodles stir-fried with pork, shrimp, vegetables, and soy sauce, a Filipino-influenced noodle dish that has become a Guam party staple. Often prepared in large quantities for fiestas and family celebrations.', TRUE),
('lumpia_guam_style_guamanian', 'Lumpia Guam Style', 220, 9.5, 22.5, 10.5, 1.8, 2.5, 100, 50, 'research', ARRAY['lumpia guam style', 'pork lumpia', 'vegetable lumpia', 'fresh lumpia (lumpiang sariwa)'], 'traditional', NULL, 1, 'GU', 'Fried spring rolls filled with ground pork, vegetables, and vermicelli noodles, adapted from Filipino lumpia. A beloved fiesta food in Guam that has been indigenized with local spices and preparations.', TRUE),
('kadon_mannok_guamanian', 'Kadon Mannok', 178, 20.5, 8.5, 7.5, 1.5, 3.5, 250, NULL, 'research', ARRAY['kadon mannok', 'spicy version', 'mild version with potatoes'], 'traditional', NULL, 1, 'GU', 'CHamoru chicken stew cooked in coconut milk with vegetables, onions, garlic, and spices. Kadon (stew) is a cooking style central to CHamoru cuisine, creating rich, creamy, comforting dishes.', TRUE),
('kadon_babui_guamanian', 'Kadon Babui', 265, 20.0, 8.0, 17.5, 1.2, 3.0, 250, NULL, 'research', ARRAY['kadon babui', 'pork belly version', 'pork shoulder version'], 'traditional', NULL, 1, 'GU', 'Pork stew cooked in coconut milk with taro, potatoes, or other vegetables. Kadon babui is a hearty CHamoru dish served over red rice at family meals and community gatherings.', TRUE),
('kadon_pika_guamanian', 'Kadon Pika', 195, 22.0, 7.5, 8.5, 1.5, 2.5, 250, NULL, 'research', ARRAY['kadon pika', 'chicken kadon pika', 'pork kadon pika', 'extra spicy version'], 'traditional', NULL, 1, 'GU', 'Spicy CHamoru chicken or pork stew made with coconut milk and generous amounts of donne'' (hot peppers). Pika means spicy in CHamoru, and this fiery stew is a beloved comfort food.', TRUE),
('tinaktak_guamanian', 'Tinaktak', 215, 18.5, 9.5, 11.5, 2.0, 3.5, 200, NULL, 'research', ARRAY['tinaktak', 'beef tinaktak', 'pork tinaktak', 'chicken tinaktak'], 'traditional', NULL, 1, 'GU', 'Ground beef or pork cooked in coconut milk with green beans, tomatoes, onions, and lemon juice. A CHamoru home-cooking staple that balances the richness of coconut milk with bright acidity.', TRUE),
('fritada_guamanian', 'Fritada', 245, 20.5, 12.5, 12.5, 2.2, 4.5, 220, NULL, 'research', ARRAY['fritada', 'chicken fritada', 'pork fritada', 'mixed meat version'], 'traditional', NULL, 1, 'GU', 'CHamoru braised pork or chicken with tomatoes, bell peppers, onions, garlic, and vinegar. A Spanish-influenced stew that became a CHamoru classic through generations of adaptation.', TRUE),
('hineksa_aga_guamanian', 'Hineksa Aga', 92, 1.0, 22.5, 0.2, 1.5, 0.5, 180, NULL, 'research', ARRAY['hineksa aga', 'jasmine rice', 'short grain rice'], 'traditional', NULL, 1, 'GU', 'Plain steamed white rice, a daily staple in Guam alongside the iconic red rice. White rice is served at every meal and holds equal importance as a base for CHamoru dishes.', TRUE),
('corn_soup_chamoru_guamanian', 'Corn Soup CHamoru', 155, 5.5, 28.5, 3.5, 3.0, 6.5, 240, NULL, 'research', ARRAY['corn soup chamoru', 'cream of corn version', 'chicken corn soup'], 'traditional', NULL, 1, 'GU', 'Sweet corn soup made with fresh or canned corn, often with chicken broth, milk, and simple seasonings. A comforting CHamoru soup that reflects the historical importance of corn cultivation on Guam.', TRUE),
('corn_on_the_cob_grilled_guamanian', 'Corn on the Cob Grilled', 112, 3.8, 22.5, 2.5, 2.8, 5.5, 150, 150, 'research', ARRAY['corn on the cob grilled', 'buttered corn', 'fina''dene corn', 'plain corn'], 'traditional', NULL, 1, 'GU', 'Grilled sweet corn seasoned with butter, salt, and sometimes local spices or fina''dene sauce. Corn has been cultivated in Guam since Spanish introduction and is central to CHamoru food culture.', TRUE),
('boiled_corn_guamanian', 'Boiled Corn', 96, 3.2, 20.5, 1.2, 2.5, 4.8, 150, NULL, 'research', ARRAY['boiled corn'], 'traditional', NULL, 1, 'GU', 'Sweet corn boiled until tender, a simple and beloved preparation in CHamoru households. Often served as a side dish or snack at family gatherings and fiestas.', TRUE),
('chick_pea_guam_guamanian', 'Chick Pea Guam', 164, 8.9, 27.5, 2.6, 7.6, 4.8, 150, NULL, 'research', ARRAY['chick pea guam', 'tomato stew version', 'coconut milk version'], 'traditional', NULL, 1, 'GU', 'Garbanzo beans prepared in CHamoru style, often simmered in tomato sauce or coconut milk as a side dish. Bean dishes reflect Spanish culinary influence integrated into CHamoru home cooking.', TRUE),
('black_bean_soup_guam_guamanian', 'Black Bean Soup Guam', 132, 8.5, 23.5, 0.8, 8.5, 1.5, 240, NULL, 'research', ARRAY['black bean soup guam', 'with pork version', 'vegetarian version'], 'traditional', NULL, 1, 'GU', 'Black bean soup adapted to CHamoru tastes with soy sauce, garlic, onions, and local seasonings. Beans have become a regular feature of Guam''s diverse food landscape.', TRUE),
('mongo_soup_guamanian', 'Mongo Soup', 118, 7.8, 20.5, 0.5, 6.8, 1.2, 240, NULL, 'research', ARRAY['mongo soup', 'with pork version', 'with shrimp version', 'plain mung bean'], 'traditional', NULL, 1, 'GU', 'Mung bean soup cooked with pork, garlic, and onions, adapted from Filipino ginisang mongo. A nutritious and filling dish common in CHamoru households reflecting Filipino culinary influence.', TRUE),
('corn_tortilla_plain_guamanian', 'Corn Tortilla Plain', 218, 5.0, 44.0, 2.8, 4.5, 0.8, 100, 25, 'research', ARRAY['corn tortilla plain'], 'traditional', NULL, 1, 'GU', 'Plain corn tortillas without additional flavoring, used as a wrap for kelaguen and other CHamoru foods. The corn tortilla tradition in Guam traces to Spanish colonial introduction of masa preparation.', TRUE),
('sweet_bringhe_guamanian', 'Sweet Bringhé', 235, 3.5, 38.5, 9.5, 1.2, 8.5, 150, NULL, 'research', ARRAY['sweet bringhé'], 'traditional', NULL, 1, 'GU', 'Sweetened version of the traditional glutinous rice dish cooked with coconut milk, sugar, and turmeric wrapped in banana leaves. Often served as a dessert or special occasion treat at CHamoru fiestas.', TRUE),
('kelaguen_uhang_fried_guamanian', 'Kelaguen Uhang Fried', 195, 18.5, 8.5, 9.5, 0.8, 1.5, 150, NULL, 'research', ARRAY['kelaguen uhang fried'], 'traditional', NULL, 1, 'GU', 'Variation of shrimp kelaguen where shrimp is lightly battered and fried before being dressed with lemon, coconut, and peppers. A modern adaptation of the traditional kelaguen style.', TRUE),
('red_rice_with_coconut_guamanian', 'Red Rice with Coconut', 195, 3.8, 36.5, 4.2, 2.0, 1.5, 180, NULL, 'research', ARRAY['red rice with coconut'], 'traditional', NULL, 1, 'GU', 'Achote-colored rice cooked with coconut milk for added richness and flavor, a variation of the standard CHamoru red rice. The coconut adds a subtle sweetness that complements grilled meats.', TRUE),
('chamoru_fried_rice_guamanian', 'CHamoru Fried Rice', 205, 7.5, 34.5, 5.5, 1.2, 2.5, 200, NULL, 'research', ARRAY['chamoru fried rice', 'spam fried rice', 'shrimp fried rice', 'vegetable fried rice'], 'traditional', NULL, 1, 'GU', 'Fried rice with eggs, green onions, soy sauce, and mixed vegetables, a CHamoru-adapted version of Asian fried rice. Often made with leftover red rice and served as a quick meal or fiesta side.', TRUE),
('spam_fried_rice_guamanian', 'Spam Fried Rice', 225, 9.5, 32.5, 7.5, 1.0, 2.0, 200, NULL, 'research', ARRAY['spam fried rice', 'with egg', 'without egg', 'with vegetables'], 'traditional', NULL, 1, 'GU', 'Fried rice made with Spam (canned luncheon meat), a beloved ingredient in Guam due to its WWII history when Spam became a critical food supply. Spam holds an iconic status in CHamoru cuisine.', TRUE),
('taro_chips_guamanian', 'Taro Chips', 355, 2.0, 48.5, 18.5, 4.2, 1.0, 50, NULL, 'research', ARRAY['taro chips', 'salted', 'seasoned with local spices'], 'traditional', NULL, 1, 'GU', 'Thinly sliced taro root deep-fried until crispy, a popular snack in Guam. Taro chips showcase the versatility of suni (taro) in modern CHamoru cooking while honoring its traditional importance.', TRUE),
('breadfruit_chips_guamanian', 'Breadfruit Chips', 340, 1.5, 52.0, 16.5, 5.0, 3.5, 50, NULL, 'research', ARRAY['breadfruit chips', 'salted', 'with dipping sauce'], 'traditional', NULL, 1, 'GU', 'Thinly sliced green breadfruit deep-fried into crispy chips, a modern interpretation of a traditional staple food. These chips highlight lemmai''s versatility as both a traditional starch and a snack.', TRUE),
('banana_flower_preparation_guamanian', 'Banana Flower Preparation', 35, 1.5, 7.0, 0.3, 3.5, 1.5, 100, NULL, 'research', ARRAY['banana flower preparation', 'sautéed version', 'coconut milk stew'], 'traditional', NULL, 1, 'GU', 'Banana blossoms prepared as a vegetable dish, sautéed with garlic, onions, and coconut milk. A resourceful CHamoru preparation that uses the entire banana plant.', TRUE),
('sweet_potato_guam_guamanian', 'Sweet Potato Guam', 86, 1.6, 20.0, 0.1, 3.0, 4.2, 130, NULL, 'research', ARRAY['sweet potato guam', 'baked', 'boiled', 'candied'], 'traditional', NULL, 1, 'GU', 'Sweet potato baked or boiled, an important root vegetable in CHamoru cooking used both as a staple carbohydrate and in desserts. A nutritious traditional food with long cultivation history on Guam.', TRUE),
('kamote_guam_guamanian', 'Kamote Guam', 86, 1.6, 20.0, 0.1, 3.0, 4.2, 130, NULL, 'research', ARRAY['kamote guam', 'boiled kamote', 'fried kamote', 'kamote fries'], 'traditional', NULL, 1, 'GU', 'Kamote (orange sweet potato) is widely consumed in Guam, often boiled or baked as a side dish or snack. Filipino influence brought this term and preparation style to CHamoru cuisine.', TRUE),
('ube_purple_yam_guamanian', 'Ube Purple Yam', 140, 2.0, 32.0, 0.2, 4.5, 5.5, 150, NULL, 'research', ARRAY['ube purple yam', 'boiled ube', 'ube halaya jam', 'ube in coconut milk'], 'traditional', NULL, 1, 'GU', 'Purple yam (ube) used in both savory and sweet preparations, reflecting Filipino influence on Guam''s food culture. Ube''s distinctive color and earthy sweetness make it a popular ingredient in desserts and snacks.', TRUE),
('cassava_guam_guamanian', 'Cassava Guam', 160, 1.4, 38.5, 0.3, 1.8, 1.8, 150, NULL, 'research', ARRAY['cassava guam', 'boiled cassava', 'cassava in coconut milk', 'cassava cake'], 'traditional', NULL, 1, 'GU', 'Cassava (tapioca) root boiled or prepared in coconut milk, an important starchy food introduced to Guam and incorporated into CHamoru cooking. Also used in traditional desserts and cakes.', TRUE),
('yam_guam_guamanian', 'Yam Guam', 118, 1.5, 27.5, 0.2, 4.0, 0.5, 150, NULL, 'research', ARRAY['yam guam', 'boiled', 'roasted'], 'traditional', NULL, 1, 'GU', 'True yam (not sweet potato) boiled or roasted as a starchy side dish, a traditional root vegetable of Pacific islands including Guam. A nutritious staple that complemented taro and breadfruit in ancient CHamoru diets.', TRUE),
('banana_blossom_stew_guamanian', 'Banana Blossom Stew', 48, 2.0, 9.5, 0.5, 4.2, 2.0, 200, NULL, 'research', ARRAY['banana blossom stew'], 'traditional', NULL, 1, 'GU', 'Tender banana blossoms slowly stewed with onions, garlic, and coconut milk or tomato sauce. A resourceful and nutritious dish that showcases traditional CHamoru use of all parts of the banana plant.', TRUE),
('achote_rice_guamanian', 'Achote Rice', 178, 3.5, 38.2, 1.2, 1.8, 0.4, 180, NULL, 'research', ARRAY['achote rice', 'darker red version', 'lighter orange version'], 'traditional', NULL, 1, 'GU', 'Rice cooked with annatto (achote) seeds or powder to achieve the signature orange-red color of CHamoru red rice. Achote was introduced by Spanish missionaries and became synonymous with CHamoru identity.', TRUE),
('rice_porridge_guam_guamanian', 'Rice Porridge Guam', 72, 1.8, 15.5, 0.5, 0.5, 0.5, 240, NULL, 'research', ARRAY['rice porridge guam', 'plain congee', 'chicken congee', 'ginger congee'], 'traditional', NULL, 1, 'GU', 'Soft-cooked rice porridge (congee-style) eaten for breakfast or when sick, adapted from Asian culinary traditions common in Guam. Often seasoned simply with salt, ginger, and green onions.', TRUE),
('sauteed_water_spinach_guamanian', 'Sautéed Water Spinach', 19, 2.8, 2.5, 0.3, 2.2, 0.5, 150, NULL, 'research', ARRAY['sautéed water spinach', 'with garlic', 'with bagoong shrimp paste'], 'traditional', NULL, 1, 'GU', 'Water spinach (kangkong) sautéed with garlic and soy sauce, a Filipino-influenced vegetable preparation common in CHamoru households. A nutritious and quick side dish popular throughout Guam.', TRUE),
('coconut_milk_rice_guamanian', 'Coconut Milk Rice', 210, 3.5, 34.5, 8.2, 0.8, 2.5, 180, NULL, 'research', ARRAY['coconut milk rice', 'plain coconut rice', 'with pandan leaf', 'sweetened coconut rice'], 'traditional', NULL, 1, 'GU', 'Jasmine or medium-grain rice cooked in coconut milk instead of water, creating a rich, creamy, aromatic dish. This preparation method reflects the central role of coconut in Pacific island cuisines.', TRUE),
('corn_gruel_guamanian', 'Corn Gruel', 88, 2.5, 19.5, 1.0, 1.5, 2.5, 240, NULL, 'research', ARRAY['corn gruel', 'sweet version', 'savory version'], 'traditional', NULL, 1, 'GU', 'Thin corn porridge made from ground corn or masa, a traditional breakfast preparation in CHamoru culture. Corn gruel reflects the historical importance of corn as a primary grain after Spanish introduction.', TRUE),
('guam_style_chili_guamanian', 'Guam Style Chili', 168, 12.5, 18.5, 4.5, 6.5, 3.5, 200, NULL, 'research', ARRAY['guam style chili', 'beef chili', 'pork chili', 'mixed bean chili'], 'traditional', NULL, 1, 'GU', 'CHamoru-style chili beans adapted to local tastes with soy sauce and regional spices alongside traditional chili peppers. Served over rice rather than with bread, reflecting the CHamoru preference for rice.', TRUE),
('fijitas_guam_guamanian', 'Fijitas Guam', 88, 3.5, 18.5, 1.0, 3.8, 2.0, 100, NULL, 'research', ARRAY['fijitas guam', 'long bean version', 'string bean version'], 'traditional', NULL, 1, 'GU', 'A local term for various legume preparations in Guam, often referring to stewed or sautéed long beans or string beans with pork and garlic. Reflects the integration of Asian bean preparations into CHamoru food.', TRUE),
('pea_soup_guam_guamanian', 'Pea Soup Guam', 125, 8.5, 20.5, 1.5, 7.5, 3.5, 240, NULL, 'research', ARRAY['pea soup guam', 'split pea with ham', 'green pea soup'], 'traditional', NULL, 1, 'GU', 'Split pea or green pea soup prepared with ham, onions, and local seasonings. A Spanish colonial-influenced dish that became part of the CHamoru culinary repertoire.', TRUE),
('black_eyed_pea_guam_guamanian', 'Black Eyed Pea Guam', 116, 7.7, 20.5, 0.5, 6.0, 2.8, 150, NULL, 'research', ARRAY['black eyed pea guam', 'with pork', 'vegetarian version'], 'traditional', NULL, 1, 'GU', 'Black eyed peas cooked with pork, garlic, and tomatoes in a simple stew. Legumes play a supporting role in CHamoru cuisine, often providing protein alongside rice and root vegetables.', TRUE),
('soy_bean_curd_guam_guamanian', 'Soy Bean Curd Guam', 76, 8.0, 1.8, 4.5, 0.3, 0.8, 100, NULL, 'research', ARRAY['soy bean curd guam', 'fried tofu', 'soft tofu in soup', 'agedashi tofu style'], 'traditional', NULL, 1, 'GU', 'Tofu prepared in Asian styles common in Guam, reflecting the diverse culinary influences from Japanese, Filipino, and Chinese communities. Often fried or used in soups and stir-fries.', TRUE),
('kadu_pigs_feet_guamanian', 'Kadu Pigs Feet', 198, 19.5, 3.5, 11.5, 0.2, 1.0, 200, NULL, 'research', ARRAY['kadu pigs feet', 'spicy version', 'plain broth version'], 'traditional', NULL, 1, 'GU', 'Pig''s feet slow-cooked in a rich broth with garlic, onion, vinegar, and soy sauce until falling off the bone. A traditional CHamoru dish that reflects the culture''s utilization of the whole pig.', TRUE),
('soup_bones_guam_guamanian', 'Soup Bones Guam', 98, 8.5, 4.5, 5.5, 0.5, 1.5, 240, NULL, 'research', ARRAY['soup bones guam', 'beef bone soup', 'pork bone soup'], 'traditional', NULL, 1, 'GU', 'Rich bone broth soup made from beef or pork marrow bones with vegetables and seasonings. A comforting traditional soup that is both nutritious and deeply flavored.', TRUE),
('corn_pudding_guam_guamanian', 'Corn Pudding Guam', 165, 4.5, 28.5, 4.5, 1.8, 8.5, 150, NULL, 'research', ARRAY['corn pudding guam', 'savory corn pudding', 'sweet dessert version'], 'traditional', NULL, 1, 'GU', 'Sweet corn pudding made with fresh or canned corn, eggs, butter, and sugar. A popular dessert or side dish at CHamoru gatherings that showcases the versatility of corn in CHamoru cuisine.', TRUE),
('taro_soup_guamanian', 'Taro Soup', 98, 2.5, 22.0, 0.8, 3.8, 1.5, 240, NULL, 'research', ARRAY['taro soup', 'coconut milk version', 'plain broth version'], 'traditional', NULL, 1, 'GU', 'Taro root simmered in a light broth with coconut milk or plain water, a simple and nourishing traditional CHamoru soup. Taro soup was a daily staple food before the arrival of rice as the primary carbohydrate.', TRUE),
('biniduklan_guamanian', 'Biniduklan', 245, 12.5, 32.5, 7.5, 3.5, 4.5, 200, NULL, 'research', ARRAY['biniduklan', 'chicken version', 'pork version'], 'traditional', NULL, 1, 'GU', 'A CHamoru dish of coconut-cooked meat and vegetables, often featuring chicken or pork with local root vegetables in coconut milk. A hearty stew that showcases the central role of coconut in CHamoru cooking.', TRUE),
('grilled_corn_chamoru_guamanian', 'Grilled Corn CHamoru', 112, 3.8, 22.5, 2.5, 2.8, 5.5, 150, 150, 'research', ARRAY['grilled corn chamoru', 'with butter and salt', 'with fina''dene', 'with local peppers'], 'traditional', NULL, 1, 'GU', 'Sweet corn grilled directly over charcoal or coconut husks, often brushed with butter, salt, and local seasonings. A popular street food and fiesta item with roots in Spanish colonial introduction of corn to Guam.', TRUE),
('pickled_papaya_guamanian', 'Pickled Papaya', 42, 0.5, 10.5, 0.1, 1.8, 7.5, 80, NULL, 'research', ARRAY['pickled papaya', 'spicy version', 'mild version'], 'traditional', NULL, 1, 'GU', 'Shredded green papaya pickled in vinegar with garlic, hot peppers, and seasonings. A tangy CHamoru condiment that accompanies grilled meats and fried foods at fiestas.', TRUE),
('papaya_kelaguen_guamanian', 'Papaya Kelaguen', 55, 1.0, 12.5, 0.8, 2.5, 7.0, 120, NULL, 'research', ARRAY['papaya kelaguen'], 'traditional', NULL, 1, 'GU', 'Ripe or semi-ripe papaya prepared kelaguen-style with lemon juice, coconut, and hot peppers. A lighter fruit-based variation of the kelaguen tradition that showcases Guam''s abundant tropical fruit.', TRUE),
('mango_preparation_guam_guamanian', 'Mango Preparation Guam', 65, 0.8, 17.0, 0.4, 1.8, 14.5, 100, NULL, 'research', ARRAY['mango preparation guam', 'ripe fresh mango', 'green mango pickle', 'mango with bagoong'], 'traditional', NULL, 1, 'GU', 'Local mangoes enjoyed fresh, pickled in vinegar and salt (a popular snack), or prepared in chutneys and sauces. Mango trees are abundant throughout Guam and their fruit is central to the local diet.', TRUE),
('green_mango_pickle_guamanian', 'Green Mango Pickle', 38, 0.5, 9.5, 0.2, 1.5, 5.5, 80, NULL, 'research', ARRAY['green mango pickle', 'with bagoong', 'plain pickled', 'with hot peppers'], 'traditional', NULL, 1, 'GU', 'Shredded or sliced green mango pickled in vinegar, salt, and chili peppers — a popular CHamoru and Filipino-influenced snack in Guam. The sour and spicy combination is highly addictive.', TRUE),
('tamarind_preparations_guamanian', 'Tamarind Preparations', 239, 2.8, 62.5, 0.6, 5.1, 38.5, 100, NULL, 'research', ARRAY['tamarind preparations', 'tamarind candy', 'tamarind sauce', 'tamarind drink'], 'traditional', NULL, 1, 'GU', 'Tamarind used in sauces, candies, and drinks throughout Guam. Its sour-sweet flavor appears in numerous CHamoru dishes as a souring agent and in traditional candies sold at local stores.', TRUE),
('coconut_meat_fresh_guamanian', 'Coconut Meat Fresh', 354, 3.3, 15.2, 33.5, 9.0, 6.2, 80, NULL, 'research', ARRAY['coconut meat fresh', 'young coconut meat', 'mature coconut meat', 'grated coconut'], 'traditional', NULL, 1, 'GU', 'Fresh white coconut meat scraped from the shell, a fundamental ingredient in CHamoru cooking. Grated coconut is used in kelaguen, bringhé, and numerous sweets, while coconut milk is extracted for stews.', TRUE),
('coconut_cream_guamanian', 'Coconut Cream', 330, 3.2, 7.5, 34.0, 2.2, 4.0, 60, NULL, 'research', ARRAY['coconut cream'], 'traditional', NULL, 1, 'GU', 'Thick coconut cream extracted from grated mature coconut, used in CHamoru stews, desserts, and rice dishes. Coconut is considered the tree of life in Pacific cultures and its cream is a cornerstone of CHamoru cooking.', TRUE),
('jackfruit_guam_guamanian', 'Jackfruit Guam', 95, 1.7, 23.5, 0.6, 1.5, 19.0, 150, NULL, 'research', ARRAY['jackfruit guam', 'ripe jackfruit', 'green jackfruit curry', 'jackfruit chips'], 'traditional', NULL, 1, 'GU', 'Jackfruit eaten ripe as a sweet fruit or cooked green as a meat substitute in curries and stews. Jackfruit trees are common throughout Guam and the fruit is enjoyed by the diverse local population.', TRUE),
('coconut_sugar_guamanian', 'Coconut Sugar', 375, 0.5, 96.0, 0.1, 0.0, 93.5, 20, NULL, 'research', ARRAY['coconut sugar'], 'traditional', NULL, 1, 'GU', 'Traditional sweetener made from evaporated coconut sap, used in CHamoru desserts and sweets. Coconut sugar production represents ancient Pacific knowledge of utilizing the coconut palm''s resources.', TRUE),
('guam_lemon_juice_prep_guamanian', 'Guam Lemon Juice Prep', 22, 0.3, 7.0, 0.2, 0.3, 2.5, 60, NULL, 'research', ARRAY['guam lemon juice prep', 'calamansi juice', 'lemon juice', 'lime juice'], 'traditional', NULL, 1, 'GU', 'Fresh calamansi or lemon juice used extensively in CHamoru cooking as a marinade, condiment, and souring agent. Citrus juice is the primary ''cooking'' medium in kelaguen preparations and a key component of fina''dene.', TRUE),
('seaweed_preparation_guam_guamanian', 'Seaweed Preparation Guam', 35, 2.5, 6.5, 0.3, 3.5, 0.5, 100, NULL, 'research', ARRAY['seaweed preparation guam', 'seaweed salad', 'dried seaweed', 'seaweed with coconut'], 'traditional', NULL, 1, 'GU', 'Edible seaweed harvested from Guam''s coastal waters, prepared as salads or side dishes. Seaweed consumption reflects the ancient CHamoru maritime culture and their deep connection to the ocean.', TRUE),
('dried_fish_guam_guamanian', 'Dried Fish Guam', 295, 62.5, 0.0, 3.8, 0.0, 0.0, 50, NULL, 'research', ARRAY['dried fish guam', 'dried mackerel', 'dried flying fish', 'smoked fish'], 'traditional', NULL, 1, 'GU', 'Fish dried in the sun or smoked as a preservation method, an ancient CHamoru technique. Dried fish is used as a condiment, in soups, and as a protein source in traditional CHamoru cooking.', TRUE),
('salted_fish_guam_guamanian', 'Salted Fish Guam', 155, 30.5, 0.0, 3.2, 0.0, 0.0, 100, NULL, 'research', ARRAY['salted fish guam'], 'traditional', NULL, 1, 'GU', 'Fish preserved in salt, an important food preservation technique in pre-refrigeration CHamoru society. Salted fish is reconstituted and used in various dishes or eaten with rice as a simple meal.', TRUE),
('inafliton_guihan_guamanian', 'Inafliton Guihan', 175, 20.5, 4.5, 7.5, 0.5, 1.5, 150, NULL, 'research', ARRAY['inafliton guihan', 'whole fish fried', 'fish fillet version'], 'traditional', NULL, 1, 'GU', 'Pan-fried or sautéed fish in CHamoru style with garlic, onions, soy sauce, and lemon. A simple everyday fish preparation that highlights the fresh seafood available in Guam''s waters.', TRUE),
('pinon_guamanian', 'Piñon', 248, 9.5, 32.5, 9.5, 2.5, 3.5, 200, NULL, 'research', ARRAY['piñon', 'ground beef version', 'ground pork version'], 'traditional', NULL, 1, 'GU', 'A CHamoru dish resembling a meat-stuffed omelet or egg and meat casserole with ground beef, onions, tomatoes, and eggs. Often made for fiesta breakfast tables.', TRUE),
('chicken_and_rice_guam_guamanian', 'Chicken and Rice Guam', 185, 18.5, 22.5, 3.5, 1.0, 1.5, 250, NULL, 'research', ARRAY['chicken and rice guam', 'with gravy', 'plain version', 'fiesta style'], 'traditional', NULL, 1, 'GU', 'Simple boiled or simmered chicken pieces served over or mixed with red rice, the most fundamental and ubiquitous CHamoru meal. Every family has their own version with slight variations in seasoning.', TRUE),
('pork_and_rice_guam_guamanian', 'Pork and Rice Guam', 215, 18.5, 22.0, 6.5, 0.8, 1.0, 250, NULL, 'research', ARRAY['pork and rice guam', 'roasted pork and rice', 'braised pork and rice', 'grilled pork and rice'], 'traditional', NULL, 1, 'GU', 'Pork pieces (roasted, braised, or grilled) served over CHamoru red rice — a quintessential combination that appears at nearly every fiesta and family meal in Guam.', TRUE),
('chamoru_rice_cake_guamanian', 'CHamoru Rice Cake', 215, 4.5, 38.5, 5.5, 1.0, 6.5, 100, 50, 'research', ARRAY['chamoru rice cake', 'plain rice cake', 'coconut rice cake', 'pandan-flavored'], 'traditional', NULL, 1, 'GU', 'Traditional CHamoru rice cakes made from glutinous rice flour, coconut milk, and sugar, steamed or baked. Rice cakes have deep cultural significance as offerings and celebratory foods in CHamoru tradition.', TRUE),
('roasted_pork_chamoru_guamanian', 'Roasted Pork CHamoru', 272, 26.5, 2.5, 16.5, 0.0, 1.5, 150, NULL, 'research', ARRAY['roasted pork chamoru', 'whole roasted pig', 'shoulder roast', 'pork belly roast'], 'traditional', NULL, 1, 'GU', 'Whole or large cut pork roasted over open fire or in an oven with CHamoru seasonings including soy sauce, vinegar, garlic, and lemon. A centerpiece dish at fiestas alongside red rice.', TRUE),
('lechon_guam_guamanian', 'Lechon Guam', 285, 24.5, 3.0, 18.5, 0.0, 1.5, 150, NULL, 'research', ARRAY['lechon guam', 'whole suckling pig', 'lechon belly', 'lechon kawali'], 'traditional', NULL, 1, 'GU', 'Whole roasted suckling pig or large pork roast, adapted from Spanish tradition and deeply embedded in CHamoru fiesta culture. Lechon is the undisputed king of CHamoru celebratory cooking.', TRUE),
('banana_blossom_salad_guamanian', 'Banana Blossom Salad', 42, 2.0, 8.5, 0.5, 4.2, 2.0, 150, NULL, 'research', ARRAY['banana blossom salad'], 'traditional', NULL, 1, 'GU', 'Tender banana blossoms tossed in a lemon-based dressing with fresh coconut and herbs, similar in concept to kelaguen. A refreshing traditional salad using resources from the abundant banana plants of Guam.', TRUE),
('pickled_vegetables_guam_guamanian', 'Pickled Vegetables Guam', 28, 1.0, 6.5, 0.1, 2.2, 3.5, 80, NULL, 'research', ARRAY['pickled vegetables guam', 'spicy version', 'sweet pickled version'], 'traditional', NULL, 1, 'GU', 'A mix of pickled cucumbers, carrots, onions, and hot peppers in vinegar brine. A common CHamoru condiment accompanying grilled meats that adds acidity and brightness to rich dishes.', TRUE),
('boiled_taro_leaves_guamanian', 'Boiled Taro Leaves', 42, 3.5, 6.5, 0.5, 4.2, 0.5, 100, NULL, 'research', ARRAY['boiled taro leaves', 'plain boiled', 'with coconut milk', 'with garlic'], 'traditional', NULL, 1, 'GU', 'Young taro leaves boiled until tender and eaten as a vegetable. Taro leaves must be cooked thoroughly to neutralize calcium oxalate crystals. A nutritious traditional vegetable in CHamoru cuisine.', TRUE),
('taro_in_coconut_milk_guamanian', 'Taro in Coconut Milk', 148, 2.5, 28.5, 4.5, 3.8, 2.5, 200, NULL, 'research', ARRAY['taro in coconut milk', 'savory version', 'sweet dessert version'], 'traditional', NULL, 1, 'GU', 'Taro root cubes simmered in sweetened or savory coconut milk until tender and creamy. This preparation can be a side dish or dessert depending on seasoning, reflecting taro''s versatility in CHamoru cooking.', TRUE),
('breadfruit_in_coconut_milk_guamanian', 'Breadfruit in Coconut Milk', 158, 1.8, 30.5, 4.5, 5.2, 5.5, 200, NULL, 'research', ARRAY['breadfruit in coconut milk', 'savory version', 'sweet version'], 'traditional', NULL, 1, 'GU', 'Ripe or slightly ripe breadfruit cooked in coconut milk with a touch of sugar and salt. A traditional CHamoru comfort dish that highlights the complementary flavors of lemmai and coconut.', TRUE),
('fermented_coconut_guamanian', 'Fermented Coconut', 285, 2.5, 10.5, 28.5, 4.5, 5.5, 80, NULL, 'research', ARRAY['fermented coconut'], 'traditional', NULL, 1, 'GU', 'Mature coconut meat left to ferment slightly, developing a distinctive tangy flavor used in traditional CHamoru cooking. Fermented coconut products represent ancient food preservation knowledge.', TRUE),
('corn_masa_dough_guamanian', 'Corn Masa Dough', 182, 4.5, 36.0, 3.0, 5.5, 0.5, 100, NULL, 'research', ARRAY['corn masa dough'], 'traditional', NULL, 1, 'GU', 'Nixtamalized corn dough (masa) used to make titiyas mais and other corn-based preparations. The process of making masa was introduced by the Spanish and became integral to CHamoru corn cooking traditions.', TRUE),
('banana_bread_guam_guamanian', 'Banana Bread Guam', 265, 4.5, 48.5, 7.5, 2.0, 25.5, 100, NULL, 'research', ARRAY['banana bread guam', 'plain banana bread', 'banana bread with coconut', 'with macadamia nuts'], 'traditional', NULL, 1, 'GU', 'Moist banana bread made with ripe local bananas, adapted from American recipes but made with Guam''s abundant local banana varieties. A popular home-baked treat in CHamoru households.', TRUE),
('corn_porridge_guam_guamanian', 'Corn Porridge Guam', 92, 2.8, 20.5, 1.0, 1.8, 3.5, 240, NULL, 'research', ARRAY['corn porridge guam', 'sweet version with coconut', 'savory version'], 'traditional', NULL, 1, 'GU', 'Sweetened or savory corn porridge made from dried or fresh ground corn, a historical breakfast staple. Corn porridge connects modern CHamoru cuisine to the post-Spanish introduction of maize cultivation.', TRUE),
('lemon_coconut_rice_guamanian', 'Lemon Coconut Rice', 205, 3.5, 35.5, 7.5, 1.0, 2.0, 180, NULL, 'research', ARRAY['lemon coconut rice'], 'traditional', NULL, 1, 'GU', 'Fragrant rice cooked in coconut milk and finished with fresh calamansi or lemon juice, combining two signature flavors of CHamoru cuisine. Served alongside grilled meats and seafood.', TRUE),
('gollai_hagun_suni_guamanian', 'Gollai Hagun Suni', 75, 3.2, 10.5, 2.5, 4.5, 1.5, 150, NULL, 'research', ARRAY['gollai hagun suni', 'with shrimp', 'with dried fish', 'vegetarian version'], 'traditional', NULL, 1, 'GU', 'Young taro leaves cooked in coconut milk with onions, garlic, and sometimes shrimp or fish. One of the most traditional CHamoru vegetable dishes, it showcases the cultural importance of the taro plant.', TRUE),
('gollai_appan_manga_guamanian', 'Gollai Appan Manga', 55, 1.0, 13.0, 0.3, 2.5, 8.5, 150, NULL, 'research', ARRAY['gollai appan manga', 'with sugar', 'unsweetened version'], 'traditional', NULL, 1, 'GU', 'Ripe mango cooked in coconut milk with a touch of sugar, a simple CHamoru preparation that showcases tropical fruit. Gollai refers to a style of cooking fruit or vegetables in coconut milk.', TRUE),
('pika_sauce_guamanian', 'Pika Sauce', 35, 1.2, 7.5, 0.5, 1.5, 4.5, 30, NULL, 'research', ARRAY['pika sauce', 'donne'' dinanche', 'donne'' fina''dene', 'vinegar pepper sauce'], 'traditional', NULL, 1, 'GU', 'CHamoru hot sauce made from donne'' peppers (local bird''s eye chilis), vinegar, garlic, and salt. Pika means spicy in CHamoru, and this fiery condiment accompanies almost every meal on the island.', TRUE),
('donne_sali_pepper_guamanian', 'Donne'' Sali Pepper', 40, 1.5, 8.5, 0.5, 3.0, 5.0, 50, NULL, 'research', ARRAY['donne'' sali pepper', 'fresh donne''', 'dried donne''', 'pickled donne'''], 'traditional', NULL, 1, 'GU', 'The local Guam bird''s eye chili pepper, one of the hottest and most culturally important ingredients in CHamoru cooking. Donne'' sali is used fresh, dried, or pickled in countless traditional preparations.', TRUE),
('atsa_guamanian', 'Atsa', 18, 0.5, 4.5, 0.1, 1.5, 2.5, 60, NULL, 'research', ARRAY['atsa', 'cucumber atsa', 'papaya atsa', 'mixed vegetable atsa'], 'traditional', NULL, 1, 'GU', 'CHamoru pickled cucumber or green papaya condiment served alongside fiesta meals. The word atsa reflects Spanish influence (escabeche) adapted into CHamoru culinary tradition.', TRUE),
('escabeche_chamoru_guamanian', 'Escabeche CHamoru', 125, 12.5, 8.5, 5.0, 1.5, 4.5, 180, NULL, 'research', ARRAY['escabeche chamoru', 'fish escabeche', 'chicken escabeche'], 'traditional', NULL, 1, 'GU', 'Fish or meat marinated in vinegar, oil, garlic, and spices in the Spanish escabeche tradition. CHamoru escabeche incorporates local hot peppers and citrus for a distinctly Pacific flavor profile.', TRUE),
('tumon_bay_fish_preparation_guamanian', 'Tumon Bay Fish Preparation', 145, 22.0, 3.5, 5.0, 0.5, 1.5, 150, NULL, 'research', ARRAY['tumon bay fish preparation', 'grilled reef fish', 'steamed reef fish', 'ceviche-style preparation'], 'traditional', NULL, 1, 'GU', 'Various reef fish preparations traditional to coastal CHamoru communities near Tumon Bay. Ancient CHamorros were expert fishers and prepared reef fish using citrus marinades and local seasonings.', TRUE),
('chamoru_fish_soup_guamanian', 'CHamoru Fish Soup', 112, 15.5, 8.5, 2.5, 1.5, 2.5, 250, NULL, 'research', ARRAY['chamoru fish soup', 'clear broth version', 'coconut milk version', 'spicy version'], 'traditional', NULL, 1, 'GU', 'Clear or lightly coconut-flavored fish soup with vegetables, a traditional daily meal in fishing CHamoru communities. Fish soup provided essential nutrition for coastal families throughout CHamoru history.', TRUE),
('latiya_guamanian', 'Latiya', 245, 5.5, 40.5, 7.5, 0.5, 22.5, 120, 120, 'research', ARRAY['latiya', 'vanilla custard version', 'plain sponge version'], 'traditional', NULL, 1, 'GU', 'A traditional CHamoru dessert of sponge cake topped with a rich custard cream and dusted with cinnamon, reflecting Spanish colonial influence. Latiya is a fiesta essential and CHamoru comfort dessert.', TRUE),
('bobo_guamanian', 'Bobo', 145, 3.2, 28.5, 3.5, 1.5, 8.5, 200, NULL, 'research', ARRAY['bobo', 'rice bobo', 'corn bobo', 'with coconut milk'], 'traditional', NULL, 1, 'GU', 'A traditional CHamoru rice or corn pudding sweetened with coconut milk and sugar. Bobo is a simple, comforting sweet dish that has been made in CHamoru homes for generations.', TRUE),
('apigigi_guamanian', 'Apigigi', 195, 2.5, 32.5, 7.5, 2.5, 8.5, 80, 80, 'research', ARRAY['apigigi', 'plain version', 'with extra coconut', 'pandan-flavored'], 'traditional', NULL, 1, 'GU', 'Traditional CHamoru glutinous rice cake made from grated young coconut and sweet rice, wrapped and cooked in banana leaves. A beloved fiesta sweet that is both a snack and dessert.', TRUE),
('bibingka_chamoru_guamanian', 'Bibingka CHamoru', 255, 4.5, 42.5, 8.5, 1.2, 18.5, 120, 120, 'research', ARRAY['bibingka chamoru', 'coconut bibingka', 'cassava bibingka', 'plain rice bibingka'], 'traditional', NULL, 1, 'GU', 'CHamoru-style rice cake baked in clay pots lined with banana leaves, topped with salted butter and grated coconut. Adapted from Filipino bibingka, this sweet cake is a Christmas season tradition in Guam.', TRUE),
('titiyas_sweet_guamanian', 'Titiyas Sweet', 312, 6.5, 55.5, 7.5, 2.5, 15.5, 80, 80, 'research', ARRAY['titiyas sweet', 'sweet corn titiyas', 'sweet flour titiyas', 'coconut sweet titiyas'], 'traditional', NULL, 1, 'GU', 'Sweetened version of CHamoru titiyas made with sugar and sometimes coconut, served as a dessert or sweet snack. Sweet titiyas are popular at bakeries and family celebrations throughout Guam.', TRUE),
('kalamasa_stew_guamanian', 'Kalamasa Stew', 88, 2.5, 18.5, 1.5, 3.5, 5.5, 200, NULL, 'research', ARRAY['kalamasa stew', 'savory version', 'sweet coconut version'], 'traditional', NULL, 1, 'GU', 'Kabocha or local pumpkin/squash cooked in coconut milk with onions and light seasoning. Kalamasa (pumpkin) stew is a simple, nutritious traditional CHamoru dish made from garden-grown squash.', TRUE),
('chayote_chamoru_style_guamanian', 'Chayote CHamoru Style', 32, 1.2, 7.0, 0.3, 2.8, 3.0, 150, NULL, 'research', ARRAY['chayote chamoru style', 'sautéed', 'in soup', 'stuffed chayote'], 'traditional', NULL, 1, 'GU', 'Chayote squash sautéed or simmered with garlic, onions, and soy sauce in CHamoru style. A light vegetable dish common in CHamoru households reflecting the abundance of garden vegetables in Guam.', TRUE),
('papaya_soup_guam_guamanian', 'Papaya Soup Guam', 58, 2.5, 12.5, 0.5, 2.5, 6.0, 240, NULL, 'research', ARRAY['papaya soup guam', 'with pork', 'with chicken', 'vegetarian'], 'traditional', NULL, 1, 'GU', 'Green papaya simmered in light broth or coconut milk, often with chicken or pork and fish sauce. A common home cooking dish reflecting Filipino and CHamoru culinary overlap in Guam.', TRUE),
('chicken_kelaguen_with_coconut_guamanian', 'Chicken Kelaguen with Coconut', 172, 24.0, 4.5, 7.0, 1.2, 2.0, 150, NULL, 'research', ARRAY['chicken kelaguen with coconut'], 'traditional', NULL, 1, 'GU', 'Traditional chicken kelaguen with an extra generous amount of freshly grated coconut, emphasizing the creamy richness of coconut against the bright citrus and hot pepper. A variation preferred at formal fiestas.', TRUE),
('corn_titiyas_with_butter_guamanian', 'Corn Titiyas with Butter', 265, 5.0, 42.5, 10.5, 3.5, 1.5, 80, 80, 'research', ARRAY['corn titiyas with butter', 'with salted butter', 'with unsalted butter'], 'traditional', NULL, 1, 'GU', 'Warm corn titiyas served with generous amounts of butter, the most traditional way to enjoy this CHamoru bread. The combination is a beloved breakfast and snack throughout Guam.', TRUE),
('chicken_chalakiles_thick_guamanian', 'Chicken Chalakiles Thick', 162, 15.5, 18.5, 3.5, 1.0, 1.2, 250, NULL, 'research', ARRAY['chicken chalakiles thick'], 'traditional', NULL, 1, 'GU', 'Thicker, porridge-style chalakiles where the rice has fully dissolved into the chicken broth creating a creamy congee texture. This style is especially popular as a comfort food during illness or cold weather.', TRUE),
('mongo_beans_with_pork_guamanian', 'Mongo Beans with Pork', 148, 11.5, 18.5, 3.5, 7.5, 1.5, 200, NULL, 'research', ARRAY['mongo beans with pork', 'with shrimp paste', 'with coconut milk', 'plain version'], 'traditional', NULL, 1, 'GU', 'Mung beans cooked with pork pieces, garlic, onions, and ampalaya (bitter melon) in a classic Filipino-CHamoru preparation common throughout Guam. Nutritious and filling, this dish is a home-cooking staple.', TRUE),
('sauteed_long_beans_guamanian', 'Sautéed Long Beans', 35, 2.2, 6.5, 0.5, 3.5, 2.5, 150, NULL, 'research', ARRAY['sautéed long beans', 'with garlic', 'with pork bits', 'with dried shrimp'], 'traditional', NULL, 1, 'GU', 'Long green beans (yard-long beans) quickly sautéed with garlic and soy sauce in Filipino-CHamoru style. A simple, nutritious vegetable preparation common in CHamoru households reflecting Asian culinary influence.', TRUE),
('chicken_tinola_guam_guamanian', 'Chicken Tinola Guam', 95, 12.5, 5.5, 2.5, 1.5, 2.0, 250, NULL, 'research', ARRAY['chicken tinola guam', 'with chayote', 'with green papaya', 'with moringa leaves'], 'traditional', NULL, 1, 'GU', 'Filipino-influenced chicken soup with ginger, green papaya, and chili leaves, a popular dish among Guam''s Filipino community that has been adopted into broader CHamoru home cooking.', TRUE),
('kaldero_guamanian', 'Kaldero', 145, 15.5, 8.5, 5.5, 2.0, 3.5, 200, NULL, 'research', ARRAY['kaldero', 'beef kaldero', 'pork kaldero', 'chicken version'], 'traditional', NULL, 1, 'GU', 'CHamoru-style beef or pork stew cooked in a pot (kaldero) with tomatoes, potatoes, carrots, and garlic. Reflects Spanish caldereta influence transformed through generations of CHamoru cooking.', TRUE),
('sinegan_guamanian', 'Sinegan', 78, 1.5, 8.5, 4.5, 2.5, 3.5, 100, NULL, 'research', ARRAY['sinegan', 'plain vinegar condiment', 'spiced vinegar'], 'traditional', NULL, 1, 'GU', 'Traditional CHamoru vinegar condiment or preparation, reflecting the widespread use of vinegar as a preservative, marinade, and condiment throughout CHamoru cuisine. Sinegan refers to vinegar-based preparations.', TRUE),
('achote_paste_guamanian', 'Achote Paste', 285, 6.5, 52.5, 7.5, 8.5, 2.5, 30, NULL, 'research', ARRAY['achote paste'], 'traditional', NULL, 1, 'GU', 'Concentrated paste made from ground annatto seeds mixed with spices and oil, used to color and flavor CHamoru red rice and marinades. Achote paste is a pantry essential in every CHamoru kitchen.', TRUE),
('soybean_paste_guam_guamanian', 'Soybean Paste Guam', 168, 10.5, 20.5, 4.5, 4.5, 8.5, 50, NULL, 'research', ARRAY['soybean paste guam', 'sweet version', 'salty version'], 'traditional', NULL, 1, 'GU', 'Fermented soybean paste used as a seasoning in CHamoru soups and stews, reflecting Japanese miso and Filipino bagoong influences in Guam''s multicultural cuisine. Used sparingly for depth of flavor.', TRUE),
('coconut_vinegar_guamanian', 'Coconut Vinegar', 18, 0.0, 4.5, 0.0, 0.0, 0.5, 30, NULL, 'research', ARRAY['coconut vinegar'], 'traditional', NULL, 1, 'GU', 'Vinegar made from fermented coconut palm sap, a traditional Pacific condiment with a milder, slightly sweet character compared to cane vinegar. Used in fina''dene and other CHamoru preparations.', TRUE),
('banana_flower_stir_fry_guamanian', 'Banana Flower Stir Fry', 52, 2.5, 10.5, 0.8, 4.5, 2.5, 150, NULL, 'research', ARRAY['banana flower stir fry'], 'traditional', NULL, 1, 'GU', 'Banana blossoms quickly stir-fried with garlic, onions, and soy sauce as a vegetable side dish. A resourceful CHamoru preparation that utilizes the edible flower of the banana plant.', TRUE),
('fish_head_soup_guam_guamanian', 'Fish Head Soup Guam', 88, 12.5, 5.5, 2.5, 1.0, 2.0, 250, NULL, 'research', ARRAY['fish head soup guam', 'with miso', 'with coconut milk', 'clear broth version'], 'traditional', NULL, 1, 'GU', 'Rich soup made from large fish heads simmered with ginger, vegetables, and local seasonings. A treasured traditional preparation that reflects CHamoru resourcefulness and the cultural importance of seafood.', TRUE),
('grilled_breadfruit_guamanian', 'Grilled Breadfruit', 108, 1.2, 25.0, 0.5, 4.5, 4.0, 150, NULL, 'research', ARRAY['grilled breadfruit', 'with butter', 'with fina''dene dipping sauce'], 'traditional', NULL, 1, 'GU', 'Breadfruit slices or halves grilled until caramelized on the outside and tender inside, often served with butter and salt. A modern preparation of the ancient staple food that remains popular at CHamoru gatherings.', TRUE),
('boiled_green_banana_guamanian', 'Boiled Green Banana', 88, 1.1, 22.5, 0.2, 2.8, 1.5, 120, 120, 'research', ARRAY['boiled green banana'], 'traditional', NULL, 1, 'GU', 'Unripe green bananas boiled in salted water until tender and eaten as a starchy vegetable, similar to plantain preparation. A traditional CHamoru food that utilizes bananas before they ripen.', TRUE),
('fried_green_banana_guamanian', 'Fried Green Banana', 152, 1.2, 28.5, 4.5, 2.5, 1.2, 120, NULL, 'research', ARRAY['fried green banana'], 'traditional', NULL, 1, 'GU', 'Green bananas sliced and pan-fried in oil until golden, served as a starchy snack or side dish. An adaptation that brings together local bananas and frying techniques popular throughout the Pacific.', TRUE),
('rice_and_beans_guam_guamanian', 'Rice and Beans Guam', 182, 6.5, 35.5, 2.0, 5.5, 1.5, 200, NULL, 'research', ARRAY['rice and beans guam', 'red rice with black beans', 'red rice with kidney beans', 'with pork addition'], 'traditional', NULL, 1, 'GU', 'Red rice served with stewed black, red, or kidney beans, a combination that reflects diverse cultural influences in Guam including Spanish, Filipino, and American culinary traditions.', TRUE),
('achote_pork_marinade_guamanian', 'Achote Pork Marinade', 225, 22.5, 5.5, 12.5, 0.5, 3.5, 150, NULL, 'research', ARRAY['achote pork marinade', 'grilled version', 'oven roasted version'], 'traditional', NULL, 1, 'GU', 'Pork marinated in achote paste with soy sauce, vinegar, garlic, and calamansi then grilled or roasted. The achote not only colors the meat but adds a subtle earthy flavor distinct to CHamoru cuisine.', TRUE),
('chamoru_beef_stew_guamanian', 'CHamoru Beef Stew', 215, 22.5, 12.5, 8.5, 2.5, 3.5, 250, NULL, 'research', ARRAY['chamoru beef stew', 'with coconut milk', 'tomato-based version', 'plain broth version'], 'traditional', NULL, 1, 'GU', 'Hearty beef stew with potatoes, carrots, and onions seasoned with soy sauce and local spices. A comforting CHamoru home cooking staple that feeds large families during community gatherings.', TRUE),
('guam_style_pork_chops_guamanian', 'Guam Style Pork Chops', 258, 26.5, 5.5, 14.5, 0.3, 3.5, 170, 170, 'research', ARRAY['guam style pork chops', 'grilled version', 'pan-fried version', 'braised version'], 'traditional', NULL, 1, 'GU', 'Pork chops marinated in soy sauce, lemon, garlic, and sugar then grilled or pan-fried in CHamoru style. A popular home-cooked dinner that showcases the characteristic CHamoru sweet-salty-sour flavor profile.', TRUE),
('lemon_chicken_guam_guamanian', 'Lemon Chicken Guam', 195, 26.5, 5.5, 7.5, 0.5, 3.5, 180, NULL, 'research', ARRAY['lemon chicken guam', 'grilled lemon chicken', 'braised lemon chicken'], 'traditional', NULL, 1, 'GU', 'Chicken pieces marinated and cooked with fresh lemon juice, garlic, onions, and local seasonings. A lighter preparation than the heavily marinated BBQ, this dish is popular for weeknight family dinners.', TRUE),
('sauteed_eggplant_guam_guamanian', 'Sautéed Eggplant Guam', 38, 1.5, 7.5, 1.5, 3.5, 3.5, 150, NULL, 'research', ARRAY['sautéed eggplant guam', 'with garlic', 'with bagoong', 'with coconut milk'], 'traditional', NULL, 1, 'GU', 'Asian eggplant sautéed with garlic, soy sauce, and sometimes coconut milk in CHamoru style. A common vegetable side dish reflecting Filipino and Asian influences on CHamoru home cooking.', TRUE),
('bean_thread_noodles_guam_guamanian', 'Bean Thread Noodles Guam', 178, 3.5, 42.5, 0.2, 0.5, 0.5, 180, NULL, 'research', ARRAY['bean thread noodles guam', 'with chicken', 'with pork', 'vegetable only'], 'traditional', NULL, 1, 'GU', 'Glass noodles (sotanghon) stir-fried with vegetables and meat, a Filipino-influenced dish popular in Guam. Bean thread noodles are commonly used in pancit-style dishes and soups throughout Guam''s diverse cuisine.', TRUE),
('coconut_milk_soup_guam_guamanian', 'Coconut Milk Soup Guam', 145, 8.5, 10.5, 8.5, 2.0, 3.5, 250, NULL, 'research', ARRAY['coconut milk soup guam', 'chicken version', 'seafood version', 'vegetable version'], 'traditional', NULL, 1, 'GU', 'A general style of CHamoru soup made with coconut milk as the base, incorporating any combination of meat, seafood, and vegetables. Coconut milk soup represents the foundational cooking technique of kadon dishes.', TRUE),
('chamorro_breakfast_plate_guamanian', 'Chamorro Breakfast Plate', 345, 18.5, 40.5, 11.5, 2.0, 3.5, 300, NULL, 'research', ARRAY['chamorro breakfast plate', 'with spam', 'with portuguese sausage', 'with bacon'], 'traditional', NULL, 1, 'GU', 'Traditional CHamoru breakfast plate consisting of fried eggs, spam or sausage, garlic fried rice or red rice, and titiyas. This combination represents the American military and Asian influences on modern CHamoru breakfast culture.', TRUE),
('tortillas_with_kelaguen_guamanian', 'Tortillas with Kelaguen', 245, 18.5, 28.5, 7.5, 3.0, 2.5, 180, NULL, 'research', ARRAY['tortillas with kelaguen', 'chicken kelaguen wrap', 'fish kelaguen wrap'], 'traditional', NULL, 1, 'GU', 'Corn titiyas served with chicken or fish kelaguen as a wrap or alongside dipping, the most traditional CHamoru way to enjoy both foods. This combination is a fiesta staple and beloved everyday meal.', TRUE),
('tamales_guam_style_guamanian', 'Tamales Guam Style', 215, 6.5, 35.5, 7.0, 3.5, 1.5, 150, NULL, 'research', ARRAY['tamales guam style', 'chicken filling', 'pork filling', 'sweet tamales'], 'traditional', NULL, 1, 'GU', 'CHamoru tamales made from corn masa filled with seasoned chicken or pork, wrapped in banana leaves or corn husks and steamed. Distinct from Mexican tamales, these reflect Guam''s Spanish colonial culinary heritage.', TRUE),
('ipes_guamanian', 'Ipes', 88, 2.5, 18.5, 1.0, 3.5, 2.5, 100, NULL, 'research', ARRAY['ipes', 'boiled corn', 'steamed corn', 'roasted corn'], 'traditional', NULL, 1, 'GU', 'Traditional CHamoru boiled or steamed corn preparation, representing the simplest and most ancient way to consume corn in the CHamoru diet. Ipes reflects the fundamental role of whole corn in CHamoru food history.', TRUE),
('beef_kaldero_chamoru_guamanian', 'Beef Kaldero CHamoru', 188, 18.5, 12.5, 7.5, 2.5, 4.5, 200, NULL, 'research', ARRAY['beef kaldero chamoru', 'with liver spread', 'without liver', 'spicy version'], 'traditional', NULL, 1, 'GU', 'CHamoru-style beef stew derived from Spanish caldereta with tomato sauce, potatoes, bell peppers, and local seasonings. One of the most beloved CHamoru fiesta dishes representing Spanish culinary heritage.', TRUE),
('chicken_noodle_soup_guam_guamanian', 'Chicken Noodle Soup Guam', 112, 10.5, 12.5, 2.5, 1.5, 2.0, 250, NULL, 'research', ARRAY['chicken noodle soup guam', 'with egg noodles', 'with rice noodles', 'with dumplings'], 'traditional', NULL, 1, 'GU', 'Comforting chicken noodle soup with egg noodles, vegetables, and CHamoru seasonings. A universally beloved soup in Guam that combines American comfort food tradition with local CHamoru spicing.', TRUE),
('sauteed_kangkong_guamanian', 'Sautéed Kangkong', 22, 2.5, 3.5, 0.5, 2.5, 0.8, 150, NULL, 'research', ARRAY['sautéed kangkong', 'with garlic', 'with oyster sauce', 'with coconut milk'], 'traditional', NULL, 1, 'GU', 'Water spinach sautéed with garlic, soy sauce, and oyster sauce in Filipino-CHamoru style. Kangkong is widely grown throughout Guam and is one of the most commonly eaten leafy vegetables in local households.', TRUE),
('pork_belly_chamoru_guamanian', 'Pork Belly CHamoru', 395, 18.5, 2.5, 35.5, 0.0, 1.5, 150, NULL, 'research', ARRAY['pork belly chamoru', 'braised pork belly', 'crispy pork belly', 'grilled pork belly'], 'traditional', NULL, 1, 'GU', 'Pork belly prepared in various CHamoru styles including braised, roasted, or grilled with soy sauce and vinegar marinades. Pork belly''s rich fat content makes it a prized ingredient in CHamoru festive cooking.', TRUE),
('corn_and_cheese_titiyas_guamanian', 'Corn and Cheese Titiyas', 355, 9.5, 48.5, 14.5, 3.5, 2.5, 90, 90, 'research', ARRAY['corn and cheese titiyas', 'with cheddar', 'with processed cheese', 'with mozzarella'], 'traditional', NULL, 1, 'GU', 'Modern variation of corn titiyas incorporating shredded cheese into the dough or as a topping, a contemporary CHamoru adaptation. This version is popular at modern CHamoru bakeries and fiesta tables.', TRUE),
('coconut_jam_guamanian', 'Coconut Jam', 285, 2.5, 42.5, 13.5, 2.5, 38.5, 40, NULL, 'research', ARRAY['coconut jam', 'pandan coconut jam', 'plain coconut jam'], 'traditional', NULL, 1, 'GU', 'Sweet coconut jam (similar to kaya) made from coconut milk, eggs, sugar, and pandan. A beloved spread for titiyas and bread, coconut jam is made in CHamoru homes and sold at local markets.', TRUE),
