('corn_dumplings_guam_guamanian', 'Corn Dumplings Guam', 195, 5.5, 35.5, 4.5, 3.5, 2.0, 150, NULL, 'research', ARRAY['corn dumplings guam', 'in chicken broth', 'in beef stew', 'sweet dessert version'], 'traditional', NULL, 1, 'GU', 'Boiled corn masa dumplings in broth or stew, a traditional CHamoru preparation that uses nixtamalized corn dough shaped into balls and cooked in soup. A hearty and filling traditional food.', TRUE),
