('chamorro_bbq_chicken_guamanian', 'Chamorro BBQ Chicken', 220, 25.0, 5.0, 11.0, 0.1, 3.5, 180, NULL, 'research', ARRAY['chamorro bbq chicken', 'roadside bbq chicken', 'achote bbq chicken'], 'traditional', NULL, 1, 'GU', 'Chicken marinated in soy sauce, vinegar, lemon, garlic, and achote powder, grilled over charcoal. Ubiquitous at roadside BBQ stands and fiestas across Guam.', TRUE),
('chicken_adobo_guam_style_guamanian', 'Chicken Adobo Guam Style', 235, 24.0, 3.0, 14.0, 0.2, 1.0, 200, NULL, 'research', ARRAY['chicken adobo guam style', 'adobo pollo', 'guam coconut adobo'], 'traditional', NULL, 1, 'GU', 'Filipino-origin adobo adapted in Guam with added coconut milk and local spices, simmered until rich and tender. The coconut addition distinguishes the Chamorro version from Philippine counterparts.', TRUE),
('pork_adobo_guam_style_guamanian', 'Pork Adobo Guam Style', 280, 20.0, 3.5, 20.0, 0.1, 1.5, 200, NULL, 'research', ARRAY['pork adobo guam style', 'adobo babui', 'pork belly adobo'], 'traditional', NULL, 1, 'GU', 'Pork belly or shoulder braised in vinegar, soy sauce, garlic, bay leaf, and black pepper, often with coconut milk stirred in at the end. A beloved weekday and fiesta dish on Guam.', TRUE),
