('fish_kadu_guamanian', 'Fish Kadu', 130, 16.0, 8.0, 4.0, 1.0, 1.5, 350, NULL, 'research', ARRAY['fish kadu', 'kadu guihan', 'reef fish stew'], 'traditional', NULL, 1, 'GU', 'A lighter version of kadu made with whole reef fish, root vegetables, and lemon. This clear, aromatic broth-based stew reflects the deep fishing heritage of the Chamorro people.', TRUE),
('beef_nilaga_guam_style_guamanian', 'Beef Nilaga Guam Style', 165, 15.0, 9.0, 7.5, 1.5, 2.0, 350, NULL, 'research', ARRAY['beef nilaga guam style', 'nilagang baka', 'guam boiled beef soup'], 'traditional', NULL, 1, 'GU', 'Filipino-origin boiled beef soup adopted into Guam''s food culture, featuring bone-in beef, potatoes, cabbage, and corn. Commonly served with white rice and fish sauce on the side.', TRUE),
('sinigang_adaptation_guam_style_guamanian', 'Sinigang Adaptation Guam Style', 145, 14.0, 8.0, 5.5, 1.8, 2.5, 350, NULL, 'research', ARRAY['sinigang adaptation guam style', 'sinigang na baboy', 'tamarind soup guam'], 'traditional', NULL, 1, 'GU', 'Tamarind-sour soup of Filipino origin widely cooked in Guam households, adapted with local fish or pork and island vegetables including kangkong and eggplant.', TRUE),
('ahu_red_snapper_chamorro_preparation_guamanian', 'Ahu (Red Snapper Chamorro Preparation)', 135, 22.0, 2.0, 4.5, 0.3, 0.5, 200, NULL, 'research', ARRAY['ahu (red snapper chamorro preparation)', 'grilled ahu', 'steamed red snapper'], 'traditional', NULL, 1, 'GU', 'Red snapper (ahu in Chamorro) prepared by grilling or steaming with lemon, garlic, onion, and soy sauce. One of the most prized reef fish in Guam''s traditional seafood cuisine.', TRUE),
('garlic_spam_musubi_guamanian', 'Garlic Spam Musubi', 210, 8.0, 28.0, 7.5, 0.5, 2.0, 120, 120, 'research', ARRAY['garlic spam musubi', 'spam musubi', 'garlic spam rice block'], 'street_food', NULL, 1, 'GU', 'A Guam twist on the Hawaiian musubi: Spam slices pan-fried with garlic and butter, placed atop seasoned rice and wrapped in nori. Sold at convenience stores and school canteens across the island.', TRUE),
('chicken_kelaguen_bbq_style_guamanian', 'Chicken Kelaguen BBQ Style', 195, 24.0, 3.0, 9.5, 0.5, 1.0, 150, NULL, 'research', ARRAY['chicken kelaguen bbq style', 'kelaguen mannok', 'bbq chicken kelaguen'], 'traditional', NULL, 1, 'GU', 'Grilled chicken pulled from the bone and mixed with lemon juice, fresh coconut, green onion, and hot pepper. Kelaguen is a distinctly Chamorro preparation that can be served warm or cold.', TRUE),
('achote_pork_guamanian', 'Achote Pork', 265, 19.0, 4.0, 19.0, 0.3, 1.5, 200, NULL, 'research', ARRAY['achote pork', 'pork achote', 'annatto pork'], 'traditional', NULL, 1, 'GU', 'Pork slow-cooked or roasted with achote (annatto) paste, garlic, and vinegar, giving it a deep orange-red color. Achote is the defining seasoning of Chamorro cuisine and culture.', TRUE),
