('longganisa_guam_style_guamanian', 'Longganisa Guam Style', 310, 14.0, 8.0, 25.0, 0.3, 4.0, 100, 50, 'research', ARRAY['longganisa guam style', 'sweet longganisa', 'chorizo de guam'], 'traditional', NULL, 1, 'GU', 'Sweet and garlicky Filipino-origin sausage widely sold and made in Guam, often pan-fried and served with garlic rice and eggs for breakfast. Guam versions tend to be sweeter than Philippine regional styles.', TRUE),
('finadene_marinated_pork_ribs_guamanian', 'Finadene Marinated Pork Ribs', 295, 20.0, 4.0, 22.0, 0.2, 2.0, 200, NULL, 'research', ARRAY['finadene marinated pork ribs', 'grilled ribs finadene', 'chamorro pork ribs'], 'traditional', NULL, 1, 'GU', 'Pork ribs soaked in finadene — Guam''s signature condiment sauce of soy, vinegar, lemon, onion, and hot pepper — then grilled over hardwood. The finadene doubles as both marinade and dipping sauce.', TRUE),
('tilapia_chamorro_style_guamanian', 'Tilapia Chamorro Style', 128, 20.0, 3.0, 4.0, 0.2, 1.0, 180, NULL, 'research', ARRAY['tilapia chamorro style', 'pan-fried tilapia', 'steamed tilapia'], 'seafood', NULL, 1, 'GU', 'Tilapia prepared with soy sauce, lemon, garlic, and ginger in the Chamorro tradition, either pan-fried or steamed. Tilapia farms on Guam supply local markets and restaurants.', TRUE),
('grilled_mahi_mahi_guamanian', 'Grilled Mahi-Mahi', 140, 24.0, 0.5, 4.5, 0.0, 0.2, 180, NULL, 'research', ARRAY['grilled mahi-mahi', 'dorado guam', 'finadene mahi-mahi'], 'seafood', NULL, 1, 'GU', 'Mahi-mahi (dorado) is one of the most commonly caught pelagic fish off Guam, typically grilled with lemon butter or finadene. Its firm, mildly sweet flesh makes it a local favorite.', TRUE),
('grilled_yellow_fin_tuna_guamanian', 'Grilled Yellow Fin Tuna', 148, 25.0, 0.0, 5.0, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled yellow fin tuna', 'ahi tuna guam', 'seared tuna steak'], 'seafood', NULL, 1, 'GU', 'Yellowfin tuna caught in Guam''s deep Pacific waters, grilled or seared with minimal seasoning. Also used in kelaguen and raw preparations, reflecting Chamorro reverence for fresh fish.', TRUE),
('beef_kelaguen_guamanian', 'Beef Kelaguen', 190, 22.0, 3.0, 10.0, 0.4, 1.0, 150, NULL, 'research', ARRAY['beef kelaguen', 'kelaguen guaka', 'beef lemon salad'], 'traditional', NULL, 1, 'GU', 'Grilled beef chopped and dressed with lemon juice, coconut, onion, and hot pepper in the kelaguen style. Less common than chicken or shrimp kelaguen but served at large fiestas.', TRUE),
('shrimp_kelaguen_guamanian', 'Shrimp Kelaguen', 110, 18.0, 4.0, 3.0, 0.5, 1.5, 150, NULL, 'research', ARRAY['shrimp kelaguen', 'kelaguen uhang', 'lemon shrimp kelaguen'], 'traditional', NULL, 1, 'GU', 'Shrimp boiled or grilled then mixed with lemon, fresh coconut, green onion, and donne'' pepper. A popular appetizer and fiesta dish that showcases Chamorro kelaguen technique.', TRUE),
('shrimp_scampi_guam_style_guamanian', 'Shrimp Scampi Guam Style', 195, 17.0, 5.0, 12.0, 0.3, 0.5, 180, NULL, 'research', ARRAY['shrimp scampi guam style', 'garlic butter shrimp', 'pacific shrimp scampi'], 'fusion', NULL, 1, 'GU', 'Guam''s version of shrimp scampi blends Italian technique with local flair — large Pacific shrimp sautéed in butter, garlic, white wine, and lemon, sometimes finished with achote.', TRUE),
('octopus_kelaguen_guamanian', 'Octopus Kelaguen', 105, 17.0, 4.5, 2.5, 0.4, 1.0, 150, NULL, 'research', ARRAY['octopus kelaguen', 'kelaguen he''e', 'octopus chamorro style'], 'traditional', NULL, 1, 'GU', 'Grilled or boiled octopus (he''e) dressed in lemon, fresh coconut, and hot pepper. Octopus has been a staple protein for the Chamorro people for thousands of years.', TRUE),
('chicken_tinaktak_guamanian', 'Chicken Tinaktak', 215, 20.0, 6.0, 12.0, 1.2, 3.0, 220, NULL, 'research', ARRAY['chicken tinaktak', 'tinaktak mannok', 'coconut chicken chamorro'], 'traditional', NULL, 1, 'GU', 'Ground or chopped chicken simmered in coconut milk with long beans, tomato, and hot pepper. Tinaktak is a uniquely Chamorro dish often compared to a coconut milk stir-fry.', TRUE),
('beef_tinaktak_guamanian', 'Beef Tinaktak', 240, 18.0, 6.0, 16.0, 1.2, 2.5, 220, NULL, 'research', ARRAY['beef tinaktak', 'tinaktak guaka', 'chamorro coconut beef'], 'traditional', NULL, 1, 'GU', 'The most traditional form of tinaktak — ground beef cooked in coconut milk with long beans and hot pepper. Considered a quintessential Chamorro comfort dish served over white rice.', TRUE),
('pork_tinaktak_guamanian', 'Pork Tinaktak', 255, 17.0, 5.5, 18.0, 1.0, 2.5, 220, NULL, 'research', ARRAY['pork tinaktak', 'tinaktak babui', 'pork coconut milk'], 'traditional', NULL, 1, 'GU', 'Ground pork version of tinaktak, equally popular as the beef variant, simmered in rich coconut milk with long beans and donne'' pepper. Often made for quick family meals.', TRUE),
('chamorro_roast_pig_lechon_guamanian', 'Chamorro Roast Pig (Lechon)', 295, 22.0, 0.0, 23.0, 0.0, 0.0, 200, NULL, 'research', ARRAY['chamorro roast pig (lechon)', 'lechon babui', 'fiesta roast pig', 'chamorro lechon'], 'traditional', NULL, 1, 'GU', 'Whole spit-roasted pig is the centerpiece of every major Chamorro fiesta, seasoned with garlic and local spices. The crispy skin (chicharron) is considered a delicacy.', TRUE),
('fried_spam_with_rice_guamanian', 'Fried Spam with Rice', 235, 9.0, 28.0, 10.0, 0.5, 1.5, 200, NULL, 'research', ARRAY['fried spam with rice', 'spam rice plate', 'canned pork rice'], 'everyday', NULL, 1, 'GU', 'Pan-fried Spam served alongside steamed white rice. Spam became a dietary staple on Guam after World War II and remains deeply embedded in everyday island food culture.', TRUE),
('pork_estufao_guamanian', 'Pork Estufao', 270, 19.0, 5.0, 19.0, 0.5, 2.0, 200, NULL, 'research', ARRAY['pork estufao', 'chamorro braised pork', 'estufao babui'], 'traditional', NULL, 1, 'GU', 'Braised pork in a Spanish-Chamorro style with vinegar, soy sauce, garlic, onion, and peppercorns. Estufao reflects the deep Spanish colonial influence on Chamorro cooking.', TRUE),
('chicken_estufao_guamanian', 'Chicken Estufao', 215, 23.0, 4.0, 11.0, 0.3, 1.5, 200, NULL, 'research', ARRAY['chicken estufao', 'estufao mannok', 'braised chicken chamorro'], 'traditional', NULL, 1, 'GU', 'Chicken braised in vinegar, garlic, onion, and bay leaves in the Chamorro estufao style. Often served with red rice and pickled vegetables at family dinners.', TRUE),
('grilled_wahoo_ono_guamanian', 'Grilled Wahoo (Ono)', 130, 23.0, 0.0, 4.0, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled wahoo (ono)', 'ono steak', 'wahoo fillet'], 'seafood', NULL, 1, 'GU', 'Wahoo (called ''ono'' meaning delicious in Hawaiian) is a prized game fish caught in Guam''s Pacific waters, grilled simply with lemon and butter to let the mild flavor shine.', TRUE),
('boiled_shrimp_with_finadene_guamanian', 'Boiled Shrimp with Finadene', 100, 19.0, 2.5, 1.5, 0.0, 0.5, 150, NULL, 'research', ARRAY['boiled shrimp with finadene', 'uhang finadene', 'boiled shrimp dipping'], 'traditional', NULL, 1, 'GU', 'Fresh shrimp boiled and served with finadene dipping sauce. This simple preparation highlights the freshness of Pacific shrimp and the bold flavor of Guam''s signature condiment.', TRUE),
('chamorro_chicken_soup_guamanian', 'Chamorro Chicken Soup', 110, 12.0, 7.0, 3.5, 0.8, 1.5, 350, NULL, 'research', ARRAY['chamorro chicken soup', 'caldo mannok', 'guam chicken broth'], 'traditional', NULL, 1, 'GU', 'Clear chicken broth soup with bone-in chicken, chayote, corn, and local vegetables. A restorative soup prepared for the sick and elderly across generations of Chamorro families.', TRUE),
('grilled_blue_marlin_guamanian', 'Grilled Blue Marlin', 155, 24.0, 0.0, 6.0, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled blue marlin', 'marlin steak', 'aguja grilled'], 'seafood', NULL, 1, 'GU', 'Blue marlin is one of Guam''s top sport fish, grilled as thick steaks. The firm, meaty flesh is similar to swordfish and is often served at seaside restaurants and fiestas.', TRUE),
('crab_in_coconut_milk_guamanian', 'Crab in Coconut Milk', 165, 15.0, 5.0, 9.5, 0.5, 2.0, 200, NULL, 'research', ARRAY['crab in coconut milk', 'coconut crab stew', 'guam crab ginataan'], 'traditional', NULL, 1, 'GU', 'Blue or mangrove crab simmered in coconut milk with garlic, ginger, and lemongrass. Coconut crab dishes reflect Guam''s dual Chamorro and Southeast Asian culinary heritage.', TRUE),
('grilled_parrotfish_guamanian', 'Grilled Parrotfish', 115, 21.0, 0.0, 3.0, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled parrotfish', 'palakse'' grilled', 'reef parrotfish'], 'seafood', NULL, 1, 'GU', 'Parrotfish (palakse'') is a reef fish commonly caught by Chamorro spearfishers, grilled whole over charcoal. Its sweet, delicate flesh is a traditional part of island seafood culture.', TRUE),
('beef_steak_filipino_style_guamanian', 'Beef Steak Filipino Style', 225, 22.0, 5.0, 13.0, 0.5, 1.5, 200, NULL, 'research', ARRAY['beef steak filipino style', 'bistek tagalog guam', 'beef steak soy-calamansi'], 'everyday', NULL, 1, 'GU', 'Bistek tagalog — thinly sliced beef in soy sauce and calamansi, topped with onion rings. Widely cooked in Guam due to the large Filipino community and reflects island fusion cuisine.', TRUE),
('lechon_kawali_guam_style_guamanian', 'Lechon Kawali Guam Style', 340, 18.0, 2.0, 29.0, 0.0, 0.5, 150, NULL, 'research', ARRAY['lechon kawali guam style', 'crispy pork belly', 'lechon kawali filipino-guam'], 'everyday', NULL, 1, 'GU', 'Deep-fried boiled pork belly with crispy crackling skin, served with vinegar dipping sauce. A Filipino-Guam adaptation extremely popular at family gatherings and carinderia-style eateries.', TRUE),
('grilled_boneless_bangus_milkfish_guamanian', 'Grilled Boneless Bangus (Milkfish)', 162, 22.0, 0.0, 8.0, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled boneless bangus (milkfish)', 'daing na bangus', 'boneless grilled milkfish'], 'seafood', NULL, 1, 'GU', 'Deboned milkfish marinated in soy sauce, calamansi, and garlic then grilled. Bangus is a Filipino staple fish beloved on Guam, commonly served for breakfast alongside garlic fried rice.', TRUE),
('pork_menudo_guam_style_guamanian', 'Pork Menudo Guam Style', 195, 14.0, 12.0, 10.0, 1.5, 3.0, 250, NULL, 'research', ARRAY['pork menudo guam style', 'menudo filipino-guam', 'pork liver tomato stew'], 'everyday', NULL, 1, 'GU', 'Filipino-influenced pork liver stew with potatoes, carrots, tomatoes, and bell pepper in a tomato-based sauce. A go-to dish in Guam homes, adapted slightly with local hot peppers.', TRUE),
('chamorro_chicken_and_pork_adobo_guamanian', 'Chamorro Chicken and Pork Adobo', 250, 21.0, 3.5, 16.5, 0.2, 1.0, 200, NULL, 'research', ARRAY['chamorro chicken and pork adobo', 'mixed adobo chamorro', 'chicken pork adobo fiesta'], 'traditional', NULL, 1, 'GU', 'A combined chicken and pork adobo simmered together with vinegar, soy sauce, and garlic. The mixed-meat version is popular at large Guam fiestas where variety is essential.', TRUE),
('spare_ribs_kare_kare_guam_style_guamanian', 'Spare Ribs Kare Kare Guam Style', 285, 18.0, 8.0, 20.0, 2.0, 3.0, 250, NULL, 'research', ARRAY['spare ribs kare kare guam style', 'kare kare baboy guam', 'peanut oxtail stew'], 'everyday', NULL, 1, 'GU', 'Filipino peanut stew with pork spare ribs, eggplant, and banana blossom, widely cooked in Guam. Served with bagoong (fermented shrimp paste) and rice for a rich, hearty meal.', TRUE),
('dinuguan_guam_style_guamanian', 'Dinuguan Guam Style', 210, 14.0, 5.0, 15.0, 0.5, 1.0, 200, NULL, 'research', ARRAY['dinuguan guam style', 'pork blood stew guam', 'chocolate meat filipino-guam'], 'everyday', NULL, 1, 'GU', 'Savory Filipino pork blood stew with vinegar and chili, known as ''chocolate meat''. Widely made in Filipino-Chamorro households on Guam and served with puto (rice cakes) or rice.', TRUE),
('beef_caldereta_guam_style_guamanian', 'Beef Caldereta Guam Style', 230, 17.0, 10.0, 14.0, 1.5, 3.0, 250, NULL, 'research', ARRAY['beef caldereta guam style', 'calderetang baka guam', 'filipino beef stew island'], 'everyday', NULL, 1, 'GU', 'Filipino goat or beef stew in tomato sauce with liver paste, olives, potatoes, and bell pepper. On Guam, beef versions are far more common than goat, enriched with local spices.', TRUE),
('grilled_pacific_lobster_guamanian', 'Grilled Pacific Lobster', 112, 20.5, 1.5, 2.5, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled pacific lobster', 'spiny lobster guam', 'grilled rock lobster'], 'seafood', NULL, 1, 'GU', 'Pacific spiny lobster grilled with butter and garlic is a prized dish at Guam seafood restaurants. Lobster fishing is regulated on the island to protect reef populations.', TRUE),
('pork_humba_guam_style_guamanian', 'Pork Humba Guam Style', 275, 18.0, 10.0, 18.0, 0.5, 5.0, 200, NULL, 'research', ARRAY['pork humba guam style', 'braised sweet pork', 'humba baboy guam'], 'everyday', NULL, 1, 'GU', 'Visayan-origin braised pork with banana blossoms, soy sauce, vinegar, and brown sugar. Popular in Guam''s Filipino community, humba is a sweeter, deeper cousin of adobo.', TRUE),
('chicken_afritada_guam_style_guamanian', 'Chicken Afritada Guam Style', 185, 18.0, 9.0, 8.5, 1.2, 4.0, 250, NULL, 'research', ARRAY['chicken afritada guam style', 'afritadang manok guam', 'tomato chicken stew'], 'everyday', NULL, 1, 'GU', 'Chicken braised in tomato sauce with potatoes, carrots, and bell pepper of Filipino-Spanish origin, widely cooked across Guam. A mild, family-friendly stew served at everyday meals.', TRUE),
('beef_mechado_guam_style_guamanian', 'Beef Mechado Guam Style', 210, 18.0, 8.0, 12.0, 1.0, 3.0, 250, NULL, 'research', ARRAY['beef mechado guam style', 'beef mechado filipino-guam', 'larded beef stew'], 'everyday', NULL, 1, 'GU', 'Spanish-Filipino larded beef stew with tomatoes, potatoes, and soy sauce. Mechado is common throughout Guam''s Filipino-heritage households and served at fiestas and family lunches.', TRUE),
('stuffed_bitter_melon_ampalaya_rellenong_guamanian', 'Stuffed Bitter Melon (Ampalaya Rellenong)', 130, 10.0, 7.0, 7.0, 2.5, 2.0, 200, NULL, 'research', ARRAY['stuffed bitter melon (ampalaya rellenong)', 'rellenong ampalaya guam', 'stuffed bitter gourd'], 'everyday', NULL, 1, 'GU', 'Bitter melon stuffed with seasoned ground pork, egg-dipped and pan-fried. A Filipino dish widely prepared in Guam that combines the bitterness of the gourd with savory pork filling.', TRUE),
('grilled_sword_fish_guamanian', 'Grilled Sword Fish', 144, 22.0, 0.0, 6.0, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled sword fish', 'pez espada steak', 'pacific swordfish'], 'seafood', NULL, 1, 'GU', 'Swordfish caught in Guam''s deep Pacific waters, grilled with lemon and herbs. Its dense, meaty texture makes it a popular choice at island restaurants and sport fishing events.', TRUE),
('prawn_sinigang_guamanian', 'Prawn Sinigang', 120, 14.0, 7.0, 3.5, 2.0, 2.5, 350, NULL, 'research', ARRAY['prawn sinigang', 'sinigang na hipon guam', 'tamarind prawn soup'], 'everyday', NULL, 1, 'GU', 'Giant freshwater prawns in tamarind-sour broth with daikon, kangkong, and eggplant. A Filipino-origin soup beloved in Guam, where large prawns are available from local aquaculture.', TRUE),
('tinola_chicken_guam_style_guamanian', 'Tinola Chicken Guam Style', 115, 13.0, 6.0, 3.5, 1.0, 1.5, 350, NULL, 'research', ARRAY['tinola chicken guam style', 'tinolang manok guam', 'ginger chicken papaya soup'], 'everyday', NULL, 1, 'GU', 'Ginger-based chicken soup with green papaya and chili leaves, adapted from Filipino tinola. On Guam, moringa (malunggay) leaves are often substituted for chili leaves in local versions.', TRUE),
('grilled_giant_clam_guamanian', 'Grilled Giant Clam', 74, 12.0, 3.5, 1.0, 0.0, 0.5, 150, NULL, 'research', ARRAY['grilled giant clam', 'taklobo guam', 'farmed giant clam grilled'], 'seafood', NULL, 1, 'GU', 'Giant clam (taklobo) was historically harvested from Guam''s reefs and grilled or steamed. Now protected, farmed giant clams are legally available and considered an island delicacy.', TRUE),
('pork_sinigang_guamanian', 'Pork Sinigang', 140, 12.0, 8.0, 6.0, 2.0, 2.0, 350, NULL, 'research', ARRAY['pork sinigang', 'sinigang na baboy guam', 'tamarind pork soup island'], 'everyday', NULL, 1, 'GU', 'Sour tamarind pork soup with sitaw (long beans), eggplant, and daikon. Among the most popular soups eaten daily in Filipino-Chamorro households across Guam.', TRUE),
('chicken_inasal_guam_style_guamanian', 'Chicken Inasal Guam Style', 210, 24.0, 4.0, 11.0, 0.2, 2.5, 180, NULL, 'research', ARRAY['chicken inasal guam style', 'bacolod chicken guam', 'inasal manok island'], 'everyday', NULL, 1, 'GU', 'Visayan-origin grilled chicken marinated in vinegar, lemongrass, ginger, and annatto oil. Popular at Filipino-run BBQ grills on Guam, served with garlic rice and vinegar dip.', TRUE),
('chamorro_pork_and_vegetable_soup_guamanian', 'Chamorro Pork and Vegetable Soup', 150, 13.0, 10.0, 6.0, 2.0, 2.5, 350, NULL, 'research', ARRAY['chamorro pork and vegetable soup', 'chamorro pork soup', 'island pork vegetable kadu'], 'traditional', NULL, 1, 'GU', 'Slow-simmered pork rib soup with local vegetables including taro, yam, corn, and green banana. This nourishing soup has fed Chamorro families through generations.', TRUE),
('squid_adobo_guamanian', 'Squid Adobo', 145, 16.0, 4.0, 7.0, 0.2, 0.5, 180, NULL, 'research', ARRAY['squid adobo', 'squid ink adobo', 'adobong pusit guam'], 'everyday', NULL, 1, 'GU', 'Fresh squid cooked in its own ink with vinegar, soy sauce, and garlic. A Filipino-Chamorro specialty that turns the braising liquid a deep, rich black color prized for its depth of flavor.', TRUE),
('grilled_sea_bass_guamanian', 'Grilled Sea Bass', 124, 21.0, 0.0, 4.0, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled sea bass', 'reef sea bass grilled', 'island sea bass'], 'seafood', NULL, 1, 'GU', 'Sea bass varieties caught around Guam''s reef system grilled whole or as fillets with lemon and herbs. A staple at waterfront seafood restaurants popular with both locals and tourists.', TRUE),
('chamorro_beef_soup_caldo_guamanian', 'Chamorro Beef Soup (Caldo)', 145, 14.0, 9.0, 5.5, 1.0, 1.5, 350, NULL, 'research', ARRAY['chamorro beef soup (caldo)', 'caldo guaka', 'chamorro beef bone broth'], 'traditional', NULL, 1, 'GU', 'Beef bone-in soup simmered for hours with local vegetables. Called caldo — from Spanish — this hearty broth-based soup is a cold remedy and celebration dish in Chamorro culture.', TRUE),
('bbq_pork_belly_skewers_guamanian', 'BBQ Pork Belly Skewers', 320, 14.0, 5.0, 27.0, 0.2, 3.5, 150, 50, 'research', ARRAY['bbq pork belly skewers', 'pork belly skewers guam', 'bbq isaw-style pork'], 'street_food', NULL, 1, 'GU', 'Thinly sliced pork belly threaded on bamboo skewers, marinated in soy-garlic sauce with achote and grilled over charcoal. Sold at roadside BBQ stands throughout Guam.', TRUE),
('grilled_grouper_guamanian', 'Grilled Grouper', 118, 22.0, 0.0, 3.0, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled grouper', 'lapiti grilled', 'pacific grouper fillet'], 'seafood', NULL, 1, 'GU', 'Grouper (lapiti) is a highly prized reef fish caught by Chamorro fishers, grilled whole or filleted with minimal seasoning. Its firm white flesh is among the most sought-after on the island.', TRUE),
('pork_sisig_guam_style_guamanian', 'Pork Sisig Guam Style', 295, 16.0, 3.0, 24.0, 0.3, 1.0, 150, NULL, 'research', ARRAY['pork sisig guam style', 'sizzling sisig guam', 'pork face sizzle plate'], 'everyday', NULL, 1, 'GU', 'Chopped pork face and ears sizzled on a hot plate with onion, calamansi, and chili. Filipino sisig has been enthusiastically adopted in Guam''s casual dining scene.', TRUE),
('achiote_chicken_wings_guamanian', 'Achiote Chicken Wings', 270, 22.0, 4.0, 18.0, 0.2, 2.0, 150, 30, 'research', ARRAY['achiote chicken wings', 'achote wings', 'chamorro chicken wings'], 'traditional', NULL, 1, 'GU', 'Chicken wings marinated in achote oil, garlic, and soy sauce, then grilled or baked. A beloved snack and party food on Guam that showcases the iconic orange achote coloring.', TRUE),
('pork_kadu_with_taro_guamanian', 'Pork Kadu with Taro', 185, 14.0, 14.0, 7.5, 2.0, 1.5, 350, NULL, 'research', ARRAY['pork kadu with taro', 'kadu suni babui', 'pork taro soup'], 'traditional', NULL, 1, 'GU', 'A hearty variation of kadu featuring pork ribs and chunks of taro root simmered in a savory broth. Taro (suni) has been cultivated in Guam for over 3,000 years.', TRUE),
('fried_milkfish_bangus_guamanian', 'Fried Milkfish (Bangus)', 190, 20.0, 2.0, 11.0, 0.0, 0.0, 180, NULL, 'research', ARRAY['fried milkfish (bangus)', 'pritong bangus', 'fried milkfish filipino-guam'], 'everyday', NULL, 1, 'GU', 'Whole or filleted milkfish pan-fried until golden and crispy. A Filipino-origin dish extremely popular in Guam, eaten for breakfast, lunch, or dinner with rice and tomato salad.', TRUE),
('chamorro_chicken_kelaguen_traditional_guamanian', 'Chamorro Chicken Kelaguen (Traditional)', 185, 23.0, 4.0, 8.5, 0.8, 2.0, 150, NULL, 'research', ARRAY['chamorro chicken kelaguen (traditional)', 'kelaguen mannok classic', 'traditional chamorro kelaguen'], 'traditional', NULL, 1, 'GU', 'The original form of kelaguen: whole chicken grilled over charcoal, pulled apart by hand, then mixed with freshly grated coconut, lemon juice, salt, and donne'' sali (hot pepper). A national dish of Guam.', TRUE),
('grilled_tuna_belly_guamanian', 'Grilled Tuna Belly', 165, 20.0, 0.0, 9.0, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled tuna belly', 'tuna belly grilled', 'fatty tuna guam style'], 'seafood', NULL, 1, 'GU', 'Fatty tuna belly (toro equivalent) grilled over open charcoal is prized at local Guam fish markets. The high fat content gives it a buttery, rich flavor unlike standard tuna cuts.', TRUE),
('chamorro_pork_bbq_plate_guamanian', 'Chamorro Pork BBQ Plate', 310, 22.0, 8.0, 21.0, 0.5, 5.0, 200, NULL, 'research', ARRAY['chamorro pork bbq plate', 'mixed bbq pork plate', 'chamorro bbq assorted'], 'traditional', NULL, 1, 'GU', 'Assorted pork cuts — ribs, belly, shoulder — marinated in soy-achote BBQ marinade and grilled for village BBQ plates. Sold at fiestas and roadside BBQ shacks all over Guam.', TRUE),
('beef_salpicao_guamanian', 'Beef Salpicao', 235, 21.0, 3.0, 15.0, 0.3, 1.5, 180, NULL, 'research', ARRAY['beef salpicao', 'garlic beef guam', 'salpicao baka island'], 'everyday', NULL, 1, 'GU', 'Garlic beef sauté in Worcestershire and oyster sauce with lots of garlic. Filipino-origin beef salpicao is popular at restaurants across Guam, often served as a rice topper.', TRUE),
('pinakbet_guam_style_guamanian', 'Pinakbet Guam Style', 115, 7.0, 9.0, 6.0, 3.0, 4.0, 200, NULL, 'research', ARRAY['pinakbet guam style', 'pinakbet baboy guam', 'ilocano vegetable stew island'], 'everyday', NULL, 1, 'GU', 'Ilocano vegetable stew with pork or shrimp paste, bitter melon, eggplant, okra, and squash. Pinakbet is one of the most common dishes in Guam Filipino households.', TRUE),
('fried_chicken_chamorro_style_guamanian', 'Fried Chicken Chamorro Style', 255, 22.0, 8.0, 15.0, 0.3, 1.0, 180, NULL, 'research', ARRAY['fried chicken chamorro style', 'chamorro fried chicken', 'achote fried chicken'], 'everyday', NULL, 1, 'GU', 'Chicken marinated in soy, garlic, and achote then coated and deep-fried. Chamorro fried chicken is a school lunch staple and popular fast food item across the island.', TRUE),
('tuna_kelaguen_guamanian', 'Tuna Kelaguen', 155, 22.0, 3.5, 5.5, 0.5, 1.0, 150, NULL, 'research', ARRAY['tuna kelaguen', 'kelaguen tuna', 'raw tuna chamorro lemon'], 'traditional', NULL, 1, 'GU', 'Fresh tuna finely chopped and mixed with lemon juice, coconut, green onion, and hot pepper — essentially a Chamorro-style tuna ceviche. Served chilled as an appetizer at fiestas.', TRUE),
('pork_pochero_guam_style_guamanian', 'Pork Pochero Guam Style', 200, 15.0, 11.0, 11.0, 2.0, 3.0, 300, NULL, 'research', ARRAY['pork pochero guam style', 'cocido guam style', 'pork pochero filipino-island'], 'everyday', NULL, 1, 'GU', 'Spanish-Filipino boiled dinner with pork, vegetables, and chorizo de bilbao sausage. Pochero is popular in Guam especially during cooler months and holidays.', TRUE),
('grilled_snapper_with_finadene_guamanian', 'Grilled Snapper with Finadene', 130, 22.0, 2.5, 4.0, 0.2, 0.5, 180, NULL, 'research', ARRAY['grilled snapper with finadene', 'red snapper finadene', 'guam grilled whole fish'], 'traditional', NULL, 1, 'GU', 'Whole red snapper grilled over charcoal and served with finadene on the side for dipping or pouring. A quintessential beachside meal in Guam.', TRUE),
('chamorro_chicken_afijao_guamanian', 'Chamorro Chicken Afijao', 235, 22.0, 5.0, 14.0, 0.5, 2.0, 200, NULL, 'research', ARRAY['chamorro chicken afijao', 'chamorro red chicken stew', 'afijao mannok'], 'traditional', NULL, 1, 'GU', 'Chicken cooked with achote, garlic, vinegar, and coconut milk in a richly colored stew unique to Chamorro cuisine. Afijao (also spelled ''affiha'') was historically served at important gatherings.', TRUE),
('beef_pochero_guamanian', 'Beef Pochero', 195, 16.0, 10.0, 10.0, 2.0, 2.5, 300, NULL, 'research', ARRAY['beef pochero', 'pochero de baka guam', 'spanish beef stew island'], 'everyday', NULL, 1, 'GU', 'Beef version of the Spanish-origin boiled dinner stew with potatoes, cabbage, chickpeas, and tomato sauce. Guam''s Filipino heritage makes this a standard home-cooked comfort meal.', TRUE),
('garlic_butter_crab_guamanian', 'Garlic Butter Crab', 145, 16.0, 3.0, 8.0, 0.0, 0.5, 200, NULL, 'research', ARRAY['garlic butter crab', 'garlic crab guam', 'butter garlic alimasag'], 'seafood', NULL, 1, 'GU', 'Crab halves stir-fried in butter with generous garlic, sometimes finished with chili. A popular restaurant-style crab preparation in Guam influenced by both Filipino and American cooking.', TRUE),
('pork_ribs_in_achote_broth_guamanian', 'Pork Ribs in Achote Broth', 260, 19.0, 6.0, 18.0, 0.3, 1.5, 250, NULL, 'research', ARRAY['pork ribs in achote broth', 'achote rib soup', 'chamorro pork rib broth'], 'traditional', NULL, 1, 'GU', 'Pork ribs simmered in an achote-tinted broth with garlic and onion until fall-off-the-bone tender. The achote imparts both color and a subtle earthy flavor to the broth.', TRUE),
('chicken_pochero_guam_style_guamanian', 'Chicken Pochero Guam Style', 175, 16.0, 10.0, 7.5, 2.0, 3.0, 300, NULL, 'research', ARRAY['chicken pochero guam style', 'pochero manok guam', 'chicken boiled dinner'], 'everyday', NULL, 1, 'GU', 'Chicken-based pochero with potatoes, plantain, cabbage, and tomato sauce. A lighter alternative to the pork version, common in Guam family kitchens for Sunday dinners.', TRUE),
('fish_escabeche_guam_style_guamanian', 'Fish Escabeche Guam Style', 155, 18.0, 8.0, 6.0, 0.5, 4.0, 200, NULL, 'research', ARRAY['fish escabeche guam style', 'escabecheng isda guam', 'sweet sour fried fish'], 'everyday', NULL, 1, 'GU', 'Fried fish served in a sweet-and-sour sauce with bell pepper, carrot, and ginger. Spanish-Filipino escabeche is popular at Guam fiestas as a colorful, tangy fish course.', TRUE),
('grilled_pork_chops_chamorro_guamanian', 'Grilled Pork Chops Chamorro', 240, 25.0, 3.0, 14.0, 0.1, 2.0, 200, NULL, 'research', ARRAY['grilled pork chops chamorro', 'chamorro pork chop', 'finadene pork chop grilled'], 'traditional', NULL, 1, 'GU', 'Pork chops marinated in finadene or soy-lemon marinade and grilled. A popular home-cooked and restaurant meal on Guam, often served with red rice and cucumber salad.', TRUE),
('lobster_butter_guam_style_guamanian', 'Lobster Butter Guam Style', 145, 18.0, 2.0, 7.5, 0.0, 0.5, 180, NULL, 'research', ARRAY['lobster butter guam style', 'butter lobster tail guam', 'spiny lobster garlic'], 'seafood', NULL, 1, 'GU', 'Spiny lobster tail sautéed in butter and garlic with lemon. A high-end seafood preparation available at Guam''s tourist-facing waterfront restaurants.', TRUE),
('beef_callos_guam_style_guamanian', 'Beef Callos Guam Style', 210, 15.0, 9.0, 13.0, 1.5, 2.0, 250, NULL, 'research', ARRAY['beef callos guam style', 'callos con garbanzos guam', 'tripe stew island'], 'everyday', NULL, 1, 'GU', 'Tripe and chorizo stew in tomato sauce with chickpeas. Spanish-origin callos adapted in the Philippines and then brought to Guam, served at special occasions.', TRUE),
('grilled_mullet_guamanian', 'Grilled Mullet', 150, 20.0, 0.0, 7.5, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled mullet', 'asuli grilled', 'island mullet whole'], 'seafood', NULL, 1, 'GU', 'Mullet (asuli) is caught in Guam''s coastal waters and grilled whole with lemon. A common everyday fish for local families, mullet is also used in fish kadu.', TRUE),
('tinolang_isda_fish_ginger_soup_guamanian', 'Tinolang Isda (Fish Ginger Soup)', 105, 15.0, 5.0, 2.5, 0.8, 1.5, 350, NULL, 'research', ARRAY['tinolang isda (fish ginger soup)', 'fish tinola guam', 'ginger fish soup island'], 'everyday', NULL, 1, 'GU', 'Fish cooked in ginger broth with green papaya and leafy greens. A Filipino-style fish tinola widely adopted in Guam, lighter and more delicate than meat-based soups.', TRUE),
('chamorro_beef_kelaguen_guamanian', 'Chamorro Beef Kelaguen', 185, 20.0, 4.5, 9.5, 0.5, 1.5, 150, NULL, 'research', ARRAY['chamorro beef kelaguen', 'kelaguen guaka chamorro', 'beef lemon coconut salad'], 'traditional', NULL, 1, 'GU', 'Grilled beef, finely chopped and mixed with lemon juice, fresh coconut, onion, and donne'' hot pepper. A less common but cherished variation of the traditional Chamorro kelaguen.', TRUE),
('chicken_caldereta_guam_style_guamanian', 'Chicken Caldereta Guam Style', 195, 18.0, 9.0, 10.0, 1.5, 3.5, 250, NULL, 'research', ARRAY['chicken caldereta guam style', 'calderetang manok guam', 'chicken liver tomato stew'], 'everyday', NULL, 1, 'GU', 'Chicken version of caldereta with liver spread, potatoes, olives, and bell pepper in tomato sauce. Popular at Guam family meals as a more affordable alternative to goat or beef.', TRUE),
('steamed_whole_fish_chamorro_guamanian', 'Steamed Whole Fish Chamorro', 112, 20.0, 2.0, 2.5, 0.3, 0.5, 180, NULL, 'research', ARRAY['steamed whole fish chamorro', 'steamed reef fish guam', 'chamorro steamed whole fish'], 'traditional', NULL, 1, 'GU', 'Whole reef fish steamed over aromatic ginger, lemon, and scallion then topped with hot oil and soy sauce in the Chinese-Chamorro fusion style common in Guam.', TRUE),
('ox_tail_kare_kare_guamanian', 'Ox Tail Kare Kare', 260, 18.0, 9.0, 17.0, 2.5, 2.5, 250, NULL, 'research', ARRAY['ox tail kare kare', 'oxtail peanut stew guam', 'kare kare buntot guam'], 'everyday', NULL, 1, 'GU', 'Classic Filipino peanut oxtail stew with banana blossom, eggplant, and sitaw, widely eaten in Guam. The gelatin-rich oxtail makes the peanut sauce silky and deeply satisfying.', TRUE),
('shrimp_in_coconut_milk_guamanian', 'Shrimp in Coconut Milk', 165, 14.0, 5.0, 10.0, 0.5, 2.5, 200, NULL, 'research', ARRAY['shrimp in coconut milk', 'shrimp ginataan guam', 'coconut milk shrimp island'], 'traditional', NULL, 1, 'GU', 'Shrimp simmered in coconut milk with garlic, ginger, and hot pepper. Reflects the Chamorro and Filipino blending of Pacific coconut cuisine with fresh island seafood.', TRUE),
('pork_and_shrimp_pancit_bihon_guamanian', 'Pork and Shrimp Pancit Bihon', 165, 9.0, 22.0, 4.5, 1.0, 2.0, 250, NULL, 'research', ARRAY['pork and shrimp pancit bihon', 'pancit bihon guam fiesta', 'rice noodle stir-fry island'], 'everyday', NULL, 1, 'GU', 'Thin rice noodles stir-fried with pork, shrimp, cabbage, carrots, and celery. Pancit bihon is made at virtually every Guam birthday and fiesta for good luck and long life.', TRUE),
('chicken_barbecue_on_stick_guamanian', 'Chicken Barbecue on Stick', 205, 23.0, 6.0, 10.0, 0.2, 4.0, 120, 120, 'research', ARRAY['chicken barbecue on stick', 'chicken bbq skewer guam', 'inihaw na manok stick'], 'street_food', NULL, 1, 'GU', 'Bite-sized marinated chicken on bamboo skewers grilled over charcoal at Guam''s night markets and roadside stands. A street food staple influenced by Filipino BBQ culture.', TRUE),
('chamorro_pork_and_bitter_melon_guamanian', 'Chamorro Pork and Bitter Melon', 155, 11.0, 6.0, 9.5, 2.0, 2.5, 200, NULL, 'research', ARRAY['chamorro pork and bitter melon', 'pork ampalaya guam', 'bitter melon pork stir-fry'], 'everyday', NULL, 1, 'GU', 'Sliced pork stir-fried with bitter melon (ampalaya) and egg in soy sauce and garlic. A common weekday dish in Guam households that balances protein with the bitter, healthful melon.', TRUE),
('grilled_barracuda_guamanian', 'Grilled Barracuda', 125, 22.5, 0.0, 3.5, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled barracuda', 'reef barracuda grilled', 'island barracuda steak'], 'seafood', NULL, 1, 'GU', 'Barracuda caught off Guam''s reef edge is grilled over charcoal. A lean, firm-fleshed fish popular among local fishermen, though the species must be sourced carefully due to ciguatera risk.', TRUE),
('chamorro_fiesta_chicken_guamanian', 'Chamorro Fiesta Chicken', 250, 24.0, 5.0, 15.0, 0.3, 2.5, 200, NULL, 'research', ARRAY['chamorro fiesta chicken', 'guam fiesta chicken', 'achote chicken chamorro fiesta'], 'traditional', NULL, 1, 'GU', 'Large pieces of chicken simmered in a rich achote-soy broth with vegetables. Fiesta chicken is served at every village feast as part of the traditional Chamorro feast spread.', TRUE),
('beef_pares_guam_style_guamanian', 'Beef Pares Guam Style', 200, 16.0, 10.0, 11.0, 0.5, 4.0, 250, NULL, 'research', ARRAY['beef pares guam style', 'beef pares filipino-guam', 'star anise beef stew rice'], 'everyday', NULL, 1, 'GU', 'Braised beef brisket in soy-star anise broth served over rice. Filipino beef pares is popular in Guam''s local eateries, pairing the sweet-savory meat with clear garlic soup.', TRUE),
('pork_and_beans_chamorro_style_guamanian', 'Pork and Beans Chamorro Style', 185, 12.0, 16.0, 8.0, 4.5, 3.5, 250, NULL, 'research', ARRAY['pork and beans chamorro style', 'guam pork beans', 'sausage beans american-chamorro'], 'everyday', NULL, 1, 'GU', 'Pork sausage or belly cooked with white beans or red kidney beans in tomato sauce. An American-influenced hearty dish widely eaten in Guam since the mid-20th century.', TRUE),
('stuffed_squid_guam_style_guamanian', 'Stuffed Squid Guam Style', 155, 15.0, 7.0, 7.5, 0.5, 1.5, 180, NULL, 'research', ARRAY['stuffed squid guam style', 'rellenong pusit guam', 'stuffed squid tomato sauce'], 'everyday', NULL, 1, 'GU', 'Whole squid tubes stuffed with seasoned ground pork, rice, and vegetables then braised in tomato sauce. A Spanish-Filipino technique commonly used in Guam for festive seafood dishes.', TRUE),
('chamorro_chicken_salad_ensalada_mannok_guamanian', 'Chamorro Chicken Salad (Ensalada Mannok)', 165, 16.0, 5.0, 9.0, 1.0, 2.0, 150, NULL, 'research', ARRAY['chamorro chicken salad (ensalada mannok)', 'chicken salad chamorro', 'ensalada mannok'], 'traditional', NULL, 1, 'GU', 'Boiled or grilled chicken shredded and mixed with lemon, onion, tomato, and hot pepper in a style similar to kelaguen but served as a salad. A light, refreshing dish for hot Guam days.', TRUE),
('grilled_amberjack_guamanian', 'Grilled Amberjack', 132, 23.0, 0.0, 4.0, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled amberjack', 'kahala steak guam', 'pacific amberjack grilled'], 'seafood', NULL, 1, 'GU', 'Amberjack (kahala) is caught by trolling off Guam''s north shore and grilled as thick steaks. Its rich, buttery flavor makes it a premium catch prized by island sport fishers.', TRUE),
('chicken_binagoongan_guamanian', 'Chicken Binagoongan', 225, 20.0, 4.0, 14.0, 0.5, 2.0, 180, NULL, 'research', ARRAY['chicken binagoongan', 'binagoongang manok guam', 'shrimp paste chicken'], 'everyday', NULL, 1, 'GU', 'Chicken cooked with bagoong (shrimp paste) and tomato, a Filipino-origin dish popular in Guam. The fermented shrimp paste gives the dish a pungent, savory depth.', TRUE),
('chamorro_beef_stew_with_root_vegetables_guamanian', 'Chamorro Beef Stew with Root Vegetables', 175, 14.0, 12.0, 7.5, 2.0, 2.5, 350, NULL, 'research', ARRAY['chamorro beef stew with root vegetables', 'chamorro beef root stew', 'kadu guaka root vegetables'], 'traditional', NULL, 1, 'GU', 'Beef simmered with yam, cassava, taro, and corn in a clear broth enriched with achote. This root vegetable-heavy stew reflects traditional Chamorro staple crops.', TRUE),
('pork_ribs_sinigang_guamanian', 'Pork Ribs Sinigang', 165, 13.0, 7.0, 9.0, 2.0, 2.0, 350, NULL, 'research', ARRAY['pork ribs sinigang', 'sinigang ribs guam', 'pork rib tamarind soup'], 'everyday', NULL, 1, 'GU', 'Pork spare ribs in sour tamarind broth with sitaw, eggplant, and kangkong. Sinigang sa sampalok (tamarind) is the most popular variation made in Guam households.', TRUE),
('grilled_skipjack_tuna_guamanian', 'Grilled Skipjack Tuna', 140, 23.0, 0.0, 5.0, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled skipjack tuna', 'atun grilled guam', 'skipjack steak chamorro'], 'seafood', NULL, 1, 'GU', 'Skipjack tuna (atun) grilled over charcoal is a traditional method of preparation for Chamorro fishermen. Also dried and smoked as an alternative fish preservation technique.', TRUE),
('spicy_garlic_pork_guamanian', 'Spicy Garlic Pork', 290, 18.0, 5.0, 21.0, 0.5, 2.0, 180, NULL, 'research', ARRAY['spicy garlic pork', 'garlic pork guam', 'spicy soy pork stir-fry'], 'everyday', NULL, 1, 'GU', 'Pork stir-fried in generous garlic with soy sauce, vinegar, and donne'' hot peppers. A bold, flavorful dish that shows the Chamorro love of garlic and heat in everyday cooking.', TRUE),
('chamorro_oxtail_soup_guamanian', 'Chamorro Oxtail Soup', 190, 17.0, 6.0, 11.0, 1.0, 1.5, 350, NULL, 'research', ARRAY['chamorro oxtail soup', 'oxtail kadu', 'guam oxtail broth'], 'traditional', NULL, 1, 'GU', 'Gelatinous oxtail slow-simmered with root vegetables and corn in a rich, golden broth. Oxtail soup is a special-occasion dish in Chamorro culture, labor-intensive and deeply nourishing.', TRUE),
('chicken_bbq_drumstick_guamanian', 'Chicken BBQ Drumstick', 215, 22.0, 5.0, 11.5, 0.2, 3.0, 130, 130, 'research', ARRAY['chicken bbq drumstick', 'bbq drumstick guam', 'achote chicken drumstick'], 'street_food', NULL, 1, 'GU', 'Chicken drumsticks marinated in soy sauce, lemon juice, and achote then grilled over charcoal at roadside stalls. Sold singly or in pairs at Guam''s many informal BBQ stands.', TRUE),
('shrimp_and_pork_dumpling_siomai_guam_style_guamanian', 'Shrimp and Pork Dumpling (Siomai Guam Style)', 145, 10.0, 12.0, 6.0, 0.5, 1.0, 150, 15, 'research', ARRAY['shrimp and pork dumpling (siomai guam style)', 'siomai guam', 'steamed pork shrimp dumpling'], 'everyday', NULL, 1, 'GU', 'Open-faced steamed dumplings with shrimp and pork filling in wonton skin, served with soy-calamansi dip. Filipino-Chinese siomai is sold at every Guam food court and carinderia.', TRUE),
('chamorro_pork_loin_roast_guamanian', 'Chamorro Pork Loin Roast', 230, 26.0, 3.0, 13.0, 0.2, 1.5, 200, NULL, 'research', ARRAY['chamorro pork loin roast', 'roast pork loin chamorro', 'achote roast pork loin'], 'traditional', NULL, 1, 'GU', 'Pork loin rubbed with achote paste, garlic, and vinegar then slow-roasted. A leaner alternative to lechon but equally festive, often served at family dinners and fiestas.', TRUE),
('banana_blossom_kare_kare_guamanian', 'Banana Blossom Kare Kare', 175, 10.0, 12.0, 10.0, 3.5, 3.0, 250, NULL, 'research', ARRAY['banana blossom kare kare', 'kare kare puso ng saging', 'banana heart peanut stew'], 'everyday', NULL, 1, 'GU', 'Kare kare made with banana blossom and tofu for a vegetarian-leaning version, though often still flavored with shrimp paste. Popular in Guam''s Filipino community as a meatless meal option.', TRUE),
('grilled_reef_triggerfish_guamanian', 'Grilled Reef Triggerfish', 110, 21.0, 0.0, 2.5, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled reef triggerfish', 'paruh grilled', 'chamorro triggerfish'], 'seafood', NULL, 1, 'GU', 'Triggerfish (paruh) is a reef fish speared by Chamorro free divers and grilled whole. Its tough skin peels away to reveal delicate, sweet white flesh that is highly prized locally.', TRUE),
('beef_nilaga_with_corn_guamanian', 'Beef Nilaga with Corn', 170, 14.0, 12.0, 6.5, 1.5, 3.0, 350, NULL, 'research', ARRAY['beef nilaga with corn', 'nilaga with corn guam', 'beef corn soup island'], 'everyday', NULL, 1, 'GU', 'Boiled beef shank with corn on the cob, potatoes, and pechay in a clear soup. Corn added to nilaga is common in Guam reflecting both Filipino origin and local agricultural abundance.', TRUE),
('chamorro_grilled_corn_husk_chicken_guamanian', 'Chamorro Grilled Corn Husk Chicken', 220, 25.0, 3.0, 12.0, 0.2, 1.5, 180, NULL, 'research', ARRAY['chamorro grilled corn husk chicken', 'corn husk wrapped chicken', 'chamorro husk-grilled chicken'], 'traditional', NULL, 1, 'GU', 'Chicken wrapped in soaked corn husks and grilled over charcoal, a traditional Chamorro technique that infuses the meat with a smoky, corn-sweet aroma.', TRUE),
('pork_dinuguan_with_puto_guamanian', 'Pork Dinuguan with Puto', 230, 13.0, 14.0, 14.0, 0.5, 2.0, 250, NULL, 'research', ARRAY['pork dinuguan with puto', 'dinuguan at puto guam', 'blood stew rice cake pair'], 'everyday', NULL, 1, 'GU', 'Pork blood stew paired with steamed rice cakes. This classic Filipino pairing is very popular at Guam gatherings; the starchy puto balances the savory, tangy blood stew.', TRUE),
('ceviche_style_shrimp_guam_guamanian', 'Ceviche Style Shrimp Guam', 95, 16.0, 5.0, 1.5, 0.5, 1.5, 150, NULL, 'research', ARRAY['ceviche style shrimp guam', 'shrimp kelaguen raw', 'citrus shrimp ceviche chamorro'], 'traditional', NULL, 1, 'GU', 'Raw or par-boiled shrimp ''cooked'' in citrus juice with tomato, onion, and hot pepper. Similar in concept to kelaguen, this ceviche-style preparation is a popular appetizer on Guam.', TRUE),
('garlic_fried_chicken_thigh_guamanian', 'Garlic Fried Chicken Thigh', 255, 21.0, 7.0, 16.0, 0.3, 0.5, 160, 160, 'research', ARRAY['garlic fried chicken thigh', 'garlic chicken thigh guam', 'fried garlic chicken'], 'everyday', NULL, 1, 'GU', 'Bone-in chicken thighs massaged with minced garlic and seasoning then deep-fried. A popular everyday dish in Guam that reflects the island''s love of garlic in meat preparations.', TRUE),
('shrimp_tinola_guamanian', 'Shrimp Tinola', 100, 12.0, 6.0, 2.5, 1.0, 2.0, 350, NULL, 'research', ARRAY['shrimp tinola', 'tinolang hipon guam', 'shrimp ginger papaya soup'], 'everyday', NULL, 1, 'GU', 'Shrimp in ginger-lemongrass broth with green papaya and malunggay. A Filipino-Guam seafood variation of tinola that is lighter and quicker to cook than chicken tinola.', TRUE),
('chamorro_grilled_fish_fillet_guamanian', 'Chamorro Grilled Fish Fillet', 130, 22.0, 1.5, 4.0, 0.0, 0.5, 180, NULL, 'research', ARRAY['chamorro grilled fish fillet', 'guam grilled fish fillet', 'finadene fish fillet'], 'traditional', NULL, 1, 'GU', 'Mixed white fish fillets from the local market grilled with finadene marinade. A generic but ubiquitous Chamorro preparation representing the daily fish-cooking traditions of island families.', TRUE),
('pork_tocino_guam_style_guamanian', 'Pork Tocino Guam Style', 290, 16.0, 14.0, 19.0, 0.0, 11.0, 120, NULL, 'research', ARRAY['pork tocino guam style', 'tocino breakfast guam', 'sweet cured pork filipino-island'], 'everyday', NULL, 1, 'GU', 'Sweet cured pork slices pan-fried until caramelized, served with garlic fried rice and eggs. Filipino tocino is a beloved breakfast staple in Guam''s many Filipino-run breakfast spots.', TRUE),
('bringhe_chamorro_glutinous_rice_with_meat_guamanian', 'Bringhe (Chamorro Glutinous Rice with Meat)', 230, 10.0, 30.0, 8.5, 1.0, 2.5, 200, NULL, 'research', ARRAY['bringhe (chamorro glutinous rice with meat)', 'chamorro bringhe', 'coconut sticky rice chicken'], 'traditional', NULL, 1, 'GU', 'Glutinous rice cooked in coconut milk with chicken, turmeric, and pandan, wrapped in banana leaf. Bringhe is a treasured Chamorro fiesta dish of probable Filipino Visayan origin.', TRUE),
('beef_short_rib_soup_guamanian', 'Beef Short Rib Soup', 200, 16.0, 7.0, 12.0, 1.0, 1.5, 350, NULL, 'research', ARRAY['beef short rib soup', 'short rib clear soup guam', 'beef rib kadu'], 'traditional', NULL, 1, 'GU', 'Short ribs simmered in a clear broth with daikon, corn, and onion until gelatinous and tender. A warming soup prepared for family meals and special healing occasions in Chamorro culture.', TRUE),
('chamorro_lamb_kadu_guamanian', 'Chamorro Lamb Kadu', 195, 16.0, 8.0, 11.0, 1.2, 1.5, 350, NULL, 'research', ARRAY['chamorro lamb kadu', 'lamb kadu guam', 'chamorro lamb stew'], 'traditional', NULL, 1, 'GU', 'An adaptation of kadu using imported lamb with local root vegetables. Lamb became available on Guam from Australian imports and has been incorporated into traditional stew preparations.', TRUE),
('grilled_chicken_half_with_red_rice_guamanian', 'Grilled Chicken Half with Red Rice', 295, 28.0, 22.0, 10.0, 0.8, 1.5, 300, NULL, 'research', ARRAY['grilled chicken half with red rice', 'chamorro chicken rice plate', 'fiesta bbq plate'], 'traditional', NULL, 1, 'GU', 'Half chicken grilled over charcoal and served alongside achote red rice, the classic Chamorro fiesta plate. The combination of BBQ chicken and red rice is the signature dish of Guam fiestas.', TRUE),
('pork_binagoongan_guamanian', 'Pork Binagoongan', 280, 17.0, 5.0, 21.0, 0.5, 2.0, 180, NULL, 'research', ARRAY['pork binagoongan', 'binagoongang baboy guam', 'pork shrimp paste stew'], 'everyday', NULL, 1, 'GU', 'Crispy pork belly cooked with shrimp paste (bagoong), tomatoes, and vinegar. One of Guam''s most popular Filipino-derived dishes, its pungent, salty-sour flavor is addictive.', TRUE),
('chamorro_grilled_corn_fed_beef_guamanian', 'Chamorro Grilled Corn-Fed Beef', 250, 25.0, 0.0, 16.0, 0.0, 0.0, 200, NULL, 'research', ARRAY['chamorro grilled corn-fed beef', 'chamorro beef bbq', 'guam grilled beef steak'], 'traditional', NULL, 1, 'GU', 'USDA grain-fed beef grilled in the Chamorro BBQ tradition with soy-lemon marinade and achote. American beef supply has heavily influenced Guam''s BBQ culture since World War II.', TRUE),
('sauteed_kangkong_with_shrimp_guamanian', 'Sautéed Kangkong with Shrimp', 90, 9.0, 5.0, 3.5, 2.0, 1.0, 200, NULL, 'research', ARRAY['sautéed kangkong with shrimp', 'adobong kangkong hipon', 'kangkong shrimp garlic guam'], 'everyday', NULL, 1, 'GU', 'Water spinach (kangkong) stir-fried with shrimp, garlic, and bagoong or oyster sauce. A fast, nutritious dish common in Filipino-Chamorro households on Guam.', TRUE),
('chamorro_seafood_soup_guamanian', 'Chamorro Seafood Soup', 130, 14.0, 7.0, 4.5, 1.0, 1.5, 350, NULL, 'research', ARRAY['chamorro seafood soup', 'mixed seafood kadu', 'guam seafood broth'], 'traditional', NULL, 1, 'GU', 'Mixed seafood broth with fish, shrimp, and crab cooked with local vegetables. A generously loaded soup reflecting Guam''s abundant coastal resources and communal cooking style.', TRUE),
('pork_asado_filipino_style_guamanian', 'Pork Asado Filipino Style', 245, 18.0, 8.0, 16.0, 0.3, 5.0, 200, NULL, 'research', ARRAY['pork asado filipino style', 'asadong baboy guam', 'sweet braised pork filipino-island'], 'everyday', NULL, 1, 'GU', 'Pork shoulder braised in soy sauce, calamansi, and brown sugar until caramelized. Filipino asado is a popular fiesta dish in Guam served as a rice topper or with steamed buns.', TRUE),
('chamorro_steamed_crab_guamanian', 'Chamorro Steamed Crab', 98, 18.0, 1.5, 2.0, 0.0, 0.0, 200, NULL, 'research', ARRAY['chamorro steamed crab', 'steamed crab finadene', 'chamorro crab lemongrass'], 'seafood', NULL, 1, 'GU', 'Whole blue crab or mud crab steamed over lemongrass and ginger and served with finadene dipping sauce. A traditional and beloved seafood preparation at Chamorro family meals.', TRUE),
('pork_chicharon_crackling_guamanian', 'Pork Chicharon (Crackling)', 540, 35.0, 1.0, 44.0, 0.0, 0.0, 50, 10, 'research', ARRAY['pork chicharon (crackling)', 'chicharron guam', 'pork crackling island'], 'snack', NULL, 1, 'GU', 'Deep-fried pork skin crackling with a hollow, airy crunch. Chicharon is beloved across Guam as a snack, appetizer, and topping for soups. Often made fresh in homes before fiestas.', TRUE),
('chicken_inasal_thigh_plate_guamanian', 'Chicken Inasal Thigh Plate', 235, 22.0, 5.0, 14.0, 0.2, 2.5, 200, NULL, 'research', ARRAY['chicken inasal thigh plate', 'inasal paa guam restaurant', 'chicken thigh annatto plate'], 'everyday', NULL, 1, 'GU', 'Chicken thigh grilled inasal-style with annatto marinade and served with cup of chicken oil dip over garlic rice. Inasal restaurants are plentiful in Guam thanks to the large Visayan community.', TRUE),
('garlic_shrimp_plate_guamanian', 'Garlic Shrimp Plate', 185, 18.0, 4.0, 11.0, 0.2, 0.5, 180, NULL, 'research', ARRAY['garlic shrimp plate', 'butter garlic shrimp guam', 'scampi style island shrimp'], 'everyday', NULL, 1, 'GU', 'Large shrimp sautéed in butter with excessive garlic, served with white rice. A simple, popular dish across Guam''s restaurants and home kitchens, showcasing the island''s Pacific shrimp.', TRUE),
('tinuno_chamorro_grilled_fish_guamanian', 'Tinuno (Chamorro Grilled Fish)', 125, 22.0, 1.0, 3.5, 0.0, 0.5, 180, NULL, 'research', ARRAY['tinuno (chamorro grilled fish)', 'tinuno na guihan', 'open-flame grilled fish'], 'traditional', NULL, 1, 'GU', 'Fish simply grilled (''tinuno'' meaning grilled in Chamorro) over an open flame, served with finadene or calamansi. One of the oldest and simplest Chamorro fish preparations.', TRUE),
('chamorro_beef_estufao_guamanian', 'Chamorro Beef Estufao', 255, 22.0, 4.0, 17.0, 0.3, 1.5, 200, NULL, 'research', ARRAY['chamorro beef estufao', 'estufao guaka', 'chamorro vinegar beef braise'], 'traditional', NULL, 1, 'GU', 'Beef braised in vinegar, soy sauce, garlic, and spices in the Chamorro estufao style. A Spanish-colonial preparation that uses the same vinegar-braising technique applied to beef cuts.', TRUE),
('pan_fried_tilapia_with_garlic_guamanian', 'Pan-fried Tilapia with Garlic', 145, 20.0, 3.0, 6.0, 0.2, 0.5, 180, NULL, 'research', ARRAY['pan-fried tilapia with garlic', 'garlic tilapia pan-fried', 'crispy tilapia soy-calamansi'], 'everyday', NULL, 1, 'GU', 'Whole tilapia scored and pan-fried crispy with sliced garlic in hot oil, finished with soy and calamansi. A fast, economical everyday fish dish eaten across Guam.', TRUE),
('chamorro_bbq_chicken_thigh_guamanian', 'Chamorro BBQ Chicken Thigh', 235, 24.0, 5.5, 13.0, 0.2, 3.5, 180, 180, 'research', ARRAY['chamorro bbq chicken thigh', 'bbq chicken thigh chamorro', 'achote grilled chicken thigh'], 'traditional', NULL, 1, 'GU', 'Bone-in chicken thighs marinated in the classic Chamorro BBQ sauce and grilled over hardwood charcoal. The darker thigh meat stays juicier than breast on Guam''s open BBQ grills.', TRUE),
('steamed_shrimp_dumplings_guamanian', 'Steamed Shrimp Dumplings', 130, 10.0, 14.0, 4.0, 0.5, 0.5, 150, 15, 'research', ARRAY['steamed shrimp dumplings', 'har gow guam', 'steamed shrimp dim sum'], 'everyday', NULL, 1, 'GU', 'Chinese-influenced har gow style shrimp dumplings steamed and served with soy-ginger dip, common at Guam''s dim sum restaurants and food courts influenced by the Chinese community.', TRUE),
('chamorro_fried_pork_liver_guamanian', 'Chamorro Fried Pork Liver', 175, 20.0, 5.0, 8.0, 0.5, 1.5, 150, NULL, 'research', ARRAY['chamorro fried pork liver', 'fried liver chamorro', 'pork liver adobo style'], 'traditional', NULL, 1, 'GU', 'Pork liver sliced and pan-fried with onion, vinegar, and soy sauce. Liver dishes are a thrifty Chamorro tradition using every part of the pig, especially after lechon preparations.', TRUE),
('grilled_king_mackerel_guamanian', 'Grilled King Mackerel', 155, 22.0, 0.0, 7.0, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled king mackerel', 'tanigi steak grilled', 'king mackerel guam'], 'seafood', NULL, 1, 'GU', 'King mackerel (tanigi) caught by Chamorro trolling fishers, grilled as steaks over charcoal. Its oily, rich flesh is popular grilled or smoked and served at waterfront restaurants.', TRUE),
('chamorro_pinayi_bbq_short_ribs_thin_cut_guamanian', 'Chamorro Pinayi (BBQ Short Ribs Thin Cut)', 295, 22.0, 5.5, 21.0, 0.1, 4.0, 200, NULL, 'research', ARRAY['chamorro pinayi (bbq short ribs thin cut)', 'flanken ribs chamorro', 'pinayi guam bbq'], 'traditional', NULL, 1, 'GU', 'Paper-thin cross-cut beef short ribs (flanken cut) marinated overnight in soy, lemon, sugar, onion, and achote then grilled fast over high heat. Pinayi is the quintessential Guam BBQ cut.', TRUE),
('chicken_liver_adobo_guamanian', 'Chicken Liver Adobo', 190, 18.0, 5.0, 11.0, 0.5, 1.0, 150, NULL, 'research', ARRAY['chicken liver adobo', 'adobong atay manok guam', 'chicken liver vinegar soy'], 'everyday', NULL, 1, 'GU', 'Chicken livers braised in vinegar, soy sauce, and garlic until creamy-tender. A budget-friendly Filipino-Chamorro dish highly flavorful and rich in iron, popular for everyday meals.', TRUE),
('clam_chowder_guam_style_guamanian', 'Clam Chowder Guam Style', 145, 8.0, 12.0, 7.0, 0.5, 2.0, 300, NULL, 'research', ARRAY['clam chowder guam style', 'pacific clam chowder guam', 'coconut clam chowder island'], 'fusion', NULL, 1, 'GU', 'American-style cream chowder made with local Pacific clams and coconut milk substituted for heavy cream, giving Guam''s version a tropical, sweeter undertone.', TRUE),
('grilled_snapper_whole_pampano_guamanian', 'Grilled Snapper Whole (Pampano)', 125, 22.0, 0.0, 3.5, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled snapper whole (pampano)', 'pampano grilled guam', 'pompano whole grilled'], 'seafood', NULL, 1, 'GU', 'Pampano (pompano) or red snapper grilled whole with lemon and garlic at beachside cook-outs. Its sweet, clean flavor makes it a crowd favorite for outdoor grilling events on Guam.', TRUE),
('chamorro_fish_fritters_guamanian', 'Chamorro Fish Fritters', 210, 12.0, 18.0, 10.0, 0.5, 1.0, 150, 30, 'research', ARRAY['chamorro fish fritters', 'fish fritter guam', 'chamorro fish cake fried'], 'street_food', NULL, 1, 'GU', 'Chopped reef fish mixed into a seasoned batter with scallion and hot pepper, deep-fried into crispy fritters. Sold at Guam night markets and school fairs as a popular snack.', TRUE),
('pork_braised_in_coconut_vinegar_guamanian', 'Pork Braised in Coconut Vinegar', 260, 18.0, 4.0, 19.0, 0.2, 1.5, 200, NULL, 'research', ARRAY['pork braised in coconut vinegar', 'tuba vinegar pork', 'pork coconut wine braise'], 'traditional', NULL, 1, 'GU', 'Pork belly or shoulder slow-braised in Chamorro coconut vinegar (tuba vinegar) with garlic and bay leaves. The indigenous coconut palm wine vinegar gives this dish a uniquely Chamorro tartness.', TRUE),
('grilled_spam_musubi_guamanian', 'Grilled Spam Musubi', 200, 7.5, 28.0, 7.0, 0.5, 2.0, 120, 120, 'research', ARRAY['grilled spam musubi', 'classic spam musubi guam', 'onigiri spam guam style'], 'street_food', NULL, 1, 'GU', 'Standard Spam musubi with Spam grilled until slightly charred, placed on pressed seasoned rice and wrapped in nori. One of the most popular grab-and-go foods sold in Guam convenience stores.', TRUE),
('beef_kare_kare_with_oxtail_guamanian', 'Beef Kare Kare with Oxtail', 250, 18.0, 9.0, 16.0, 2.5, 2.0, 250, NULL, 'research', ARRAY['beef kare kare with oxtail', 'kare kare mixed meat guam', 'oxtail beef peanut stew'], 'everyday', NULL, 1, 'GU', 'Traditional kare kare with mixed oxtail and beef short ribs in a thick peanut sauce with banana blossom and sitaw. Served at Guam parties and Sunday family lunches.', TRUE),
('chamorro_fish_soup_with_lemon_guamanian', 'Chamorro Fish Soup with Lemon', 100, 15.0, 5.0, 2.5, 0.5, 1.0, 350, NULL, 'research', ARRAY['chamorro fish soup with lemon', 'caldo guihan', 'chamorro fish lemon soup'], 'traditional', NULL, 1, 'GU', 'Light fish broth with reef fish, lemon, garlic, and onion. One of the simplest and most restorative soups in Chamorro cuisine, often made for the sick and for postpartum recovery.', TRUE),
('chicken_barbeque_wings_guamanian', 'Chicken Barbeque Wings', 265, 22.0, 5.0, 17.0, 0.2, 3.5, 150, 30, 'research', ARRAY['chicken barbeque wings', 'bbq wings guam', 'chamorro chicken wings party'], 'everyday', NULL, 1, 'GU', 'Chicken wings marinated in Chamorro BBQ sauce and grilled or baked, a crowd-pleasing party food at Guam gatherings. Served with finadene or ranch-style dipping sauce.', TRUE),
('pork_blood_soup_dinuguan_soup_guamanian', 'Pork Blood Soup (Dinuguan Soup)', 145, 10.0, 4.0, 10.0, 0.3, 0.5, 300, NULL, 'research', ARRAY['pork blood soup (dinuguan soup)', 'soup dinuguan guam', 'pork blood clear soup'], 'everyday', NULL, 1, 'GU', 'A thinner, soup-form version of dinuguan with pork intestines and blood in vinegar-chili broth. This variant is eaten as a full soup rather than a thick stew, popular in Guam Filipino homes.', TRUE),
('grilled_barramundi_guamanian', 'Grilled Barramundi', 120, 21.0, 0.0, 3.5, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled barramundi', 'asian sea bass guam grilled', 'barramundi lemon'], 'seafood', NULL, 1, 'GU', 'Barramundi (Asian sea bass) farmed locally or imported to Guam, grilled with lemon and herbs. Its mild, sweet flavor and low fat content make it a healthy choice at Guam seafood restaurants.', TRUE),
('pork_spare_ribs_bbq_guam_guamanian', 'Pork Spare Ribs BBQ Guam', 290, 19.0, 5.0, 22.0, 0.2, 3.5, 200, NULL, 'research', ARRAY['pork spare ribs bbq guam', 'spare ribs chamorro bbq', 'pork rib rack guam style'], 'traditional', NULL, 1, 'GU', 'Pork spare ribs marinated in Chamorro BBQ sauce and slow-grilled over charcoal until smoky and tender. A BBQ cut favored for its balance of meat and rendered fat after grilling.', TRUE),
('lamb_adobo_guamanian', 'Lamb Adobo', 255, 20.0, 3.0, 18.0, 0.2, 1.0, 200, NULL, 'research', ARRAY['lamb adobo', 'lamb chop adobo guam', 'australian lamb chamorro style'], 'fusion', NULL, 1, 'GU', 'Australian lamb chops or shoulder braised in vinegar, soy sauce, and garlic in the adobo style. A creative fusion seen in Guam''s modern restaurants using imported lamb.', TRUE),
('garlic_fried_fish_guamanian', 'Garlic Fried Fish', 175, 20.0, 5.0, 8.5, 0.2, 0.5, 180, NULL, 'research', ARRAY['garlic fried fish', 'pritong isda bawang guam', 'crispy garlic fish'], 'everyday', NULL, 1, 'GU', 'Local fish fried crispy with minced garlic and served with calamansi and soy sauce. A quick-prep everyday fish dish common in Guam homes that needs only minutes of cooking time.', TRUE),
('chamorro_turkey_tail_bbq_guamanian', 'Chamorro Turkey Tail BBQ', 330, 18.0, 4.0, 28.0, 0.0, 2.5, 150, NULL, 'research', ARRAY['chamorro turkey tail bbq', 'turkey tail bbq guam', 'grilled turkey tail chamorro'], 'traditional', NULL, 1, 'GU', 'Turkey tails marinated in soy, achote, and lemon then grilled over charcoal. Turkey tails became a cheap protein staple on Guam from American food surpluses, embraced as a BBQ delicacy.', TRUE),
('chamorro_seafood_kadu_guamanian', 'Chamorro Seafood Kadu', 145, 15.0, 9.0, 5.0, 1.5, 2.0, 350, NULL, 'research', ARRAY['chamorro seafood kadu', 'seafood kadu fiesta', 'mixed seafood chamorro stew'], 'traditional', NULL, 1, 'GU', 'A festive version of kadu combining fish, shrimp, and crab with root vegetables in a light aromatic broth. Made on special occasions when seafood is plentiful after community fishing trips.', TRUE),
('chamorro_pork_afijao_guamanian', 'Chamorro Pork Afijao', 270, 18.0, 4.5, 19.5, 0.3, 1.5, 200, NULL, 'research', ARRAY['chamorro pork afijao', 'afijao babui', 'pork achote coconut stew'], 'traditional', NULL, 1, 'GU', 'Pork version of the achote-coconut milk Chamorro afijao stew. Pork afijao is deeply colored orange-red from annatto and has a rich, slightly tangy-sweet flavor from the coconut.', TRUE),
('squid_rings_fried_calamares_guam_guamanian', 'Squid Rings Fried (Calamares Guam)', 200, 14.0, 14.0, 9.0, 0.3, 0.5, 150, NULL, 'research', ARRAY['squid rings fried (calamares guam)', 'calamares guam', 'fried squid rings island'], 'everyday', NULL, 1, 'GU', 'Squid rings coated in seasoned flour and deep-fried, served with vinegar-garlic dip or aioli. Calamares is extremely popular at Guam beach bars and seafood restaurants.', TRUE),
('chicken_sotanghon_soup_guamanian', 'Chicken Sotanghon Soup', 120, 10.0, 12.0, 3.0, 0.5, 1.0, 350, NULL, 'research', ARRAY['chicken sotanghon soup', 'sotanghon soup filipino-guam', 'glass noodle chicken soup'], 'everyday', NULL, 1, 'GU', 'Clear chicken soup with glass noodles (sotanghon), shredded chicken, and vegetables. A Filipino comfort soup universally made in Guam for sick family members and cold rainy nights.', TRUE),
('grilled_chicken_breast_finadene_guamanian', 'Grilled Chicken Breast Finadene', 185, 30.0, 3.0, 6.0, 0.2, 1.0, 180, NULL, 'research', ARRAY['grilled chicken breast finadene', 'finadene chicken breast', 'lean chamorro bbq chicken'], 'traditional', NULL, 1, 'GU', 'Boneless chicken breast marinated in finadene and grilled, the leaner option at Guam BBQ stands. Popular among health-conscious locals who still want authentic Chamorro BBQ flavor.', TRUE),
('chamorro_pork_nilaga_guamanian', 'Chamorro Pork Nilaga', 155, 14.0, 8.0, 7.0, 1.5, 1.5, 350, NULL, 'research', ARRAY['chamorro pork nilaga', 'nilagang baboy guam', 'boiled pork soup island'], 'everyday', NULL, 1, 'GU', 'Pork version of boiled nilaga with bone-in pork, potatoes, corn, and pechay. Popular alternative to beef nilaga and cooked regularly in both Filipino and Chamorro households on Guam.', TRUE),
('chamorro_bbq_pork_shoulder_guamanian', 'Chamorro BBQ Pork Shoulder', 275, 22.0, 4.5, 19.0, 0.2, 3.0, 200, NULL, 'research', ARRAY['chamorro bbq pork shoulder', 'pork shoulder bbq chamorro', 'pulled pork guam style'], 'traditional', NULL, 1, 'GU', 'Whole pork shoulder marinated in Chamorro BBQ sauce and slow-grilled over charcoal until smoky and falling apart. Often served pulled or sliced at large fiesta BBQ tables.', TRUE),
('marinated_squid_guam_style_guamanian', 'Marinated Squid Guam Style', 115, 16.0, 4.0, 4.0, 0.0, 0.5, 150, NULL, 'research', ARRAY['marinated squid guam style', 'grilled whole squid guam', 'lemon soy squid chamorro'], 'seafood', NULL, 1, 'GU', 'Cleaned whole squid marinated in lemon, soy sauce, and garlic then grilled quickly over high heat. A light, protein-rich seafood dish common at Guam''s beachside grills.', TRUE),
('beef_mechado_with_potatoes_guamanian', 'Beef Mechado with Potatoes', 220, 17.0, 12.0, 12.0, 1.5, 3.0, 250, NULL, 'research', ARRAY['beef mechado with potatoes', 'mechado patatas guam', 'larded tomato beef stew'], 'everyday', NULL, 1, 'GU', 'Spanish-Filipino beef stew with larded beef, potatoes, tomatoes, and soy sauce, common at Guam fiestas and family lunches. The larding (fat strips inserted in meat) adds richness.', TRUE),
('chamorro_pork_ribs_estufao_guamanian', 'Chamorro Pork Ribs Estufao', 280, 19.0, 4.0, 21.0, 0.2, 1.5, 200, NULL, 'research', ARRAY['chamorro pork ribs estufao', 'estufao pork ribs', 'vinegar braised pork ribs chamorro'], 'traditional', NULL, 1, 'GU', 'Pork ribs braised estufao style in vinegar, soy sauce, garlic, onion, and whole peppercorns until deeply tender. A traditional Chamorro preparation for special Sunday family dinners.', TRUE),
('grilled_tilapia_whole_guamanian', 'Grilled Tilapia Whole', 132, 20.0, 1.0, 5.0, 0.0, 0.5, 200, NULL, 'research', ARRAY['grilled tilapia whole', 'whole grilled tilapia guam', 'inihaw na tilapia island'], 'everyday', NULL, 1, 'GU', 'Whole tilapia scored and grilled over charcoal or on a flat grill pan until crispy-skinned. One of the most economical and widely eaten fish preparations across everyday Guam households.', TRUE),
('chamorro_coconut_crab_stew_guamanian', 'Chamorro Coconut Crab Stew', 175, 16.0, 6.0, 10.0, 0.5, 2.5, 200, NULL, 'research', ARRAY['chamorro coconut crab stew', 'ayuyu coconut stew', 'land crab chamorro'], 'traditional', NULL, 1, 'GU', 'Land crab (ayuyu) simmered in coconut milk with garlic and local aromatics. The coconut crab (ayuyu) is one of the most culturally significant animals in Chamorro tradition, though now protected.', TRUE),
('grilled_carabao_beef_guamanian', 'Grilled Carabao Beef', 185, 26.0, 0.0, 9.0, 0.0, 0.0, 200, NULL, 'research', ARRAY['grilled carabao beef', 'carabao steak guam', 'water buffalo grilled chamorro'], 'traditional', NULL, 1, 'GU', 'Water buffalo (carabao) meat grilled over charcoal, a legacy of Spanish colonial-era farming on Guam. Leaner and more mineral-rich than conventional beef, it is prized as a traditional protein.', TRUE),
('pork_and_shrimp_lumpia_shanghai_guamanian', 'Pork and Shrimp Lumpia Shanghai', 195, 10.0, 14.0, 11.0, 0.5, 1.0, 150, 25, 'research', ARRAY['pork and shrimp lumpia shanghai', 'lumpia shanghai guam', 'crispy spring roll filipino-island'], 'everyday', NULL, 1, 'GU', 'Crispy fried spring rolls filled with ground pork and shrimp, served with sweet chili dipping sauce. Filipino lumpia Shanghai is one of the most popular finger foods at Guam parties.', TRUE),
('chicken_afritada_with_peas_guamanian', 'Chicken Afritada with Peas', 190, 18.0, 10.0, 8.5, 2.0, 4.5, 250, NULL, 'research', ARRAY['chicken afritada with peas', 'afritada with sausage peas guam', 'chicken tomato pea stew'], 'everyday', NULL, 1, 'GU', 'Chicken afritada enriched with green peas and sausage in tomato sauce. The pea-and-sausage variation is particularly popular at Guam fiestas for its vibrant color and hearty texture.', TRUE),
('beef_lengua_ox_tongue_guamanian', 'Beef Lengua (Ox Tongue)', 235, 19.0, 4.0, 16.0, 0.3, 1.5, 150, NULL, 'research', ARRAY['beef lengua (ox tongue)', 'lengua estofado guam', 'ox tongue mushroom sauce'], 'everyday', NULL, 1, 'GU', 'Braised ox tongue in mushroom-cream sauce, a Filipino-Spanish dish served at upscale Guam restaurants. The tongue is simmered for hours until tender then sliced and served in rich sauce.', TRUE),
('chamorro_red_fish_preparation_guamanian', 'Chamorro Red Fish Preparation', 138, 22.0, 2.0, 4.5, 0.2, 0.5, 180, NULL, 'research', ARRAY['chamorro red fish preparation', 'red goatfish guam', 'bigeye snapper chamorro'], 'traditional', NULL, 1, 'GU', 'Generic term for red-fleshed reef fish (goatfish, bigeye, squirrelfish) prepared Chamorro-style with soy, lemon, and garlic. ''Red fish'' is a common reference in local Guam markets.', TRUE),
('grilled_goatfish_saramulyete_guamanian', 'Grilled Goatfish (Saramulyete)', 112, 21.0, 0.0, 2.8, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled goatfish (saramulyete)', 'saramulyete grilled', 'goatfish chamorro'], 'seafood', NULL, 1, 'GU', 'Saramulyete (goatfish) is a shallow-reef species caught by Chamorro spearfishers, grilled whole with lemon. Its delicate flavor and ease of catch made it a classic everyday fish on Guam.', TRUE),
('pork_intestine_adobo_isaw_guamanian', 'Pork Intestine Adobo (Isaw)', 175, 12.0, 4.0, 12.5, 0.2, 0.5, 150, NULL, 'research', ARRAY['pork intestine adobo (isaw)', 'isaw adobo guam', 'pork intestine vinegar braise'], 'everyday', NULL, 1, 'GU', 'Cleaned pork intestines braised in vinegar, soy sauce, and garlic until tender. Offal dishes like intestine adobo reflect the Chamorro and Filipino tradition of whole-animal cooking.', TRUE),
('chamorro_turkey_wing_bbq_guamanian', 'Chamorro Turkey Wing BBQ', 280, 24.0, 4.5, 18.0, 0.0, 2.5, 180, 180, 'research', ARRAY['chamorro turkey wing bbq', 'turkey wing chamorro bbq', 'grilled turkey wing island'], 'traditional', NULL, 1, 'GU', 'Turkey wings marinated in Chamorro BBQ sauce and grilled. Turkey parts became a Guam BBQ staple alongside turkey tails; the wings are meaty and hold up well on the grill.', TRUE),
('steamed_pork_siomai_guamanian', 'Steamed Pork Siomai', 135, 10.0, 11.0, 5.5, 0.4, 0.8, 150, 15, 'research', ARRAY['steamed pork siomai', 'pork siomai guam', 'steamed pork dumpling island'], 'everyday', NULL, 1, 'GU', 'Open-faced steamed dumplings with ground pork, water chestnuts, and scallion in wonton skin. Sold at food courts and carinderia-style eateries all over Guam as a cheap, satisfying snack.', TRUE),
('chicken_caldereta_with_olives_guamanian', 'Chicken Caldereta with Olives', 200, 18.0, 9.0, 11.0, 1.5, 3.5, 250, NULL, 'research', ARRAY['chicken caldereta with olives', 'calderetang manok olives guam', 'spanish chicken olive stew'], 'everyday', NULL, 1, 'GU', 'Chicken in tomato-liver sauce with potatoes, bell pepper, and green olives. The olive addition gives this Guam fiesta-style caldereta a Spanish colonial character.', TRUE),
('grilled_moonfish_opah_guamanian', 'Grilled Moonfish (Opah)', 158, 22.0, 0.0, 7.5, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled moonfish (opah)', 'opah fillet guam', 'moonfish pacific grilled'], 'seafood', NULL, 1, 'GU', 'Opah (moonfish) is a deep-sea species occasionally caught off Guam''s offshore banks. Its rich, salmon-like flavor makes it a sought-after catch at local fish markets.', TRUE),
('chamorro_pork_intestine_soup_guamanian', 'Chamorro Pork Intestine Soup', 145, 11.0, 5.0, 9.0, 0.3, 0.5, 300, NULL, 'research', ARRAY['chamorro pork intestine soup', 'organ soup chamorro', 'pork innards soup guam'], 'traditional', NULL, 1, 'GU', 'Cleaned pork intestines and organ meats simmered in clear broth with ginger and garlic. This offal soup has roots in the Chamorro tradition of utilizing every part of the slaughtered pig.', TRUE),
('stuffed_chicken_wings_rellenong_pakpak_guamanian', 'Stuffed Chicken Wings (Rellenong Pakpak)', 245, 18.0, 8.0, 16.0, 0.5, 1.5, 120, 120, 'research', ARRAY['stuffed chicken wings (rellenong pakpak)', 'rellenong pakpak guam', 'stuffed deboned chicken wing'], 'everyday', NULL, 1, 'GU', 'Chicken wings deboned and stuffed with seasoned ground pork mixture, then deep-fried or baked. A Filipino-origin party dish made by skilled home cooks at Guam celebrations.', TRUE),
('grilled_manta_ray_fanihi_dagga_guamanian', 'Grilled Manta Ray (Fanihi Dagga)', 105, 20.0, 0.0, 2.5, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled manta ray (fanihi dagga)', 'grilled stingray guam', 'ray wing chamorro style'], 'traditional', NULL, 1, 'GU', 'Historically Chamorro fishers harvested stingray wings and grilled them with lemon and garlic. Though no longer common, this dish represents the breadth of traditional Chamorro seafood knowledge.', TRUE),
('pork_and_cabbage_soup_guamanian', 'Pork and Cabbage Soup', 120, 11.0, 6.0, 5.5, 1.5, 2.5, 350, NULL, 'research', ARRAY['pork and cabbage soup', 'pork cabbage soup guam', 'repolyo pork soup island'], 'everyday', NULL, 1, 'GU', 'Simple pork and cabbage soup with garlic, onion, and fish sauce. A humble, everyday soup cooked in Filipino-Chamorro households on Guam that stretches a small amount of meat into a full meal.', TRUE),
('beef_nilaga_with_banana_heart_guamanian', 'Beef Nilaga with Banana Heart', 165, 14.0, 10.0, 6.5, 2.5, 2.0, 350, NULL, 'research', ARRAY['beef nilaga with banana heart', 'nilaga with banana blossom guam', 'beef banana heart soup'], 'everyday', NULL, 1, 'GU', 'Beef nilaga soup enriched with banana blossom (puso ng saging), which adds a meaty, slightly bitter note. The banana heart variation is particularly popular in Guam''s Filipino community.', TRUE),
('chamorro_steamed_rice_with_chicken_fat_guamanian', 'Chamorro Steamed Rice with Chicken Fat', 225, 6.0, 40.0, 5.0, 0.5, 0.5, 200, NULL, 'research', ARRAY['chamorro steamed rice with chicken fat', 'chicken fat rice guam', 'chamorro fiesta rice'], 'traditional', NULL, 1, 'GU', 'White rice cooked with rendered chicken fat and garlic, a traditional Chamorro side pairing for fiesta BBQ chicken. The fat-cooked rice absorbs a rich, savory chicken essence.', TRUE),
('grilled_threadfin_mafute_guamanian', 'Grilled Threadfin (Mafute)', 118, 20.5, 0.0, 3.5, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled threadfin (mafute)', 'mafute grilled guam', 'threadfin reef fish chamorro'], 'seafood', NULL, 1, 'GU', 'Threadfin (mafute) is a coastal fish caught near Guam''s river mouths and mangroves, grilled whole. Its multiple filament-like pectoral fin rays make it unmistakable at local fish markets.', TRUE),
('pork_paksiw_guam_style_guamanian', 'Pork Paksiw Guam Style', 240, 17.0, 5.0, 17.0, 0.2, 2.0, 200, NULL, 'research', ARRAY['pork paksiw guam style', 'paksiw na baboy guam', 'vinegar pork paksiw island'], 'everyday', NULL, 1, 'GU', 'Pork braised in vinegar, garlic, peppercorns, and bay leaf with water until reduced and concentrated. Filipino paksiw na baboy is a common weekday dish in Guam, similar to but distinct from adobo.', TRUE),
('fish_paksiw_guamanian', 'Fish Paksiw', 115, 18.0, 3.0, 3.5, 0.2, 0.5, 200, NULL, 'research', ARRAY['fish paksiw', 'paksiw na isda guam', 'vinegar fish stew island'], 'everyday', NULL, 1, 'GU', 'Fish steamed/simmered in vinegar, garlic, ginger, and bitter melon. Paksiw na isda is a Filipino quick-cook fish method widely used in Guam homes for leftover or fresh fish.', TRUE),
('chamorro_grilled_chicken_leg_guamanian', 'Chamorro Grilled Chicken Leg', 240, 25.0, 5.0, 13.5, 0.2, 3.0, 200, 200, 'research', ARRAY['chamorro grilled chicken leg', 'bbq chicken leg chamorro', 'grilled chicken quarter guam'], 'traditional', NULL, 1, 'GU', 'Whole chicken leg (thigh and drumstick) marinated in Chamorro BBQ sauce and grilled. The leg quarter is the most popular cut at Guam village fiestas due to its size and generous meat yield.', TRUE),
('pork_hamonado_guam_style_guamanian', 'Pork Hamonado Guam Style', 265, 16.0, 12.0, 17.0, 0.2, 9.0, 150, NULL, 'research', ARRAY['pork hamonado guam style', 'hamonado baboy guam', 'sweet pineapple pork braise'], 'everyday', NULL, 1, 'GU', 'Pork cured and braised in pineapple juice and soy sauce until glossy and sweet. Filipino hamonado is a Christmas and fiesta dish in Guam, where the sweet-savory pork is served sliced.', TRUE),
('chicken_hamonado_guamanian', 'Chicken Hamonado', 225, 20.0, 10.0, 11.5, 0.2, 8.0, 180, NULL, 'research', ARRAY['chicken hamonado', 'hamonado manok guam', 'pineapple chicken filipino-island'], 'everyday', NULL, 1, 'GU', 'Chicken braised in pineapple juice, soy sauce, and sugar until caramelized and glossy. A crowd-pleaser at Guam parties, the sweet pineapple flavor makes it popular with children.', TRUE),
('grilled_pacific_mackerel_guamanian', 'Grilled Pacific Mackerel', 160, 20.0, 0.0, 9.0, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled pacific mackerel', 'chub mackerel guam grilled', 'pacific mackerel inihaw'], 'seafood', NULL, 1, 'GU', 'Pacific chub mackerel caught in Guam''s nearshore waters, grilled with salt and lemon. An affordable, oily fish with omega-3 richness eaten regularly by fishing families on the island.', TRUE),
('beef_pochero_with_chorizo_guamanian', 'Beef Pochero with Chorizo', 220, 15.0, 11.0, 13.0, 2.0, 3.0, 300, NULL, 'research', ARRAY['beef pochero with chorizo', 'pochero chorizo guam', 'beef sausage spanish stew'], 'everyday', NULL, 1, 'GU', 'Beef pochero with sliced chorizo de bilbao for extra smoky depth. The sausage addition elevates this Spanish-origin stew and makes it one of the most festive-tasting versions in Guam.', TRUE),
('chamorro_lamb_kare_kare_guamanian', 'Chamorro Lamb Kare Kare', 275, 18.0, 9.0, 18.0, 2.0, 2.5, 250, NULL, 'research', ARRAY['chamorro lamb kare kare', 'lamb kare kare guam fusion', 'peanut lamb stew island'], 'fusion', NULL, 1, 'GU', 'A fusion kare kare using imported Australian lamb shoulder in peanut sauce with banana blossom. Reflects Guam''s creative blending of Filipino cooking traditions with imported ingredients.', TRUE),
('fried_pork_chops_chamorro_guamanian', 'Fried Pork Chops Chamorro', 265, 24.0, 5.0, 17.0, 0.2, 0.5, 180, NULL, 'research', ARRAY['fried pork chops chamorro', 'fried pork chop guam lunch', 'breaded pork chop chamorro'], 'traditional', NULL, 1, 'GU', 'Pork chops marinated in soy, garlic, and calamansi then breaded lightly and pan-fried. A popular Guam plate lunch item served with red rice and pickled vegetables.', TRUE),
('chamorro_shrimp_patties_guamanian', 'Chamorro Shrimp Patties', 165, 12.0, 12.0, 7.5, 0.5, 1.0, 120, 60, 'research', ARRAY['chamorro shrimp patties', 'shrimp cake guam', 'chamorro shrimp burger patty'], 'traditional', NULL, 1, 'GU', 'Ground shrimp mixed with garlic, scallion, egg, and breadcrumbs, formed into patties and pan-fried. A simple Chamorro-style seafood cake sold at local bakeries and canteens on Guam.', TRUE),
('chicken_pochero_with_plantain_guamanian', 'Chicken Pochero with Plantain', 185, 15.0, 14.0, 7.5, 2.0, 5.0, 300, NULL, 'research', ARRAY['chicken pochero with plantain', 'pochero with banana guam', 'chicken plantain stew island'], 'everyday', NULL, 1, 'GU', 'Chicken pochero featuring ripe plantain (saging na saba) for natural sweetness alongside potatoes and cabbage. The plantain version is considered the most traditional by Guam''s Filipino-Chamorro families.', TRUE),
('chamorro_beef_rib_kadu_guamanian', 'Chamorro Beef Rib Kadu', 210, 16.0, 9.0, 12.0, 1.5, 2.0, 350, NULL, 'research', ARRAY['chamorro beef rib kadu', 'short rib kadu chamorro', 'beef bone kadu guam'], 'traditional', NULL, 1, 'GU', 'Bone-in beef short ribs simmered low-and-slow in a clear broth with yam, corn, and local greens. A hearty, gelatinous kadu variant showcasing the Chamorro preference for braised bone-in cuts.', TRUE),
('grilled_surgeonfish_palata_guamanian', 'Grilled Surgeonfish (Palata)', 108, 20.5, 0.0, 2.5, 0.0, 0.0, 180, NULL, 'research', ARRAY['grilled surgeonfish (palata)', 'palata grilled guam', 'surgeonfish reef chamorro'], 'seafood', NULL, 1, 'GU', 'Surgeonfish (palata) are reef-grazing fish abundant around Guam''s coral reefs, grilled whole by Chamorro families. Their firm white flesh and clean flavor make them a reliable everyday catch.', TRUE),
('pork_adobo_sa_gata_coconut_pork_adobo_guamanian', 'Pork Adobo sa Gata (Coconut Pork Adobo)', 295, 19.0, 4.0, 22.0, 0.3, 2.0, 200, NULL, 'research', ARRAY['pork adobo sa gata (coconut pork adobo)', 'adobo sa gata guam', 'coconut cream pork adobo'], 'traditional', NULL, 1, 'GU', 'Pork adobo finished with rich coconut milk for a creamy, mellow sauce. The sa gata (with coconut) version of adobo is popular in Guam and Bicol-influenced Filipino communities on the island.', TRUE),
('chamorro_chicken_arroz_caldo_guamanian', 'Chamorro Chicken Arroz Caldo', 145, 10.0, 18.0, 3.5, 0.5, 1.0, 350, NULL, 'research', ARRAY['chamorro chicken arroz caldo', 'arroz caldo guam', 'chicken rice porridge island'], 'everyday', NULL, 1, 'GU', 'Ginger-spiced rice porridge with shredded chicken, fried garlic, and hard-boiled egg. Filipino arroz caldo is the go-to comfort food for the sick and elderly across Filipino-Chamorro households in Guam.', TRUE),
('ensaladang_papaya_green_papaya_salad_guamanian', 'Ensaladang Papaya (Green Papaya Salad)', 38, 0.6, 8.5, 0.2, 1.8, 5.2, 150, NULL, 'research', ARRAY['ensaladang papaya (green papaya salad)', 'green papaya salad', 'ensalada papaya'], 'traditional', NULL, 1, 'GU', 'Shredded unripe green papaya tossed with vinegar, soy sauce, onion, and donne (bird''s eye chili), a staple side dish at CHamoru fiestas. The tart, crunchy salad reflects Filipino and Spanish culinary influences absorbed into CHamoru food culture.', TRUE),
('ensaladang_pipino_cucumber_salad_guamanian', 'Ensaladang Pipino (Cucumber Salad)', 28, 0.8, 5.2, 0.5, 0.6, 3.0, 150, NULL, 'research', ARRAY['ensaladang pipino (cucumber salad)', 'pipino salad', 'cucumber finadene salad'], 'traditional', NULL, 1, 'GU', 'Sliced cucumber dressed with soy sauce, vinegar, sesame oil, and black pepper, a refreshing CHamoru table salad. Soy sauce dressing reflects Japanese influence on Guam during the early 20th century.', TRUE),
('chamorro_potato_salad_guamanian', 'Chamorro Potato Salad', 145, 2.8, 18.5, 6.8, 1.5, 2.2, 200, NULL, 'research', ARRAY['chamorro potato salad', 'potato salad guam style', 'ensalada patatas'], 'traditional', NULL, 1, 'GU', 'Boiled diced potatoes mixed with mayonnaise, chopped Spam, hard-boiled eggs, sweet relish, celery, and onion, a beloved fiesta staple. The addition of Spam distinguishes the CHamoru version from American potato salad and reflects the canned meat''s deep integration into island cuisine.', TRUE),
('chamorro_macaroni_salad_guamanian', 'Chamorro Macaroni Salad', 168, 3.5, 22.0, 7.5, 0.9, 3.5, 200, NULL, 'research', ARRAY['chamorro macaroni salad', 'mac salad guam', 'ensalada macaroni'], 'traditional', NULL, 1, 'GU', 'Elbow macaroni tossed with mayonnaise, carrots, celery, onion, and sweet pickles, served cold at nearly every CHamoru fiesta and family gathering. American-influenced but deeply localized, it often includes canned tuna or Spam.', TRUE),
('taro_leaf_coconut_soup_lulun_suni_guamanian', 'Taro Leaf Coconut Soup (Lulun Suni)', 72, 3.5, 6.8, 3.8, 2.2, 1.5, 250, NULL, 'research', ARRAY['taro leaf coconut soup (lulun suni)', 'suni en lechen niyok', 'taro leaf in coconut milk'], 'traditional', NULL, 1, 'GU', 'Young taro leaves (suni) simmered in fresh coconut milk with salt and onion until silky tender, one of the oldest CHamoru vegetable preparations. Taro was a sacred crop in ancient CHamoru society and continues to represent cultural continuity.', TRUE),
('boiled_taro_root_suni_asulon_guamanian', 'Boiled Taro Root (Suni Asulon)', 112, 1.5, 26.5, 0.2, 4.1, 0.5, 200, NULL, 'research', ARRAY['boiled taro root (suni asulon)', 'suni', 'boiled taro', 'dago boiled'], 'traditional', NULL, 1, 'GU', 'Whole or chunked taro corm boiled in salted water until tender, served as a starchy side alongside grilled meats and fish. Ancient CHamoru communities cultivated taro in paddies and regarded it as a foundational food crop.', TRUE),
('fried_taro_chips_guamanian', 'Fried Taro Chips', 382, 2.8, 52.0, 18.0, 4.5, 1.0, 50, NULL, 'research', ARRAY['fried taro chips', 'taro crisps', 'suni chips'], 'traditional', NULL, 1, 'GU', 'Thinly sliced taro deep-fried until crisp, sold as a snack at roadside stands and local markets across Guam. A popular modern adaptation of the ancient taro staple, sometimes seasoned with garlic salt or chili powder.', TRUE),
('breadfruit_boiled_lemmai_guamanian', 'Breadfruit Boiled (Lemmai)', 103, 1.1, 27.1, 0.2, 4.9, 11.0, 200, NULL, 'research', ARRAY['breadfruit boiled (lemmai)', 'lemmai boiled', 'boiled breadfruit', 'dokdok boiled'], 'traditional', NULL, 1, 'GU', 'Seedless breadfruit (lemmai) boiled whole or in wedges until starchy and tender, served as a side dish or snack. Breadfruit trees (dokdok for seeded, lemmai for seedless) were fundamental to the ancient CHamoru diet and canoe-building culture.', TRUE),
('roasted_breadfruit_guamanian', 'Roasted Breadfruit', 120, 1.3, 30.5, 0.3, 4.5, 13.0, 200, NULL, 'research', ARRAY['roasted breadfruit', 'grilled breadfruit', 'lemmai grilled'], 'traditional', NULL, 1, 'GU', 'Whole breadfruit roasted directly over coals or open fire until charred outside and creamy inside, a traditional CHamoru preparation that concentrates natural sweetness. Roasting was the primary ancient cooking technique before Spanish contact introduced iron pots.', TRUE),
('fried_breadfruit_guamanian', 'Fried Breadfruit', 165, 1.4, 31.0, 4.8, 4.2, 11.5, 150, NULL, 'research', ARRAY['fried breadfruit', 'pan-fried breadfruit', 'lemmai fritada'], 'traditional', NULL, 1, 'GU', 'Sliced or chunked breadfruit pan-fried in oil until golden and slightly caramelized on the edges, often eaten as a breakfast side or snack. A practical way to use slightly overripe breadfruit that develops additional sweetness during frying.', TRUE),
('banana_blossom_salad_ensaladang_puso_ng_saging_guamanian', 'Banana Blossom Salad (Ensaladang Puso ng Saging)', 52, 1.8, 9.5, 0.8, 2.5, 3.2, 150, NULL, 'research', ARRAY['banana blossom salad (ensaladang puso ng saging)', 'banana flower salad', 'puso ng saging ensalada'], 'traditional', NULL, 1, 'GU', 'Thinly sliced raw banana blossom tossed with vinegar, onion, chili, and fish sauce dressing, served chilled as a side. The banana flower (puso ng saging in Filipino, adopted into Guam''s culinary vocabulary) was introduced by Filipino immigrants and became a CHamoru vegetable staple.', TRUE),
('spinach_with_coconut_milk_kangkong_en_lechen_niyok_guamanian', 'Spinach with Coconut Milk (Kangkong en Lechen Niyok)', 65, 3.2, 5.5, 3.5, 2.1, 1.2, 200, NULL, 'research', ARRAY['spinach with coconut milk (kangkong en lechen niyok)', 'water spinach coconut', 'sauteed spinach coconut milk'], 'traditional', NULL, 1, 'GU', 'Water spinach (kangkong) or regular spinach wilted in fresh coconut milk with garlic and onion, a simple vegetable side dish common in CHamoru home cooking. The use of coconut milk to braise greens reflects both indigenous Pacific and Filipino culinary traditions.', TRUE),
('ampalaya_bitter_melon_saute_guamanian', 'Ampalaya (Bitter Melon) Sauté', 42, 2.1, 6.5, 1.5, 2.8, 2.0, 150, NULL, 'research', ARRAY['ampalaya (bitter melon) sauté', 'ginisang ampalaya', 'bitter gourd saute', 'amargoso'], 'traditional', NULL, 1, 'GU', 'Sliced bitter melon stir-fried with garlic, onion, egg, and sometimes shrimp or ground pork, a Filipino-influenced vegetable dish deeply embedded in Guam''s cuisine. Bitter melon is valued in CHamoru households for its perceived medicinal qualities and distinctive sharp flavor.', TRUE),
('eggplant_adobo_talong_adobo_guamanian', 'Eggplant Adobo (Talong Adobo)', 68, 1.8, 9.2, 3.0, 3.5, 4.5, 200, NULL, 'research', ARRAY['eggplant adobo (talong adobo)', 'ginisang talong', 'eggplant braised'], 'traditional', NULL, 1, 'GU', 'Sliced eggplant braised in vinegar, soy sauce, garlic, and bay leaf until tender and infused with tangy adobo flavor, a vegetarian preparation popular in CHamoru households. Spanish-introduced eggplant combined with adobo technique produces a versatile meatless dish.', TRUE),
('grilled_eggplant_with_finadene_guamanian', 'Grilled Eggplant with Finadene', 45, 1.5, 8.5, 0.8, 3.8, 4.2, 200, NULL, 'research', ARRAY['grilled eggplant with finadene', 'talong inihaw', 'smoky eggplant chamoru'], 'traditional', NULL, 1, 'GU', 'Whole eggplant char-grilled over open flame until smoky and collapsed, peeled and served drizzled with finadene sauce of soy sauce, lemon, and donne pepper. The smoky eggplant dipped in finadene is a beloved simple vegetable preparation at CHamoru backyard cookouts.', TRUE),
('long_beans_with_garlic_sitaw_guisado_guamanian', 'Long Beans with Garlic (Sitaw Guisado)', 48, 2.8, 7.5, 1.2, 3.2, 2.8, 150, NULL, 'research', ARRAY['long beans with garlic (sitaw guisado)', 'yard long bean saute', 'string beans chamoru', 'sitaw'], 'traditional', NULL, 1, 'GU', 'Yard-long beans (sitaw) cut and sautéed with garlic, onion, and a splash of soy sauce or fish sauce, a simple everyday vegetable side dish. Long beans are widely grown in Guam''s backyard gardens and are a common ingredient in CHamoru home cooking.', TRUE),
('okra_in_coconut_milk_guamanian', 'Okra in Coconut Milk', 58, 2.0, 7.8, 2.5, 3.2, 2.5, 200, NULL, 'research', ARRAY['okra in coconut milk', 'okra guisado', 'lady finger coconut'], 'traditional', NULL, 1, 'GU', 'Fresh okra pods simmered in coconut milk with garlic and onion until tender, the natural mucilage thickening the sauce into a silky coating. Okra grows abundantly in Guam''s tropical climate and is frequently combined with coconut milk in both CHamoru and Filipino-influenced preparations.', TRUE),
('pumpkin_in_coconut_milk_kalabasa_en_lechen_niyok_guamanian', 'Pumpkin in Coconut Milk (Kalabasa en Lechen Niyok)', 72, 1.8, 11.5, 3.0, 2.2, 5.5, 200, NULL, 'research', ARRAY['pumpkin in coconut milk (kalabasa en lechen niyok)', 'ginataang kalabasa', 'squash coconut chamoru'], 'traditional', NULL, 1, 'GU', 'Cubed kabocha or calabaza pumpkin simmered in coconut milk with shrimp paste or patis until tender and creamy, a comfort dish served over rice. The sweet pumpkin and rich coconut milk combination is one of the most popular vegetable preparations in CHamoru households.', TRUE),
('sweet_potato_boiled_kamuti_guamanian', 'Sweet Potato Boiled (Kamuti)', 86, 1.6, 20.1, 0.1, 3.0, 4.2, 200, NULL, 'research', ARRAY['sweet potato boiled (kamuti)', 'kamuti boiled', 'boiled camote', 'sweet potato guam'], 'traditional', NULL, 1, 'GU', 'Orange-fleshed sweet potato boiled whole in salted water, peeled and eaten as a simple starchy side or snack. Sweet potatoes (kamuti) have been grown in Guam since pre-contact times and remain a staple root vegetable in traditional CHamoru households.', TRUE),
('candied_sweet_potato_guamanian', 'Candied Sweet Potato', 148, 1.2, 34.5, 1.5, 2.8, 18.5, 150, NULL, 'research', ARRAY['candied sweet potato', 'sweet potato glazed', 'kamuti dulce'], 'traditional', NULL, 1, 'GU', 'Sweet potato chunks cooked in sugar, butter, and a touch of cinnamon until glazed and caramelized, served as a side dish or light dessert. A popular preparation at CHamoru family gatherings that bridges the line between savory side and sweet accompaniment.', TRUE),
('cassava_boiled_manihok_guamanian', 'Cassava Boiled (Mañihok)', 160, 1.4, 38.1, 0.3, 1.8, 1.7, 200, NULL, 'research', ARRAY['cassava boiled (mañihok)', 'manioc boiled', 'yuca boiled chamoru'], 'traditional', NULL, 1, 'GU', 'Peeled cassava (mañihok) boiled in salted water until fork-tender, served as a starchy side dish often accompanied by finadene sauce. Cassava was introduced to Guam via the Manila Galleon trade and became a significant carbohydrate staple alongside taro and breadfruit.', TRUE),
('fried_cassava_patties_guamanian', 'Fried Cassava Patties', 195, 2.0, 38.5, 5.5, 2.0, 2.5, 100, 60, 'research', ARRAY['fried cassava patties', 'cassava fritters', 'mañihok fritada'], 'traditional', NULL, 1, 'GU', 'Grated cassava formed into flat rounds and pan-fried in oil until crispy on the outside and chewy within, eaten as a snack or breakfast starch. The simple preparation showcases cassava''s naturally starchy and slightly sweet character.', TRUE),
('moringa_leaf_soup_malunggay_tinola_guamanian', 'Moringa Leaf Soup (Malunggay Tinola)', 45, 3.5, 5.2, 1.0, 2.0, 1.5, 250, NULL, 'research', ARRAY['moringa leaf soup (malunggay tinola)', 'malunggay soup', 'moringa chamoru', 'malunggay tinola'], 'traditional', NULL, 1, 'GU', 'Moringa (malunggay) leaves added to a light ginger-garlic chicken or vegetable broth, creating a nutritious green soup common in CHamoru households. Moringa trees grow prolifically across Guam and their leaves are considered a superfood rich in iron and vitamins.', TRUE),
('sauteed_moringa_leaves_ginisang_malunggay_guamanian', 'Sautéed Moringa Leaves (Ginisang Malunggay)', 38, 3.8, 4.5, 1.2, 2.5, 1.0, 100, NULL, 'research', ARRAY['sautéed moringa leaves (ginisang malunggay)', 'malunggay guisado', 'moringa leaves stir-fry'], 'traditional', NULL, 1, 'GU', 'Fresh moringa leaves sautéed with garlic, onion, and a splash of fish sauce, served as a nutritious vegetable side dish. The leaves are stripped from their stems and wilted quickly over high heat to preserve their bright green color and nutrient content.', TRUE),
('coleslaw_chamoru_style_guamanian', 'Coleslaw CHamoru Style', 85, 1.2, 10.5, 4.5, 1.8, 6.5, 150, NULL, 'research', ARRAY['coleslaw chamoru style', 'ensalada repolyo', 'cabbage salad guam'], 'traditional', NULL, 1, 'GU', 'Shredded cabbage, carrot, and cucumber tossed in a creamy mayonnaise and vinegar dressing with a touch of sugar, a standard fiesta side salad. The CHamoru version often includes more cucumber than American coleslaw, reflecting locally abundant ingredients.', TRUE),
('heart_of_palm_salad_guamanian', 'Heart of Palm Salad', 52, 2.5, 8.5, 0.5, 3.5, 2.8, 150, NULL, 'research', ARRAY['heart of palm salad', 'ubod salad', 'palmito salad guam'], 'traditional', NULL, 1, 'GU', 'Sliced heart of palm (ubod) tossed with tomatoes, onion, and a vinegar-oil dressing, a delicate salad found on CHamoru fiesta tables. Heart of palm was harvested from local coconut palms and became a specialty ingredient associated with festive occasions.', TRUE),
('tomato_and_onion_salad_with_finadene_guamanian', 'Tomato and Onion Salad with Finadene', 35, 0.9, 7.0, 0.3, 1.5, 4.8, 150, NULL, 'research', ARRAY['tomato and onion salad with finadene', 'tomato finadene salad', 'ensalada kamatis'], 'traditional', NULL, 1, 'GU', 'Sliced ripe tomatoes and raw onion rings dressed with soy sauce, lemon juice, and crushed donne pepper, served as a condiment-salad hybrid. This bare-bones preparation is a common accompaniment to grilled meats, serving as both sauce and vegetable side.', TRUE),
('pinakbet_guam_style_vegetable_medley_guamanian', 'Pinakbet Guam Style (Vegetable Medley)', 78, 3.5, 10.2, 3.0, 3.8, 4.5, 200, NULL, 'research', ARRAY['pinakbet guam style (vegetable medley)', 'mixed vegetable guisado', 'pakbet chamoru'], 'traditional', NULL, 1, 'GU', 'Sautéed mixed vegetables including bitter melon, eggplant, okra, long beans, squash, and tomato seasoned with shrimp paste (bagoong) and pork, a Filipino-origin dish adopted into CHamoru everyday cooking. Filipino immigration beginning in the early 20th century brought pinakbet which has since become a standard household vegetable dish in Guam.', TRUE),
('steamed_taro_leaves_with_coconut_lau_lau_style_guamanian', 'Steamed Taro Leaves with Coconut (Lau Lau Style)', 68, 3.8, 6.5, 3.2, 2.5, 1.2, 200, NULL, 'research', ARRAY['steamed taro leaves with coconut (lau lau style)', 'taro leaf parcels', 'steamed suni leaves'], 'traditional', NULL, 1, 'GU', 'Young taro leaves wrapped around coconut cream and steamed in banana leaf parcels until tender, similar to Hawaiian lau lau. This communal cooking method of using leaves as cooking vessels connects CHamoru food traditions to broader Polynesian and Micronesian practices.', TRUE),
('boiled_yam_nika_guamanian', 'Boiled Yam (Nika)', 118, 1.5, 27.9, 0.2, 4.1, 0.7, 200, NULL, 'research', ARRAY['boiled yam (nika)', 'nika', 'dago boiled', 'chamoru yam'], 'traditional', NULL, 1, 'GU', 'True yam (nika) boiled until starchy and earthy-flavored, eaten as a traditional staple starch. Multiple yam varieties (nika, dago, gado'') were cultivated by ancient CHamoru farmers and formed a critical part of the pre-contact diet before rice became dominant.', TRUE),
('arrowroot_porridge_gabgab_guamanian', 'Arrowroot Porridge (Gabgab)', 65, 0.3, 16.0, 0.1, 0.8, 0.5, 200, NULL, 'research', ARRAY['arrowroot porridge (gabgab)', 'gabgab porridge', 'arrowroot gruel chamoru'], 'traditional', NULL, 1, 'GU', 'Arrowroot starch (gabgab) cooked with water or coconut milk into a smooth, delicate porridge, one of the oldest CHamoru food preparations. Arrowroot was gathered from wild plants and processed by ancient CHamoru women into a fine starch used for gruels and puddings.', TRUE),
('coconut_cream_dipping_sauce_lechen_niyok_guamanian', 'Coconut Cream Dipping Sauce (Lechen Niyok)', 188, 2.0, 3.8, 19.5, 0.5, 2.8, 60, NULL, 'research', ARRAY['coconut cream dipping sauce (lechen niyok)', 'fresh coconut cream', 'niyok cream'], 'traditional', NULL, 1, 'GU', 'Freshly pressed coconut cream served as a dipping sauce or dressing for grilled fish, cooked vegetables, and starches. Coconut (niyok) is the defining ingredient of CHamoru cuisine, and the ability to press fresh coconut cream by hand is a valued traditional skill.', TRUE),
('finadene_sauce_soy_lemon_guamanian', 'Finadene Sauce (Soy-Lemon)', 18, 1.5, 2.8, 0.1, 0.2, 1.2, 30, NULL, 'research', ARRAY['finadene sauce (soy-lemon)', 'fina''denne', 'black finadene', 'soy finadene'], 'traditional', NULL, 1, 'GU', 'The quintessential CHamoru condiment of soy sauce, lemon juice, sliced onion, and crushed donne sali (bird''s eye chili), present at every meal and fiesta. Finadene unifies CHamoru cuisine, tying together proteins, starches, and vegetables with its bright, salty, spicy character.', TRUE),
('white_finadene_lemon_vinegar_sauce_guamanian', 'White Finadene (Lemon-Vinegar Sauce)', 12, 0.3, 2.5, 0.1, 0.1, 0.8, 30, NULL, 'research', ARRAY['white finadene (lemon-vinegar sauce)', 'finadene i''es', 'lemon finadene', 'coconut vinegar sauce'], 'traditional', NULL, 1, 'GU', 'A lighter finadene variation using lemon juice or coconut vinegar instead of soy sauce, typically paired with fish and seafood dishes. White finadene predates the soy sauce version, reflecting the ancient CHamoru reliance on citrus and salt as primary seasonings.', TRUE),
('donne_dinanche_fermented_pepper_sauce_guamanian', 'Donne Dinanche (Fermented Pepper Sauce)', 22, 1.0, 4.5, 0.3, 1.5, 2.0, 20, NULL, 'research', ARRAY['donne dinanche (fermented pepper sauce)', 'donne'' dinanche''', 'fermented chili paste chamoru'], 'traditional', NULL, 1, 'GU', 'Mashed bird''s eye chili peppers (donne sali) combined with fish brine or soy sauce and fermented into a pungent paste condiment. Donne dinanche is the most intense CHamoru pepper preparation, used sparingly as a condiment and heat source in fiesta spreads.', TRUE),
('achote_rice_hineksa_agaga_red_rice_guamanian', 'Achote Rice (Hineksa Agaga / Red Rice)', 168, 3.2, 36.5, 1.8, 0.8, 0.5, 200, NULL, 'research', ARRAY['achote rice (hineksa agaga / red rice)', 'hineksa'' aga''ga''', 'chamoru red rice', 'fiesta rice guam'], 'traditional', NULL, 1, 'GU', 'Short-grain white rice cooked in annatto (achote) seed water with bacon and onion, turning a vivid orange-red color that has become the defining visual of a CHamoru fiesta plate. Achote seeds were introduced to Guam via the Manila Galleon trade from Mexico and immediately became central to CHamoru cooking.', TRUE),
('titiyas_mais_corn_flatbread_guamanian', 'Titiyas Mais (Corn Flatbread)', 218, 5.2, 44.0, 2.8, 3.5, 1.2, 100, 55, 'research', ARRAY['titiyas mais (corn flatbread)', 'titiyas', 'corn titiyas', 'chamoru tortilla'], 'traditional', NULL, 1, 'GU', 'CHamoru corn tortilla made from masa harina nixtamalized with lime water, hand-pressed thin and cooked on a cast iron kommat, the defining starch of 19th-century CHamoru diet. Introduced via Spanish-Mexican influence through the Manila Galleon trade, titiyas mais replaced earlier root starches as the primary staple before rice took over after WWII.', TRUE),
('titiyas_harina_flour_flatbread_guamanian', 'Titiyas Harina (Flour Flatbread)', 245, 6.5, 48.0, 3.8, 1.5, 1.5, 100, 60, 'research', ARRAY['titiyas harina (flour flatbread)', 'flour titiyas', 'wheat titiyas chamoru'], 'traditional', NULL, 1, 'GU', 'Wheat flour titiyas made with flour, salt, water, and a small amount of lard, cooked on a dry griddle until lightly charred and puffed. The wheat flour version developed after American occupation increased flour availability and is now the most commonly made titiyas style.', TRUE),
('titiyas_faddang_federico_nut_flatbread_guamanian', 'Titiyas Faddang (Federico Nut Flatbread)', 198, 4.2, 38.5, 4.5, 5.2, 1.0, 100, 55, 'research', ARRAY['titiyas faddang (federico nut flatbread)', 'faddang titiyas', 'fadang bread', 'cycas flatbread'], 'traditional', NULL, 1, 'GU', 'Traditional CHamoru flatbread made from detoxified federico nut (fadang/faddang, Cycas micronesica) flour, one of the most ancient CHamoru starch preparations. Fadang required extended washing to leach out natural toxins before drying and grinding into flour, demonstrating sophisticated CHamoru food processing knowledge.', TRUE),
('pan_tosta_guam_toast_guamanian', 'Pan Tosta (Guam Toast)', 280, 5.5, 38.0, 12.5, 1.2, 6.5, 100, 50, 'research', ARRAY['pan tosta (guam toast)', 'toast chamoru', 'tosta guam', 'butter toast guam'], 'traditional', NULL, 1, 'GU', 'Thick slices of local pan Guåhan or Spanish bread toasted until golden and spread generously with margarine or butter and sugar, a beloved CHamoru breakfast and afternoon snack. Pan tosta is a staple of Guam''s bakery culture, often paired with hot coffee or Milo.', TRUE),
('pan_guahan_local_guam_bread_guamanian', 'Pan Guåhan (Local Guam Bread)', 268, 7.5, 50.0, 3.8, 1.8, 5.5, 100, 80, 'research', ARRAY['pan guåhan (local guam bread)', 'guam local bread', 'pan chamoru', 'bakery bread guam'], 'traditional', NULL, 1, 'GU', 'A slightly sweet, soft white bread with a tender crumb baked in local Guam bakeries, distinct from American sandwich bread with its richer texture and faint sweetness. Local bakeries across Guam produce pan Guåhan daily and it is deeply embedded in CHamoru breakfast and snack culture.', TRUE),
('spanish_bread_guam_style_guamanian', 'Spanish Bread Guam Style', 315, 6.2, 46.0, 12.0, 1.2, 12.0, 80, 80, 'research', ARRAY['spanish bread guam style', 'pan de leche relleno', 'guam spanish bread roll'], 'traditional', NULL, 1, 'GU', 'A rolled sweet bread filled with a breadcrumb-margarine-sugar paste, baked until golden and dusted with powdered sugar, a Filipino-Guam bakery staple. Despite the name, Spanish bread in Guam is a Filipino-origin pastry that arrived with immigrant bakers and became a beloved local treat.', TRUE),
('ensaimada_guam_style_guamanian', 'Ensaimada Guam Style', 348, 7.0, 48.5, 14.5, 1.0, 16.0, 90, 90, 'research', ARRAY['ensaimada guam style', 'ensaymada', 'chamoru ensaimada', 'guam coil pastry'], 'traditional', NULL, 1, 'GU', 'A coiled sweet yeast pastry brushed with butter and topped with grated cheese and sugar, a Spanish-origin bread that came to Guam via the Philippines. Ensaimada is a festive pastry associated with Christmas and fiestas, often given as gifts in specialty bakery boxes.', TRUE),
('pan_de_sal_guam_dinner_roll_guamanian', 'Pan de Sal (Guam Dinner Roll)', 255, 7.8, 48.0, 3.5, 1.5, 6.0, 60, 55, 'research', ARRAY['pan de sal (guam dinner roll)', 'pandesal', 'pan de sal guam', 'morning roll chamoru'], 'traditional', NULL, 1, 'GU', 'Small soft bread rolls with a slightly sweet crumb and lightly crisp crust dusted with breadcrumbs, the most popular daily bread in Guam baked fresh each morning. Adopted from Filipino bakery tradition, pan de sal is eaten for breakfast with butter, cheese, or dipped into coffee or hot chocolate.', TRUE),
('monay_bread_guamanian', 'Monay Bread', 285, 7.2, 52.0, 5.5, 1.2, 10.0, 80, 80, 'research', ARRAY['monay bread', 'monay roll', 'filipino monay guam'], 'traditional', NULL, 1, 'GU', 'A dense, slightly sweet round bread with a hard crust and tender interior, a Filipino-origin bread popular in Guam''s local bakeries. Monay is often eaten plain or with butter and is particularly enjoyed with hot coffee or tsokolate as a morning or merienda bread.', TRUE),
('empanada_chamoru_fried_chicken_turnover_guamanian', 'Empanada CHamoru (Fried Chicken Turnover)', 285, 9.5, 32.0, 13.5, 1.8, 2.5, 120, 120, 'research', ARRAY['empanada chamoru (fried chicken turnover)', 'empanada chamoru', 'corn empanada guam', 'chicken turnover chamoru'], 'traditional', NULL, 1, 'GU', 'A masa harina dough turnover filled with achote-seasoned chicken, onion, bell pepper, and green onion, deep-fried until golden. The CHamoru empanada is distinctly corn-based unlike Latin American versions, reflecting the Galleon trade corn influence, and is a beloved fiesta and street food.', TRUE),
('tamales_gisu_chamoru_savory_tamale_guamanian', 'Tamales Gisu (CHamoru Savory Tamale)', 195, 7.5, 28.0, 7.5, 2.2, 1.5, 150, 150, 'research', ARRAY['tamales gisu (chamoru savory tamale)', 'chamoru tamale', 'tamales chamorro', 'gisu tamale'], 'traditional', NULL, 1, 'GU', 'A bicolored steamed tamale with one half colored orange with achote and filled with seasoned chicken or bacon, and one half plain masa, wrapped in banana leaves. Tamales gisu are a fiesta staple with roots in the Spanish colonial-era Galleon trade between Guam and Mexico.', TRUE),
('mendioka_tamale_tapioca_sweet_tamale_guamanian', 'Mendi''oka Tamale (Tapioca Sweet Tamale)', 175, 2.0, 35.0, 4.5, 1.0, 15.0, 120, 120, 'research', ARRAY['mendi''oka tamale (tapioca sweet tamale)', 'cassava tamale chamoru', 'sweet tapioca tamale'], 'traditional', NULL, 1, 'GU', 'A sweet tamale made from grated cassava (mañihok) or tapioca mixed with coconut milk and sugar, steamed in banana leaves. Unlike savory tamales gisu, mendi''oka tamales occupy the dessert section of the fiesta table and represent the CHamoru use of root starches in sweet preparations.', TRUE),
('suni_tamale_taro_sweet_tamale_guamanian', 'Suni Tamale (Taro Sweet Tamale)', 148, 1.8, 30.0, 3.8, 2.5, 12.5, 120, 120, 'research', ARRAY['suni tamale (taro sweet tamale)', 'taro tamale sweet', 'chamoru taro tamale'], 'traditional', NULL, 1, 'GU', 'A sweet steamed tamale made from mashed taro combined with coconut milk, sugar, and a pinch of salt, wrapped and steamed in banana leaves. Suni tamales represent the sweet side of the CHamoru tamale tradition, contrasting with the savory tamales gisu on the fiesta table.', TRUE),
('coconut_bread_titiyas_niyok_guamanian', 'Coconut Bread (Titiyas Niyok)', 295, 5.0, 45.0, 12.0, 3.2, 8.5, 100, 70, 'research', ARRAY['coconut bread (titiyas niyok)', 'niyok bread', 'coconut flatbread chamoru'], 'traditional', NULL, 1, 'GU', 'A flatbread or small loaf made with shredded coconut mixed into flour dough, imparting a subtly sweet coconut flavor and moist texture. Coconut-enriched breads reflect the abundance of niyok (coconut) on Guam and its role as a fat and flavor source in baking.', TRUE),
('bringhe_glutinous_rice_in_banana_leaf_guamanian', 'Bringhe (Glutinous Rice in Banana Leaf)', 225, 6.5, 38.0, 7.5, 1.5, 2.5, 200, NULL, 'research', ARRAY['bringhe (glutinous rice in banana leaf)', 'chamoru bringhe', 'glutinous rice banana leaf', 'yellow rice cake guam'], 'traditional', NULL, 1, 'GU', 'Glutinous rice cooked in coconut milk with turmeric and chicken, wrapped and steamed in banana leaves until set into a firm, sliceable cake. Bringhe is a festive dish served at CHamoru fiestas and quinceañeras, its vibrant yellow color from turmeric making it visually distinctive on the fiesta table.', TRUE),
('scrambled_eggs_with_spam_guamanian', 'Scrambled Eggs with Spam', 198, 14.5, 2.5, 15.0, 0.1, 1.0, 150, NULL, 'research', ARRAY['scrambled eggs with spam', 'spam egg scramble', 'chamoru breakfast scramble'], 'traditional', NULL, 1, 'GU', 'Diced Spam pan-fried until slightly crispy then scrambled with eggs and green onion, the quintessential CHamoru breakfast protein. Spam''s introduction during WWII American military presence became so thoroughly integrated into CHamoru food culture that it appears at breakfast, lunch, and dinner.', TRUE),
('fried_egg_chamoru_style_guamanian', 'Fried Egg CHamoru Style', 148, 10.5, 0.5, 11.5, 0.0, 0.3, 100, NULL, 'research', ARRAY['fried egg chamoru style', 'huevo frito chamoru', 'rice and egg chamoru'], 'traditional', NULL, 1, 'GU', 'Eggs fried sunny-side-up or over-easy in well-oiled pan, served alongside rice and finadene sauce rather than toast as in American breakfast. The CHamoru breakfast plate typically combines fried egg, rice, and a pickled or fried protein, reflecting the rice-centered meal structure.', TRUE),
('hard_boiled_egg_with_finadene_guamanian', 'Hard-Boiled Egg with Finadene', 142, 12.5, 1.5, 9.5, 0.0, 0.8, 120, NULL, 'research', ARRAY['hard-boiled egg with finadene', 'huevos duros finadene', 'boiled egg chamoru'], 'traditional', NULL, 1, 'GU', 'Halved hard-boiled eggs served drizzled with finadene sauce as a simple protein on the fiesta table or as a snack. Hard-boiled eggs prepared in large quantities are a standard component of CHamoru potato salad and also served independently at fiestas.', TRUE),
('egg_salad_chamoru_style_guamanian', 'Egg Salad CHamoru Style', 165, 8.5, 3.5, 13.5, 0.3, 1.5, 150, NULL, 'research', ARRAY['egg salad chamoru style', 'ensalada huevo', 'egg spread chamoru'], 'traditional', NULL, 1, 'GU', 'Chopped hard-boiled eggs mixed with mayonnaise, mustard, sweet relish, and diced celery, served as a sandwich filling or side dish. Egg salad sandwiches on pan Guåhan or pan de sal are a popular school lunch and convenience store item across Guam.', TRUE),
('tortang_talong_eggplant_omelette_guamanian', 'Tortang Talong (Eggplant Omelette)', 128, 8.5, 7.5, 8.0, 3.2, 3.5, 150, NULL, 'research', ARRAY['tortang talong (eggplant omelette)', 'eggplant omelette chamoru', 'talong torta'], 'traditional', NULL, 1, 'GU', 'Grilled and peeled eggplant fanned out and dipped in beaten egg, then pan-fried into a flat omelette-like patty served with rice and ketchup or finadene. A Filipino-origin dish adopted widely across CHamoru households as an inexpensive and satisfying everyday meal.', TRUE),
('tortang_giniling_ground_pork_omelette_guamanian', 'Tortang Giniling (Ground Pork Omelette)', 195, 13.5, 5.5, 14.0, 0.5, 2.0, 150, NULL, 'research', ARRAY['tortang giniling (ground pork omelette)', 'ground meat omelette guam', 'pork torta chamoru'], 'traditional', NULL, 1, 'GU', 'Seasoned ground pork mixed with beaten eggs, onion, garlic, and vegetables then pan-fried into thick patties, a hearty everyday dish served over rice. Torta preparations are ubiquitous in CHamoru home cooking where eggs and ground meat are combined into filling family meals.', TRUE),
('chamorro_egg_and_achote_soup_guamanian', 'Chamorro Egg and Achote Soup', 88, 6.5, 5.5, 4.5, 0.5, 1.0, 250, NULL, 'research', ARRAY['chamorro egg and achote soup', 'egg drop soup chamoru', 'achote egg soup'], 'traditional', NULL, 1, 'GU', 'Beaten eggs dropped into simmering achote-colored broth creating egg-drop threads in an orange-hued soup flavored with onion and garlic. A simple and economical soup that showcases CHamoru fondness for achote as a universal coloring and mild flavoring agent.', TRUE),
('deviled_eggs_chamoru_style_guamanian', 'Deviled Eggs CHamoru Style', 158, 9.5, 2.5, 12.5, 0.2, 1.5, 100, NULL, 'research', ARRAY['deviled eggs chamoru style', 'chamoru deviled eggs', 'stuffed eggs fiesta'], 'traditional', NULL, 1, 'GU', 'Hard-boiled egg yolks mixed with mayonnaise, mustard, and sweet relish piped back into egg whites, garnished with paprika, a popular party and potluck dish on Guam. Deviled eggs appear regularly at CHamoru fiestas and American-style parties, reflecting Guam''s blend of military-American and CHamoru food culture.', TRUE),
('milk_and_egg_pudding_leche_flan_style_guamanian', 'Milk and Egg Pudding (Leche Flan Style)', 175, 6.5, 25.0, 5.5, 0.0, 22.0, 100, NULL, 'research', ARRAY['milk and egg pudding (leche flan style)', 'leche plan chamoru', 'flan guam', 'caramel custard chamoru'], 'traditional', NULL, 1, 'GU', 'A steamed or baked custard of condensed milk, eggs, vanilla, and caramel syrup, silkier and richer than French crème caramel due to the condensed milk. Leche flan appears on every CHamoru fiesta dessert table as the most essential sweet dish, with family recipes passed down through generations.', TRUE),
('latiya_chamoru_custard_sponge_cake_guamanian', 'Latiya (CHamoru Custard Sponge Cake)', 225, 6.0, 36.0, 7.5, 0.2, 24.0, 150, NULL, 'research', ARRAY['latiya (chamoru custard sponge cake)', 'chamoru latiya', 'custard sponge cake guam'], 'traditional', NULL, 1, 'GU', 'Sliced sponge cake layered under a warm poured custard made from condensed milk, egg yolks, butter, cornstarch, and vanilla, dusted generously with cinnamon. Latiya is the most distinctly CHamoru dessert, found exclusively in Guam and the CNMI, representing the fusion of American baking with Spanish custard tradition.', TRUE),
('butter_mochi_chamorro_style_guamanian', 'Butter Mochi (Chamorro Style)', 285, 4.5, 48.0, 9.0, 0.5, 22.0, 100, 80, 'research', ARRAY['butter mochi (chamorro style)', 'bibingka mochi', 'chamoru mochi cake', 'baked mochi guam'], 'traditional', NULL, 1, 'GU', 'Glutinous rice flour baked with butter, eggs, coconut milk, and sugar into a dense, chewy, slightly crispy-edged cake, popular at CHamoru potlucks. The buttery mochi cake blends Japanese mochi tradition with American baking culture, both influences prominent in Guam''s 20th-century food history.', TRUE),
('bibingka_rice_cake_chamoru_style_guamanian', 'Bibingka (Rice Cake CHamoru Style)', 252, 5.0, 40.0, 9.5, 0.8, 18.0, 120, 120, 'research', ARRAY['bibingka (rice cake chamoru style)', 'rice cake guam', 'chamoru bibingka', 'coconut rice cake'], 'traditional', NULL, 1, 'GU', 'A baked or steamed rice flour cake with coconut milk, eggs, and sugar, topped with salted egg slices and fresh grated coconut. Filipino-origin bibingka is widely made in CHamoru households for Christmas season and fiestas, representing the strong Filipino cultural influence on Guam''s food traditions.', TRUE),
('puto_steamed_rice_cakes_guamanian', 'Puto (Steamed Rice Cakes)', 168, 3.8, 32.0, 3.2, 0.5, 10.0, 80, 25, 'research', ARRAY['puto (steamed rice cakes)', 'steamed rice cake chamoru', 'puto cheese'], 'traditional', NULL, 1, 'GU', 'Small fluffy steamed rice flour cakes eaten as a snack or alongside savory dishes like dinuguan, often topped with a sliver of cheese. A Filipino-origin snack deeply integrated into Guam''s food culture, puto is sold at roadside stalls and served at fiestas across the island.', TRUE),
('kalamay_sweet_sticky_rice_cake_guamanian', 'Kalamay (Sweet Sticky Rice Cake)', 285, 3.5, 55.0, 7.0, 1.2, 28.0, 100, NULL, 'research', ARRAY['kalamay (sweet sticky rice cake)', 'sticky rice sweet chamoru', 'kalamay guam'], 'traditional', NULL, 1, 'GU', 'Glutinous rice flour cooked with coconut milk and brown sugar into a thick sticky confection, poured into banana leaf-lined trays and cut into squares when set. Kalamay is a beloved merienda snack and dessert in Guam with roots in Filipino and Spanish confectionery traditions.', TRUE),
('chamorro_cooked_banana_chotda_guisada_guamanian', 'Chamorro Cooked Banana (Chotda Guisada)', 122, 1.0, 30.0, 2.5, 2.5, 16.0, 150, NULL, 'research', ARRAY['chamorro cooked banana (chotda guisada)', 'fried banana guam', 'chotda dulce', 'sweet banana chamoru'], 'traditional', NULL, 1, 'GU', 'Ripe saba or plantain bananas cooked in butter and brown sugar until caramelized and golden, a traditional sweet side dish or dessert. Bananas (chotda) have been cultivated in Guam since ancient times and the saba variety is particularly valued for cooking due to its starchy sweetness.', TRUE),
('boiled_saba_banana_guamanian', 'Boiled Saba Banana', 108, 1.2, 25.8, 0.3, 2.8, 12.0, 150, NULL, 'research', ARRAY['boiled saba banana', 'saba banana boiled', 'guinataan saging simple'], 'traditional', NULL, 1, 'GU', 'Unpeeled saba plantain bananas boiled in lightly salted water until the skin splits and the flesh becomes tender, served warm as a snack or side. This simple preparation is one of the oldest ways to eat bananas across Pacific island cultures and remains a comfort food in CHamoru households.', TRUE),
('dulce_de_coco_coconut_candy_guamanian', 'Dulce de Coco (Coconut Candy)', 345, 2.8, 52.0, 15.0, 3.5, 45.0, 50, 12, 'research', ARRAY['dulce de coco (coconut candy)', 'coconut balls chamoru', 'coco candy guam', 'coconut fudge chamoru'], 'traditional', NULL, 1, 'GU', 'Freshly grated coconut cooked with sugar, condensed milk, and sometimes chocolate into a thick fudge-like paste, rolled into balls and allowed to set. Dulce de coco is a traditional CHamoru sweet served at fiestas and homemade as holiday gifts, representing the island''s affinity for coconut-based confections.', TRUE),
('achote_water_coloring_agent_guamanian', 'Achote Water (Coloring Agent)', 8, 0.2, 1.8, 0.2, 0.5, 0.1, 100, NULL, 'research', ARRAY['achote water (coloring agent)', 'annatto water', 'achote liquid', 'atsuete water'], 'traditional', NULL, 1, 'GU', 'Water infused by soaking annatto seeds until it turns deep orange-red, used as a cooking liquid for red rice, tamales, and achote-colored dishes. Achote (Bixa orellana) was one of the most important flavor and color contributions of the Manila Galleon trade to CHamoru cuisine.', TRUE),
('tinaktak_vegetables_guamanian', 'Tinaktak Vegetables', 88, 4.5, 8.5, 4.5, 2.8, 3.5, 200, NULL, 'research', ARRAY['tinaktak vegetables', 'vegetable tinaktak', 'tinaktak guisantes'], 'traditional', NULL, 1, 'GU', 'A vegetarian adaptation of the classic CHamoru ground meat and long bean dish cooked in coconut milk, omitting the meat for a lighter vegetable-forward side. Tinaktak is one of the most beloved CHamoru preparations and this vegetable version is increasingly popular in health-conscious households.', TRUE),
('kangkong_adobo_water_spinach_adobo_guamanian', 'Kangkong Adobo (Water Spinach Adobo)', 52, 2.8, 6.0, 2.0, 2.2, 1.5, 150, NULL, 'research', ARRAY['kangkong adobo (water spinach adobo)', 'water spinach adobo', 'adobong kangkong'], 'traditional', NULL, 1, 'GU', 'Water spinach braised in vinegar, soy sauce, garlic, and bay leaf until wilted and tangy, a vegetable adobo common across CHamoru and Filipino-influenced Guam households. Kangkong grows wild in Guam''s waterways and is one of the most accessible and affordable greens on the island.', TRUE),
('ginataang_gulay_mixed_vegetables_in_coconut_milk_guamanian', 'Ginataang Gulay (Mixed Vegetables in Coconut Milk)', 82, 2.5, 9.5, 4.2, 3.0, 3.8, 200, NULL, 'research', ARRAY['ginataang gulay (mixed vegetables in coconut milk)', 'ginataan vegetables', 'coconut milk mixed vegetables chamoru'], 'traditional', NULL, 1, 'GU', 'Assorted vegetables including squash, long beans, eggplant, and leafy greens simmered in coconut milk with garlic and shrimp paste. This coconut milk vegetable medley reflects the core CHamoru cooking technique of using coconut milk to transform simple vegetables into rich, satisfying side dishes.', TRUE),
('corn_on_the_cob_grilled_mais_inihaw_guamanian', 'Corn on the Cob Grilled (Mais Inihaw)', 115, 3.5, 24.5, 1.8, 2.8, 6.5, 150, NULL, 'research', ARRAY['corn on the cob grilled (mais inihaw)', 'grilled corn chamoru', 'bbq corn guam', 'mais barbecue'], 'traditional', NULL, 1, 'GU', 'Whole corn cobs grilled over charcoal until charred and smoky, brushed with butter and served with a side of finadene sauce. Corn has deep CHamoru cultural roots as the original source of titiyas flatbread flour and grilled corn is a popular roadside snack at Guam village fairs.', TRUE),
('papaya_kelaguen_green_papaya_with_lemon_guamanian', 'Papaya Kelaguen (Green Papaya with Lemon)', 42, 1.0, 9.5, 0.3, 2.0, 5.5, 150, NULL, 'research', ARRAY['papaya kelaguen (green papaya with lemon)', 'kelaguen papaya', 'green papaya kelaguen chamoru'], 'traditional', NULL, 1, 'GU', 'Shredded raw green papaya mixed with lemon juice, donne pepper, and green onion in the style of CHamoru kelaguen but without meat, a refreshing tart side dish. This vegetarian kelaguen draws on the same acid-based curing technique used for meat and seafood kelaguens.', TRUE),
('banana_cue_skewered_fried_banana_guamanian', 'Banana Cue (Skewered Fried Banana)', 188, 1.2, 42.0, 3.5, 2.5, 22.0, 150, 80, 'research', ARRAY['banana cue (skewered fried banana)', 'banana skewer guam', 'chotda cue', 'caramel banana stick'], 'traditional', NULL, 1, 'GU', 'Saba bananas deep-fried in brown sugar until caramelized and skewered on bamboo sticks, a Filipino-origin street food sold at CHamoru markets and roadside stalls. Banana cue is one of the most popular merienda foods in Guam alongside turon and camote que.', TRUE),
('turon_banana_spring_roll_guamanian', 'Turon (Banana Spring Roll)', 195, 2.5, 35.0, 6.5, 2.2, 16.0, 100, 80, 'research', ARRAY['turon (banana spring roll)', 'banana lumpia sweet', 'banana egg roll guam', 'turon guam'], 'traditional', NULL, 1, 'GU', 'Saba banana and jackfruit wrapped in lumpia spring roll wrapper, dredged in brown sugar, and deep-fried until crispy and caramelized. Turon is a beloved Filipino-origin street snack that has become a staple at CHamoru fiestas, school events, and roadside vendors across Guam.', TRUE),
('palitaw_rice_cake_in_coconut_guamanian', 'Palitaw (Rice Cake in Coconut)', 165, 2.8, 32.0, 3.5, 1.0, 12.0, 80, 40, 'research', ARRAY['palitaw (rice cake in coconut)', 'floating rice cake', 'rice oval chamoru'], 'traditional', NULL, 1, 'GU', 'Flat oval rice cakes made from glutinous rice flour boiled until they float, then rolled in toasted coconut, sugar, and sesame seeds. Palitaw is a Filipino-origin kakanin popular in Guam''s local merienda culture, the name meaning to float referring to the cooking method.', TRUE),
('cascaron_fried_coconut_rice_balls_guamanian', 'Cascaron (Fried Coconut Rice Balls)', 312, 3.5, 42.0, 15.0, 2.5, 18.0, 100, 25, 'research', ARRAY['cascaron (fried coconut rice balls)', 'chamoru cascaron', 'coconut rice ball fried', 'fiesta rice balls guam'], 'traditional', NULL, 1, 'GU', 'Small balls of glutinous rice flour and shredded coconut deep-fried until golden and rolled in sugar, a traditional CHamoru sweet sold at village fiestas and fairs. Cascaron are one of the most nostalgic CHamoru sweets, prepared communally by women for village celebrations.', TRUE),
('bunelos_dago_yam_fritters_guamanian', 'Bunelos Dago (Yam Fritters)', 265, 3.5, 42.0, 10.5, 3.0, 8.0, 100, 35, 'research', ARRAY['bunelos dago (yam fritters)', 'yam fritters chamoru', 'dago fritters', 'bunuelos dago'], 'traditional', NULL, 1, 'GU', 'Grated yam (dago) or taro mixed with egg, flour, and a little sugar then deep-fried into golden fritters, a traditional CHamoru snack. Bunelos dago is one of the authentic ancient CHamoru snack forms adapted from root vegetables available before Spanish contact.', TRUE),
('bunelos_ahu_deep_fried_rice_fritters_guamanian', 'Bunelos Ahu (Deep-Fried Rice Fritters)', 285, 4.5, 46.0, 9.5, 0.8, 10.0, 100, 30, 'research', ARRAY['bunelos ahu (deep-fried rice fritters)', 'chamoru doughnuts', 'rice doughnut guam'], 'traditional', NULL, 1, 'GU', 'Sweet fried doughnut-like fritters made from rice flour, coconut milk, sugar, and egg, cooked in a doughnut shape or as irregular puffs. Bunelos ahu are a classic CHamoru fiesta sweet sold hot at village celebrations and associated with the joyful atmosphere of CHamoru fiestas.', TRUE),
('banana_fritters_ukoy_chotda_guamanian', 'Banana Fritters (Ukoy Chotda)', 225, 3.2, 38.0, 7.5, 2.0, 14.0, 100, 50, 'research', ARRAY['banana fritters (ukoy chotda)', 'fried banana batter', 'banana tempura chamoru'], 'traditional', NULL, 1, 'GU', 'Sliced ripe banana dipped in a light batter and deep-fried until crispy and golden, a simple street snack common across Guam and the Marianas. Banana fritters are sold at roadside stalls and school canteens as an affordable and satisfying merienda.', TRUE),
('kamote_cue_fried_sweet_potato_skewer_guamanian', 'Kamote Cue (Fried Sweet Potato Skewer)', 175, 1.8, 38.5, 3.5, 3.2, 18.0, 150, 80, 'research', ARRAY['kamote cue (fried sweet potato skewer)', 'sweet potato skewer guam', 'camote que', 'kamuti cue'], 'traditional', NULL, 1, 'GU', 'Sliced sweet potato deep-fried in caramelized brown sugar on skewers, a Filipino-origin street food popular at CHamoru markets and merienda stalls. Kamote cue alongside banana cue represents the classic Filipino-influenced sweet snack culture embedded in Guam''s food landscape.', TRUE),
('champurrado_chocolate_corn_porridge_guamanian', 'Champurrado (Chocolate Corn Porridge)', 145, 3.8, 28.0, 3.5, 1.5, 12.0, 250, NULL, 'research', ARRAY['champurrado (chocolate corn porridge)', 'chocolate atole chamoru', 'chamoru chocolate porridge'], 'traditional', NULL, 1, 'GU', 'A warm thick porridge of corn masa cooked in hot chocolate, milk, and piloncillo sugar, a Mexican-origin comfort food that arrived via the Galleon trade. Champurrado is often served for breakfast during Christmas season alongside tamales gisu at CHamoru households.', TRUE),
('atole_de_arroz_rice_and_coconut_gruel_guamanian', 'Atole de Arroz (Rice and Coconut Gruel)', 95, 2.0, 18.5, 2.2, 0.8, 4.5, 250, NULL, 'research', ARRAY['atole de arroz (rice and coconut gruel)', 'chamoru rice gruel', 'atoli chamoru', 'rice coconut porridge'], 'traditional', NULL, 1, 'GU', 'A thin porridge of ground rice cooked in coconut water or coconut milk, historically served with salted fish, one of the oldest documented CHamoru dishes. French navigator Louis Freycinet recorded atole as the primary staple food of the CHamoru people in the early 19th century.', TRUE),
('arroz_caldo_chamoru_rice_congee_guamanian', 'Arroz Caldo (CHamoru Rice Congee)', 88, 5.5, 14.0, 1.5, 0.5, 0.8, 250, NULL, 'research', ARRAY['arroz caldo (chamoru rice congee)', 'lugaw chamoru', 'chicken congee guam', 'arroscaldo'], 'traditional', NULL, 1, 'GU', 'Rice congee with chicken, ginger, fish sauce, and garlic oil, topped with calamansi, boiled egg, and green onion, a warm comfort food eaten when ill or on rainy days. Arroz caldo was introduced by Filipino immigrants and became a CHamoru household staple particularly valued as a sick-day remedy.', TRUE),
('sinangag_garlic_fried_rice_guamanian', 'Sinangag (Garlic Fried Rice)', 175, 4.0, 34.0, 3.5, 0.8, 0.5, 200, NULL, 'research', ARRAY['sinangag (garlic fried rice)', 'garlic rice chamoru', 'fried rice garlic guam'], 'traditional', NULL, 1, 'GU', 'Day-old rice stir-fried with large amounts of garlic until fragrant and slightly crispy, a breakfast staple across CHamoru households in Guam. Sinangag forms the base of the classic CHamoru silog breakfast plate alongside fried egg and cured meat.', TRUE),
('chamorro_fried_rice_guamanian', 'Chamorro Fried Rice', 185, 5.5, 32.0, 5.0, 1.0, 1.5, 200, NULL, 'research', ARRAY['chamorro fried rice', 'chamoru fried rice', 'spam fried rice guam', 'local fried rice guam'], 'traditional', NULL, 1, 'GU', 'Cooked rice stir-fried with diced Spam, eggs, soy sauce, onion, garlic, and green onion in a hot wok, a local comfort food reflecting CHamoru-Chinese-American influence. Chamorro fried rice at local diners typically uses red rice as the base, giving it an orange hue.', TRUE),
('pancit_sotanghon_glass_noodle_soup_guamanian', 'Pancit Sotanghon (Glass Noodle Soup)', 112, 5.8, 18.5, 2.0, 1.2, 2.0, 250, NULL, 'research', ARRAY['pancit sotanghon (glass noodle soup)', 'glass noodle soup chamoru', 'sotanghon chamoru'], 'traditional', NULL, 1, 'GU', 'Glass noodles in a clear chicken broth with chicken strips, mushrooms, cabbage, and green onion, a light noodle soup popular at CHamoru family gatherings. Sotanghon soup is commonly prepared for merienda or as a lighter alternative to meat-heavy fiesta dishes.', TRUE),
('lumpiang_sariwa_fresh_spring_rolls_guamanian', 'Lumpiang Sariwa (Fresh Spring Rolls)', 105, 5.5, 14.0, 3.5, 2.5, 4.0, 150, 100, 'research', ARRAY['lumpiang sariwa (fresh spring rolls)', 'fresh lumpia chamoru', 'vegetable spring roll guam'], 'traditional', NULL, 1, 'GU', 'Soft crepe-like wrappers filled with sauteed heart of palm, jicama, green beans, tofu, and shrimp, served fresh with a sweet peanut-garlic sauce. Lumpiang sariwa appears at CHamoru fiestas as a lighter vegetable option amid the heavier meat dishes.', TRUE),
('lumpia_shanghai_guam_style_guamanian', 'Lumpia Shanghai Guam Style', 215, 8.5, 18.0, 12.5, 0.8, 1.5, 100, 15, 'research', ARRAY['lumpia shanghai guam style', 'fried spring roll guam', 'chamoru lumpia', 'mini egg roll guam'], 'traditional', NULL, 1, 'GU', 'Thin crispy spring rolls filled with seasoned ground pork, carrots, and green onion, deep-fried until golden, served with sweet chili dipping sauce. Lumpia Shanghai is one of the most popular fried snacks in Guam, prepared in large batches for fiestas and sold as street food.', TRUE),
('jicama_and_mango_salad_guamanian', 'Jicama and Mango Salad', 48, 0.8, 11.5, 0.2, 2.5, 7.5, 150, NULL, 'research', ARRAY['jicama and mango salad', 'jicama mango salad guam', 'singkamas ensalada'], 'traditional', NULL, 1, 'GU', 'Julienned jicama and sliced green mango tossed with lime juice, donne chili, and a pinch of salt, a crisp refreshing salad sold at local markets. Jicama was introduced to Guam via the Galleon trade and is appreciated for its neutral crunch that complements acidic fruit salad dressings.', TRUE),
('green_mango_salad_ensaladang_mangga_guamanian', 'Green Mango Salad (Ensaladang Mangga)', 52, 0.8, 12.5, 0.3, 1.8, 9.0, 150, NULL, 'research', ARRAY['green mango salad (ensaladang mangga)', 'mango kelaguen', 'mangga ensalada chamoru'], 'traditional', NULL, 1, 'GU', 'Shredded unripe green mango tossed with fish sauce, lime, sugar, crushed peanuts, and donne chili, a tart and spicy fruit salad popular in Guam. Green mango salad reflects Thai and Filipino influences on Guam''s modern food culture and is a popular accompaniment to grilled seafood.', TRUE),
('lablab_hyacinth_bean_stew_guamanian', 'Lablab (Hyacinth Bean) Stew', 95, 7.5, 14.5, 1.2, 5.5, 2.5, 200, NULL, 'research', ARRAY['lablab (hyacinth bean) stew', 'bonavista bean stew chamoru', 'hyacinth bean coconut chamoru'], 'traditional', NULL, 1, 'GU', 'Lablab beans stewed with coconut milk, onion, garlic, and salt until tender and creamy, a traditional CHamoru legume dish. Lablab (also called bonavista beans) is an ancient crop adapted to Guam''s tropical climate and was an important protein source in the pre-contact CHamoru diet.', TRUE),
('chamoru_corn_soup_kaldo_mais_guamanian', 'CHamoru Corn Soup (Kaldo Mais)', 82, 3.5, 14.5, 2.0, 2.0, 4.5, 250, NULL, 'research', ARRAY['chamoru corn soup (kaldo mais)', 'corn chowder chamoru', 'mais soup guam'], 'traditional', NULL, 1, 'GU', 'Fresh corn kernels simmered in a light chicken broth with garlic, onion, and coconut milk, thickened slightly with cornstarch, a comforting soup. Corn soup draws on the ancient CHamoru use of corn as a primary grain and the tradition of coconut milk-enriched broths.', TRUE),
('squash_coconut_soup_kalabasa_soup_guamanian', 'Squash Coconut Soup (Kalabasa Soup)', 75, 2.0, 12.0, 3.0, 2.2, 5.5, 250, NULL, 'research', ARRAY['squash coconut soup (kalabasa soup)', 'pumpkin coconut soup guam', 'kalabasa cream soup chamoru'], 'traditional', NULL, 1, 'GU', 'Pureed kabocha squash blended with coconut milk, ginger, and onion into a velvety smooth soup, a modern CHamoru-style preparation of a traditional vegetable. The natural sweetness of squash paired with coconut milk is a beloved flavor combination in CHamoru cooking.', TRUE),
('bitter_melon_with_egg_and_shrimp_guamanian', 'Bitter Melon with Egg and Shrimp', 72, 6.5, 5.0, 3.5, 2.5, 1.8, 150, NULL, 'research', ARRAY['bitter melon with egg and shrimp', 'ampalaya eggs shrimp', 'bitter gourd egg chamoru'], 'traditional', NULL, 1, 'GU', 'Sliced bitter melon stir-fried with beaten eggs and baby shrimp, the eggs softening the intense bitterness into a complex savory dish. This bitter melon preparation is a home-cooking staple in CHamoru households where the bitter flavor is appreciated as a digestive aid.', TRUE),
('eggplant_in_coconut_milk_talong_ginata_guamanian', 'Eggplant in Coconut Milk (Talong Ginata)', 82, 2.0, 8.5, 5.0, 3.5, 4.2, 200, NULL, 'research', ARRAY['eggplant in coconut milk (talong ginata)', 'talong ginata chamoru', 'eggplant coconut cream'], 'traditional', NULL, 1, 'GU', 'Sliced eggplant simmered in fresh coconut milk with shrimp paste, garlic, and long chili until tender and saucy, a common CHamoru vegetable side. The coconut milk transforms eggplant into a creamy dish that pairs well with plain or red rice.', TRUE),
('pickled_papaya_atsara_guamanian', 'Pickled Papaya (Atsara)', 35, 0.5, 8.5, 0.1, 1.5, 6.5, 50, NULL, 'research', ARRAY['pickled papaya (atsara)', 'pickled green papaya', 'achara chamoru', 'atsara guam'], 'traditional', NULL, 1, 'GU', 'Shredded green papaya pickled in vinegar, sugar, garlic, carrots, and raisins, a Filipino-origin condiment used as a palate-cleanser alongside grilled meats. Atsara is a common condiment in CHamoru households particularly served alongside BBQ pork and chicken to cut through the richness.', TRUE),
('chamorro_vegetable_kadu_guamanian', 'Chamorro Vegetable Kadu', 55, 2.5, 9.5, 1.0, 3.0, 3.5, 250, NULL, 'research', ARRAY['chamorro vegetable kadu', 'vegetable kadu chamoru', 'root vegetable broth guam'], 'traditional', NULL, 1, 'GU', 'A clear vegetable broth stew with taro, breadfruit, green banana, and moringa leaves, a vegetarian version of the traditional CHamoru kadu stew. Vegetable kadu showcases the ancient CHamoru root vegetable and tree crop pantry in a single warming bowl.', TRUE),
('pumpkin_and_shrimp_adobo_guamanian', 'Pumpkin and Shrimp Adobo', 95, 6.5, 10.5, 3.0, 2.0, 4.5, 200, NULL, 'research', ARRAY['pumpkin and shrimp adobo', 'kalabasa adobo chamoru', 'squash shrimp adobo'], 'traditional', NULL, 1, 'GU', 'Cubed pumpkin and shrimp braised together in vinegar, soy sauce, garlic, and bay leaf until the squash absorbs the adobo tang. A CHamoru-Filipino fusion that pairs the natural sweetness of squash with briny shrimp in the classic adobo preparation.', TRUE),
('chamorro_coleslaw_with_spam_guamanian', 'Chamorro Coleslaw with Spam', 118, 3.5, 10.5, 7.0, 1.8, 5.5, 150, NULL, 'research', ARRAY['chamorro coleslaw with spam', 'spam coleslaw guam', 'chamoru slaw with spam'], 'traditional', NULL, 1, 'GU', 'Shredded cabbage and carrot slaw mixed with diced Spam and a sweet-tangy mayonnaise dressing, a distinctly CHamoru salad combining American potluck tradition with the island''s beloved canned meat. Often served alongside red rice and BBQ at family cookouts.', TRUE),
('pan_de_coco_coconut_filled_bun_guamanian', 'Pan de Coco (Coconut-Filled Bun)', 298, 6.5, 48.0, 9.5, 2.5, 18.0, 90, 90, 'research', ARRAY['pan de coco (coconut-filled bun)', 'coconut bun guam', 'pan coco chamoru'], 'traditional', NULL, 1, 'GU', 'Soft sweet bread rolls filled with a sweetened grated coconut filling, a popular bakery item in Guam inspired by Filipino and Spanish baking traditions. Pan de coco from local bakeries is a beloved snack with shredded coconut providing both filling sweetness and textural contrast.', TRUE),
('hopia_mung_bean_pastry_guamanian', 'Hopia (Mung Bean Pastry)', 285, 5.5, 48.0, 9.0, 3.5, 22.0, 80, 70, 'research', ARRAY['hopia (mung bean pastry)', 'hopiang munggo', 'bean paste pastry guam', 'hopia baboy'], 'traditional', NULL, 1, 'GU', 'A round flaky pastry with a smooth sweetened mung bean, ube, or pork filling, a Chinese-Filipino confection popular in Guam''s local bakeries. Hopia is associated with Chinese-Filipino lunar new year celebrations and has become a year-round Guam bakery staple.', TRUE),
('polvoron_toasted_flour_sweet_guamanian', 'Polvoron (Toasted Flour Sweet)', 445, 7.0, 58.0, 22.0, 1.0, 28.0, 60, 15, 'research', ARRAY['polvoron (toasted flour sweet)', 'powdered cookie chamoru', 'polvoron guam', 'toasted flour sweet'], 'traditional', NULL, 1, 'GU', 'A crumbly powdery shortbread made from toasted flour, powdered milk, sugar, and butter pressed into small cylinders wrapped in cellophane, a Spanish-Filipino sweet popular in Guam. Polvoron is a common pasalubong item bought from Guam bakeries to bring back to relatives.', TRUE),
('brazo_de_mercedes_meringue_roll_guamanian', 'Brazo de Mercedes (Meringue Roll)', 255, 7.5, 42.0, 8.0, 0.1, 38.0, 100, NULL, 'research', ARRAY['brazo de mercedes (meringue roll)', 'meringue roll guam', 'brazo chamoru'], 'traditional', NULL, 1, 'GU', 'A soft meringue roll filled with rich egg yolk custard (yema), a Filipino-origin pastry found in Guam bakeries particularly during fiesta and holiday seasons. The contrast of cloud-like meringue with dense egg custard makes brazo de Mercedes a prized special-occasion dessert.', TRUE),
('yema_egg_yolk_candy_guamanian', 'Yema (Egg Yolk Candy)', 378, 8.5, 62.0, 11.0, 0.0, 58.0, 50, 12, 'research', ARRAY['yema (egg yolk candy)', 'egg candy chamoru', 'yema balls guam'], 'traditional', NULL, 1, 'GU', 'Cooked egg yolks mixed with condensed milk and shaped into balls or pyramids wrapped in cellophane, a simple Filipino-Spanish candy popular across Guam. Yema is sold at bakeries and market stalls, an economical sweet embedded in CHamoru snack culture.', TRUE),
('ube_halaya_purple_yam_jam_guamanian', 'Ube Halaya (Purple Yam Jam)', 225, 3.5, 45.0, 4.5, 3.5, 28.0, 100, NULL, 'research', ARRAY['ube halaya (purple yam jam)', 'purple yam jam', 'ube jam guam', 'ube halaya chamoru'], 'traditional', NULL, 1, 'GU', 'Boiled purple yam (ube) mashed with condensed milk, butter, and coconut milk into a smooth jam-like confection served as dessert or spread. Ube halaya is extremely popular in Guam''s Filipino-influenced food culture and has experienced a global revival in recent years.', TRUE),
('chamorro_corn_porridge_atole_mais_guamanian', 'Chamorro Corn Porridge (Atole Mais)', 105, 2.5, 22.5, 1.5, 2.0, 5.0, 250, NULL, 'research', ARRAY['chamorro corn porridge (atole mais)', 'corn atole chamoru', 'mais porridge guam'], 'traditional', NULL, 1, 'GU', 'Ground corn cooked with coconut milk and sugar into a thick warm porridge, a CHamoru-adapted version of the Mexican atole that arrived via the Galleon trade. Corn atole is a traditional morning food during CHamoru fiestas and Christmas celebrations.', TRUE),
('miso_soup_guam_style_guamanian', 'Miso Soup Guam Style', 35, 2.5, 4.5, 1.0, 1.0, 1.0, 250, NULL, 'research', ARRAY['miso soup guam style', 'miso chamoru', 'japanese miso guam adaptation'], 'traditional', NULL, 1, 'GU', 'Japanese-style miso broth with tofu, wakame seaweed, and green onion, reflecting the significant Japanese cultural influence on Guam from the occupation period and post-war Japanese tourism. Miso soup appears on many local Guam diner menus as a standard soup option.', TRUE),
('taro_leaf_chips_suni_chips_guamanian', 'Taro Leaf Chips (Suni Chips)', 398, 5.5, 52.0, 19.5, 4.5, 1.5, 50, NULL, 'research', ARRAY['taro leaf chips (suni chips)', 'suni leaf chips', 'taro chip chamoru'], 'traditional', NULL, 1, 'GU', 'Young taro leaves deep-fried until crispy and lightly salted, a savory snack sold at local markets and farm stalls across Guam. Taro leaf chips have gained popularity as a locally sourced artisan snack showcasing Guam''s traditional agricultural crops in modern snack formats.', TRUE),
('chamorro_fiesta_lumpia_large_egg_roll_guamanian', 'Chamorro Fiesta Lumpia (Large Egg Roll)', 198, 7.5, 18.5, 11.0, 1.5, 2.0, 100, 40, 'research', ARRAY['chamorro fiesta lumpia (large egg roll)', 'fiesta lumpia guam', 'chamoru egg roll large'], 'traditional', NULL, 1, 'GU', 'Large-format egg rolls filled with a mixed pork, vegetable, and glass noodle filling, deep-fried until golden brown and served in big batches at CHamoru fiestas. CHamoru fiesta lumpia are larger than Shanghai-style and often contain bean thread noodles and more vegetables.', TRUE),
('chamorro_vegetable_soup_sopas_gulay_guamanian', 'Chamorro Vegetable Soup (Sopas Gulay)', 58, 2.8, 9.5, 1.2, 2.8, 3.5, 250, NULL, 'research', ARRAY['chamorro vegetable soup (sopas gulay)', 'vegetable broth soup guam', 'sopas chamoru'], 'traditional', NULL, 1, 'GU', 'A light clear broth soup with a medley of locally grown vegetables including sayote, tomato, moringa, and long beans, a staple home-cooked soup. Sopas gulay is made from whatever vegetables are available in the backyard garden, reflecting sustainable CHamoru home cooking traditions.', TRUE),
('sayote_chayote_stir_fry_guamanian', 'Sayote (Chayote) Stir-Fry', 35, 1.2, 7.5, 0.5, 2.5, 2.8, 200, NULL, 'research', ARRAY['sayote (chayote) stir-fry', 'chayote guisado', 'sayote chamoru', 'vegetable pear saute'], 'traditional', NULL, 1, 'GU', 'Sliced chayote squash stir-fried with garlic, onion, and a splash of fish sauce or soy sauce, a crisp-tender vegetable side dish. Sayote grows abundantly in Guam''s backyard gardens and is one of the most frequently cooked vegetables in CHamoru households due to its mild flavor and year-round availability.', TRUE),
('pechay_bok_choy_with_oyster_sauce_guamanian', 'Pechay (Bok Choy) with Oyster Sauce', 38, 2.0, 5.5, 1.0, 1.8, 2.5, 150, NULL, 'research', ARRAY['pechay (bok choy) with oyster sauce', 'bok choy oyster sauce guam', 'pechay chamoru'], 'traditional', NULL, 1, 'GU', 'Baby bok choy blanched and drizzled with oyster sauce and sesame oil, a Chinese-influenced vegetable preparation popular in Guam''s Chinese-Filipino restaurant culture. Pechay in oyster sauce is commonly served as a vegetable side at local Chinese restaurants and has been adopted into CHamoru home cooking.', TRUE),
('chamorro_bean_soup_sopas_frijoles_guamanian', 'Chamorro Bean Soup (Sopas Frijoles)', 95, 5.5, 16.0, 1.5, 5.5, 2.0, 250, NULL, 'research', ARRAY['chamorro bean soup (sopas frijoles)', 'bean pork soup chamoru', 'frijoles chamoru'], 'traditional', NULL, 1, 'GU', 'A hearty soup of pinto or red beans cooked with pork neck bones, tomatoes, garlic, and onion, a Spanish-origin preparation that became a CHamoru staple. Bean soups were introduced during Spanish colonial rule and provide a protein and fiber-rich warming meal during Guam''s rainy season.', TRUE),
('pan_de_ube_purple_yam_bread_guamanian', 'Pan de Ube (Purple Yam Bread)', 268, 6.5, 48.0, 6.5, 1.5, 14.0, 90, 90, 'research', ARRAY['pan de ube (purple yam bread)', 'purple yam bread guam', 'ube bun chamoru', 'purple bread guam'], 'traditional', NULL, 1, 'GU', 'A soft vibrant purple bread roll made with ube flavoring or real purple yam puree mixed into the dough, a visually striking Filipino-influenced pastry popular in Guam bakeries. Pan de ube is one of the most popular specialty breads in Guam''s local bakeries and is frequently gifted as a pasalubong.', TRUE),
('pan_con_leche_milk_toast_chamoru_guamanian', 'Pan con Leche (Milk Toast CHamoru)', 265, 8.0, 42.0, 8.0, 1.2, 12.0, 100, 60, 'research', ARRAY['pan con leche (milk toast chamoru)', 'pan leche chamoru', 'chamoru french toast', 'sweet milk bread guam'], 'traditional', NULL, 1, 'GU', 'Thick slices of local sweet bread soaked in warm milk and egg and pan-fried until golden, a CHamoru-Spanish influenced breakfast preparation similar to French toast. Pan con leche is a childhood comfort food in Guam often sweetened with condensed milk or sugar.', TRUE),
('cinnamon_roll_guam_bakery_style_guamanian', 'Cinnamon Roll Guam Bakery Style', 345, 6.5, 55.0, 12.0, 1.5, 22.0, 120, 120, 'research', ARRAY['cinnamon roll guam bakery style', 'cinnamon bun guam', 'pan canela guam'], 'traditional', NULL, 1, 'GU', 'Large soft cinnamon rolls filled with cinnamon-sugar and drizzled with cream cheese frosting or simple icing, a popular pastry at Guam local bakeries. Guam''s bakery culture blends American-style pastries with Filipino and CHamoru sweet bread traditions.', TRUE),
('cheese_bread_pan_de_queso_guamanian', 'Cheese Bread (Pan de Queso)', 298, 9.5, 42.0, 11.5, 1.0, 8.0, 90, 90, 'research', ARRAY['cheese bread (pan de queso)', 'cheese bun guam', 'pan queso chamoru', 'cheese pandesal'], 'traditional', NULL, 1, 'GU', 'A soft sweet roll topped or filled with grated cheese, balancing savory and sweet in a single pastry, a Filipino bakery tradition deeply embedded in Guam. Cheese bread from local bakeries is eaten as a snack or light breakfast, the salty cheese offsetting the sweet enriched dough.', TRUE),
('arroz_con_leche_chamoru_rice_pudding_guamanian', 'Arroz con Leche (CHamoru Rice Pudding)', 162, 4.5, 30.0, 3.5, 0.3, 16.0, 150, NULL, 'research', ARRAY['arroz con leche (chamoru rice pudding)', 'rice pudding chamoru', 'arroz leche guam', 'sweet rice milk'], 'traditional', NULL, 1, 'GU', 'Short-grain rice cooked slowly in whole milk with cinnamon, sugar, and vanilla until thick and creamy, dusted with ground cinnamon, a Spanish-origin dessert deeply embedded in CHamoru tradition. Arroz con leche appears at nearly every CHamoru fiesta dessert spread and is a beloved comfort food.', TRUE),
('chamorro_bread_pudding_guamanian', 'Chamorro Bread Pudding', 255, 7.5, 38.0, 9.0, 0.8, 22.0, 150, NULL, 'research', ARRAY['chamorro bread pudding', 'pan pudding guam', 'chamoru bread pudding coconut'], 'traditional', NULL, 1, 'GU', 'Day-old pan Guahan or pan de sal soaked in a coconut milk-egg custard with sugar and vanilla, baked until golden and custardy, often topped with a caramel or coconut sauce. Bread pudding made from local bread reflects the CHamoru practice of using surplus bakery bread creatively.', TRUE),
('maja_blanca_coconut_cornstarch_pudding_guamanian', 'Maja Blanca (Coconut Cornstarch Pudding)', 188, 2.5, 34.0, 5.5, 1.0, 20.0, 100, NULL, 'research', ARRAY['maja blanca (coconut cornstarch pudding)', 'coconut pudding chamoru', 'maja guam', 'blancmange coconut'], 'traditional', NULL, 1, 'GU', 'A firm coconut milk pudding set with cornstarch and topped with toasted coconut or sweet corn kernels, a Spanish-Filipino dessert popular at CHamoru fiestas. Maja blanca is a classic fiesta dessert alongside leche flan and latiya, its pure white appearance making it visually striking on the dessert table.', TRUE),
('tsokolate_chamoru_hot_chocolate_guamanian', 'Tsokolate (CHamoru Hot Chocolate)', 115, 4.5, 18.5, 3.5, 2.0, 14.0, 240, NULL, 'research', ARRAY['tsokolate (chamoru hot chocolate)', 'chamoru chocolate drink', 'hot cacao chamoru', 'sikwate guam'], 'traditional', NULL, 1, 'GU', 'Thick rich hot chocolate made from cacao tablets dissolved in hot water or milk and frothed with a traditional wooden molinillo, a Spanish-influenced CHamoru morning beverage. Tsokolate is traditionally paired with pan tosta or titiyas for breakfast and remains a beloved morning ritual in CHamoru households.', TRUE),
('calamansi_juice_guamanian', 'Calamansi Juice', 22, 0.3, 5.5, 0.1, 0.2, 4.2, 240, NULL, 'research', ARRAY['calamansi juice', 'kalamansi juice', 'calamansi lemonade guam', 'philippine lime juice'], 'traditional', NULL, 1, 'GU', 'Freshly squeezed calamansi (Philippine lime) juice sweetened with sugar and diluted with water, a refreshing citrus beverage popular across Guam. Calamansi trees are commonly grown in CHamoru backyard gardens and the juice is also used as a finadene ingredient and marinade acid.', TRUE),
('coconut_water_tubig_niyok_guamanian', 'Coconut Water (Tubig Niyok)', 19, 0.7, 3.7, 0.2, 1.1, 2.6, 240, NULL, 'research', ARRAY['coconut water (tubig niyok)', 'fresh coconut water guam', 'niyok water', 'buko juice chamoru'], 'traditional', NULL, 1, 'GU', 'Fresh coconut water drunk directly from the young green niyok, the most traditional hydrating beverage in CHamoru culture. Young coconuts are commonly sold roadside and at markets across Guam, valued for hydration and electrolyte content in the tropical climate.', TRUE),
('sinanglaw_beef_innards_soup_guamanian', 'Sinanglaw (Beef Innards Soup)', 98, 12.5, 4.5, 4.0, 0.5, 1.5, 250, NULL, 'research', ARRAY['sinanglaw (beef innards soup)', 'beef innards sour soup guam', 'sinanglaw chamoru'], 'traditional', NULL, 1, 'GU', 'A sour tamarind or calamansi-based soup using beef innards, liver, and tripe simmered with ginger, onion, and lemon grass, a Filipino-CHamoru dish valued as a hangover remedy. Sinanglaw''s robust sour broth is a bold counterpoint to the milder broths typical of CHamoru cooking.', TRUE),
('ginagang_coconut_crab_curry_style_guamanian', 'Ginagang (Coconut Crab Curry Style)', 155, 14.5, 6.5, 8.5, 1.0, 2.5, 200, NULL, 'research', ARRAY['ginagang (coconut crab curry style)', 'ayuyu coconut chamoru', 'land crab coconut guam'], 'traditional', NULL, 1, 'GU', 'Coconut crab (ayuyu) or land crab simmered in coconut milk with turmeric, ginger, and lemon grass in a mild curry-style preparation. Coconut crab is the most prized land animal in CHamoru culture and its preparation is reserved for special occasions due to its protected status.', TRUE),
('kadon_pika_spicy_chicken_stew_guamanian', 'Kadon Pika (Spicy Chicken Stew)', 185, 18.5, 6.5, 9.5, 1.0, 2.5, 200, NULL, 'research', ARRAY['kadon pika (spicy chicken stew)', 'spicy coconut chicken chamoru', 'chicken kadun pika'], 'traditional', NULL, 1, 'GU', 'Chicken pieces braised in coconut milk with generous amounts of donne (bird''s eye chili) and ginger until richly spiced and tender, one of the most beloved CHamoru stews. Kadon pika is considered the flagship dish of CHamoru comfort cooking, its fiery heat tempered by the creamy coconut milk.', TRUE),
('kadon_puerko_pork_coconut_stew_guamanian', 'Kadon Puerko (Pork Coconut Stew)', 265, 18.0, 5.5, 19.5, 0.8, 2.0, 200, NULL, 'research', ARRAY['kadon puerko (pork coconut stew)', 'pork coconut stew chamoru', 'kadun puerko'], 'traditional', NULL, 1, 'GU', 'Cubed pork braised slowly in fresh coconut milk with garlic, onion, and donne pepper until the pork is meltingly tender and the sauce is thick and rich. Kadon puerko is a fixture at CHamoru fiestas and family Sunday meals, often served alongside red rice and titiyas.', TRUE),
('kelaguen_mannok_chicken_kelaguen_traditional_guamanian', 'Kelaguen Mannok (Chicken Kelaguen Traditional)', 145, 20.5, 3.5, 5.5, 0.8, 1.5, 150, NULL, 'research', ARRAY['kelaguen mannok (chicken kelaguen traditional)', 'chicken kelaguen', 'mannok kelaguen', 'kelaguen manok'], 'traditional', NULL, 1, 'GU', 'Grilled chicken finely chopped and cured in fresh lemon juice with shredded coconut, donne sali, green onion, and salt, served cold or room temperature. Kelaguen mannok is the most fundamental CHamoru dish, present at every fiesta, its acid-curing technique an ancient CHamoru food preservation method.', TRUE),
('ahu_finadene_salted_fish_preparation_guamanian', 'Ahu (Finadene Salted Fish Preparation)', 125, 22.0, 0.5, 3.8, 0.0, 0.2, 100, NULL, 'research', ARRAY['ahu (finadene salted fish preparation)', 'salted fish chamoru', 'dried fish finadene', 'titiyas accompaniment fish'], 'traditional', NULL, 1, 'GU', 'Dried or salted reef fish prepared simply with finadene sauce, one of the oldest CHamoru food preparations recorded by early European explorers. Salted and dried fish was a critical preservation method for the ancient CHamoru people who relied on reef fish as their primary protein.', TRUE),
('binakle_coconut_vinegar_condiment_guamanian', 'Binakle (Coconut Vinegar Condiment)', 15, 0.5, 3.0, 0.1, 0.2, 1.5, 30, NULL, 'research', ARRAY['binakle (coconut vinegar condiment)', 'tuba finadene', 'coconut vinegar sauce chamoru', 'finadene binakle'], 'traditional', NULL, 1, 'GU', 'A traditional CHamoru condiment of tuba vinegar (fermented coconut sap) combined with salt, sliced onion, and crushed pepper, an ancestor of modern finadene. Tuba vinegar from fermented coconut palm sap was used by CHamoru people before soy sauce was introduced by Japanese immigrants.', TRUE),
('donne_sali_birds_eye_chili_paste_guamanian', 'Donne Sali (Bird''s Eye Chili Paste)', 45, 2.0, 8.5, 0.8, 4.5, 4.0, 20, NULL, 'research', ARRAY['donne sali (bird''s eye chili paste)', 'bird eye chili paste chamoru', 'donne'' sa''li', 'chamoru hot sauce'], 'traditional', NULL, 1, 'GU', 'Raw or lightly fermented bird''s eye chili peppers (donne sali) crushed into a paste and mixed with salt, used as a table condiment to add fiery heat to any dish. Donne sali is indispensable in CHamoru cuisine, present on every dining table as the primary heat source.', TRUE),
('kelaguen_uhang_shrimp_kelaguen_guamanian', 'Kelaguen Uhang (Shrimp Kelaguen)', 95, 15.5, 3.0, 2.5, 0.5, 1.0, 150, NULL, 'research', ARRAY['kelaguen uhang (shrimp kelaguen)', 'shrimp kelaguen chamoru', 'uhang kelaguen'], 'traditional', NULL, 1, 'GU', 'Fresh shrimp briefly grilled or blanched then tossed with lemon juice, shredded coconut, donne pepper, and green onion, a seafood kelaguen. Kelaguen is an ancient CHamoru food preparation technique where acid from lemon or vinegar effectively cures raw or lightly cooked protein.', TRUE),
('agadgad_guam_boonchi_pickle_guamanian', 'Agadgad (Guam Boonchi Pickle)', 28, 1.5, 5.5, 0.2, 2.2, 2.5, 80, NULL, 'research', ARRAY['agadgad (guam boonchi pickle)', 'pickled long beans chamoru', 'boonchi pickle', 'chamoru pickles'], 'traditional', NULL, 1, 'GU', 'Pickled long beans (boonchi) or mixed vegetables preserved in cane vinegar and salt, a traditional CHamoru fermented condiment served alongside rich fiesta foods. Fermented and pickled vegetables were used by ancient CHamoru people to preserve seasonal produce and add acidic contrast to starchy meals.', TRUE),
('chamorro_egg_drop_soup_achote_guamanian', 'Chamorro Egg Drop Soup (Achote)', 88, 6.5, 5.5, 4.5, 0.5, 1.0, 250, NULL, 'research', ARRAY['chamorro egg drop soup (achote)', 'egg drop soup chamoru', 'achote egg soup'], 'traditional', NULL, 1, 'GU', 'Beaten eggs dropped into simmering achote-colored broth creating egg-drop threads in an orange-hued soup flavored with onion and garlic. A simple and economical soup that showcases the CHamoru fondness for achote as a universal coloring and mild flavoring agent.', TRUE),
('butter_mochi_chamoru_style_guamanian', 'Butter Mochi (CHamoru Style)', 285, 4.5, 48.0, 9.0, 0.5, 22.0, 100, 80, 'research', ARRAY['butter mochi (chamoru style)', 'bibingka mochi', 'chamoru mochi cake', 'baked mochi guam'], 'traditional', NULL, 1, 'GU', 'Glutinous rice flour baked with butter, eggs, coconut milk, and sugar into a dense chewy slightly crispy-edged cake, popular at CHamoru potlucks. The buttery mochi cake blends Japanese mochi tradition with American baking culture, both influences prominent in Guam''s 20th-century food history.', TRUE),
('bibingka_chamoru_rice_cake_guamanian', 'Bibingka (CHamoru Rice Cake)', 252, 5.0, 40.0, 9.5, 0.8, 18.0, 120, 120, 'research', ARRAY['bibingka (chamoru rice cake)', 'rice cake guam', 'chamoru bibingka', 'coconut rice cake'], 'traditional', NULL, 1, 'GU', 'A baked or steamed rice flour cake with coconut milk, eggs, and sugar, topped with salted egg slices and fresh grated coconut. Filipino-origin bibingka is widely made in CHamoru households for Christmas season and fiestas, representing the strong Filipino cultural influence on Guam''s food traditions.', TRUE),
('kalamay_sweet_sticky_rice_confection_guamanian', 'Kalamay (Sweet Sticky Rice Confection)', 285, 3.5, 55.0, 7.0, 1.2, 28.0, 100, NULL, 'research', ARRAY['kalamay (sweet sticky rice confection)', 'sticky rice sweet chamoru', 'kalamay guam'], 'traditional', NULL, 1, 'GU', 'Glutinous rice flour cooked with coconut milk and brown sugar into a thick sticky confection, poured into banana leaf-lined trays and cut into squares when set. Kalamay is a beloved merienda snack and dessert in Guam with roots in Filipino and Spanish confectionery traditions.', TRUE),
('chamorro_cooked_saba_banana_chotda_guisada_guamanian', 'Chamorro Cooked Saba Banana (Chotda Guisada)', 122, 1.0, 30.0, 2.5, 2.5, 16.0, 150, NULL, 'research', ARRAY['chamorro cooked saba banana (chotda guisada)', 'fried banana guam', 'chotda dulce', 'sweet banana chamoru'], 'traditional', NULL, 1, 'GU', 'Ripe saba or plantain bananas cooked in butter and brown sugar until caramelized and golden, a traditional sweet side dish or dessert. Bananas (chotda) have been cultivated in Guam since ancient times and the saba variety is particularly valued for cooking due to its starchy sweetness.', TRUE),
('dulce_de_coco_coconut_candy_balls_guamanian', 'Dulce de Coco (Coconut Candy Balls)', 345, 2.8, 52.0, 15.0, 3.5, 45.0, 50, 12, 'research', ARRAY['dulce de coco (coconut candy balls)', 'coconut balls chamoru', 'coco candy guam', 'coconut fudge chamoru'], 'traditional', NULL, 1, 'GU', 'Freshly grated coconut cooked with sugar, condensed milk, and sometimes chocolate into a thick fudge-like paste, rolled into balls and allowed to set. Dulce de coco is a traditional CHamoru sweet served at fiestas and homemade as holiday gifts, representing the island''s affinity for coconut-based confections.', TRUE),
('niyok_malanao_fermented_coconut_cream_guamanian', 'Niyok Malanao (Fermented Coconut Cream)', 168, 1.8, 4.5, 17.0, 0.5, 3.0, 60, NULL, 'research', ARRAY['niyok malanao (fermented coconut cream)', 'soured coconut cream chamoru', 'fermented niyok'], 'traditional', NULL, 1, 'GU', 'Slightly aged coconut cream left to ferment briefly until pleasantly sour and rich, used as a flavoring agent in CHamoru cooking. This controlled fermentation of coconut cream adds a complex tangy note to dishes and reflects ancient CHamoru food preservation techniques using coconut.', TRUE),
('ahu_estufao_fish_estufao_guamanian', 'Ahu Estufao (Fish Estufao)', 138, 18.5, 5.5, 4.5, 0.5, 2.0, 200, NULL, 'research', ARRAY['ahu estufao (fish estufao)', 'fish estufao chamoru', 'reef fish braised chamoru'], 'traditional', NULL, 1, 'GU', 'Whole small reef fish braised in soy sauce, vinegar, garlic, onion, and achote until the liquid reduces to a sticky glaze coating the fish. Fish estufao applies the classic CHamoru braising technique to local reef species, creating a intensely flavored dish eaten over red rice.', TRUE),
('tinomok_chamoru_stuffed_banana_leaves_guamanian', 'Tinomok (CHamoru Stuffed Banana Leaves)', 145, 7.5, 18.0, 5.5, 2.0, 2.5, 150, 150, 'research', ARRAY['tinomok (chamoru stuffed banana leaves)', 'chamoru banana leaf wrap', 'tinomok fish', 'stuffed leaf chamoru'], 'traditional', NULL, 1, 'GU', 'Seasoned ground fish or pork mixed with coconut cream wrapped in banana leaves and steamed until the filling sets into a tender cake. Tinomok is an ancient CHamoru cooking method using banana leaves as cooking vessels, creating a portable and self-contained meal.', TRUE),
('chenchule_rice_dish_guamanian', 'Chenchule Rice Dish', 195, 5.5, 38.5, 3.5, 1.2, 1.5, 200, NULL, 'research', ARRAY['chenchule rice dish', 'chenchule food gift', 'chamoru reciprocal rice'], 'traditional', NULL, 1, 'GU', 'A gift rice dish traditionally contributed by community members to CHamoru life events such as funerals, baptisms, and fiestas as part of the chenchule reciprocal gift-giving system. Chenchule is a central pillar of CHamoru social culture where community members exchange food and labor to support each other through major life events.', TRUE),
('guam_spam_musubi_guamanian', 'Guam Spam Musubi', 178, 7.5, 28.5, 4.5, 0.5, 2.5, 150, 120, 'research', ARRAY['guam spam musubi', 'spam musubi guam', 'chamoru musubi', 'rice spam nori guam'], 'traditional', NULL, 1, 'GU', 'A rectangle of sushi rice topped with a teriyaki-glazed Spam slice wrapped in nori seaweed, a Japanese-American fusion snack that became one of Guam''s most popular convenience store foods. The Spam musubi reflects Guam''s unique position as a crossroads of American, Japanese, and Pacific Island food cultures.', TRUE),
('finadenne_achote_marinade_guamanian', 'Fina''denne Achote Marinade', 25, 1.0, 4.0, 0.5, 0.5, 2.0, 30, NULL, 'research', ARRAY['fina''denne achote marinade', 'chamoru bbq marinade', 'achote finadene marinade', 'guam bbq sauce'], 'traditional', NULL, 1, 'GU', 'A cooking marinade of achote seeds steeped in soy sauce, lemon, garlic, and vinegar used to coat meats before grilling, the base flavor profile of CHamoru BBQ. This marinade is arguably the most recognizable flavor of CHamoru cuisine, imparting both the characteristic orange color and complex sweet-sour-salty taste.', TRUE),
('coconut_tuba_fermented_palm_wine_guamanian', 'Coconut Tuba (Fermented Palm Wine)', 48, 0.5, 4.5, 0.1, 0.0, 4.2, 240, NULL, 'research', ARRAY['coconut tuba (fermented palm wine)', 'tuba chamoru', 'coconut wine guam', 'palm toddy chamoru'], 'traditional', NULL, 1, 'GU', 'Freshly tapped coconut palm sap (tuba) lightly fermented into a mildly alcoholic beverage with a sweet-sour effervescent taste, traditionally consumed at CHamoru celebrations. Tuba tapping was practiced by ancient CHamoru people and Filipino immigrants who brought the technique, providing both a drink and the basis for tuba vinegar used in finadene.', TRUE),
('kalamungay_fritters_moringa_fritters_guamanian', 'Kalamungay Fritters (Moringa Fritters)', 175, 5.5, 22.0, 7.5, 2.5, 1.5, 100, 25, 'research', ARRAY['kalamungay fritters (moringa fritters)', 'malunggay fritters guam', 'moringa pakora chamoru'], 'traditional', NULL, 1, 'GU', 'Moringa (malunggay) leaves and pods mixed into a seasoned batter and deep-fried into crispy fritters, a creative way to incorporate the nutrient-dense tree into everyday snacks. Moringa fritters are sold at local markets and fairs as a healthy-leaning street snack.', TRUE),
('jackfruit_adobo_langka_adobo_guamanian', 'Jackfruit Adobo (Langka Adobo)', 82, 1.5, 16.5, 2.0, 2.8, 8.5, 200, NULL, 'research', ARRAY['jackfruit adobo (langka adobo)', 'young jackfruit adobo guam', 'langka guisado chamoru'], 'traditional', NULL, 1, 'GU', 'Young unripe jackfruit (langka) cut into chunks and braised in vinegar, soy sauce, garlic, and bay leaf, absorbing the adobo flavors while remaining meaty in texture. Jackfruit adobo is a popular vegetarian-friendly dish in Guam given that jackfruit trees grow prolifically across the island.', TRUE),
('pandanus_leaf_infused_rice_guamanian', 'Pandanus Leaf Infused Rice', 165, 3.0, 36.0, 0.5, 0.5, 0.3, 200, NULL, 'research', ARRAY['pandanus leaf infused rice', 'pandan rice guam', 'pandanus rice chamoru'], 'traditional', NULL, 1, 'GU', 'Plain white rice cooked with pandan (pandanus) leaves tied in a knot placed in the cooking water, imparting a subtle sweet floral aroma. Pandan grows abundantly across Guam and its leaves are used to perfume rice, desserts, and beverages in CHamoru and Filipino-influenced cooking.', TRUE),
('chamorro_vegetable_salad_with_crab_guamanian', 'Chamorro Vegetable Salad with Crab', 88, 8.5, 7.5, 3.0, 2.0, 3.5, 150, NULL, 'research', ARRAY['chamorro vegetable salad with crab', 'crab vegetable salad chamoru', 'ensalada alimasag'], 'traditional', NULL, 1, 'GU', 'Flaked fresh crab meat tossed with cucumber, tomato, onion, and a light lemon-soy dressing, a refreshing seafood salad. Fresh crab is abundantly available from Guam''s coastal waters and this simple salad showcases the clean flavor of local crab without heavy seasonings.', TRUE),
('guyuria_chamoru_coconut_cookies_guamanian', 'Guyuria (CHamoru Coconut Cookies)', 398, 4.5, 58.0, 18.0, 1.5, 20.0, 60, 8, 'research', ARRAY['guyuria (chamoru coconut cookies)', 'chamoru coconut rings', 'guyuria cookies', 'fiesta cookies guam'], 'traditional', NULL, 1, 'GU', 'Hard crunchy ring-shaped cookies made from flour, coconut milk, sugar, and lard, deep-fried until golden, one of the most iconic CHamoru sweets. Guyuria are prepared in large quantities for fiestas and given as gifts, the rings symbolizing unity and celebration in CHamoru culture.', TRUE),
('rosquillos_chamoru_ring_biscuits_guamanian', 'Rosquillos (CHamoru Ring Biscuits)', 368, 5.5, 55.0, 15.0, 1.0, 18.0, 60, 15, 'research', ARRAY['rosquillos (chamoru ring biscuits)', 'chamoru ring biscuits', 'rosquillas guam', 'baked ring cookie chamoru'], 'traditional', NULL, 1, 'GU', 'Baked ring-shaped butter biscuits with a crisp exterior and tender crumb, similar to Spanish rosquillas and sold at Guam bakeries as a classic merienda biscuit. Rosquillos reflect the Spanish colonial baking tradition that took root in Guam and remains visible in the island''s bakery culture today.', TRUE),
('kutsinta_brown_rice_cake_guamanian', 'Kutsinta (Brown Rice Cake)', 175, 2.0, 38.5, 1.5, 0.5, 18.0, 80, 30, 'research', ARRAY['kutsinta (brown rice cake)', 'brown sticky rice cake guam', 'kutsinta chamoru'], 'traditional', NULL, 1, 'GU', 'Steamed sticky brown rice cake made with rice flour, brown sugar, lye water, and annatto for color, topped with grated coconut. Kutsinta is a Filipino-origin kakanin (rice snack) popular at Guam''s local markets and merienda stalls, its chewy jelly-like texture making it distinctive among rice cakes.', TRUE),
('sapin_sapin_layered_rice_cake_guamanian', 'Sapin-Sapin (Layered Rice Cake)', 215, 3.0, 42.0, 5.0, 1.0, 22.0, 100, NULL, 'research', ARRAY['sapin-sapin (layered rice cake)', 'layered coconut rice cake guam', 'tri-color rice cake chamoru'], 'traditional', NULL, 1, 'GU', 'A layered steamed cake of glutinous rice flour and coconut milk with each layer colored differently using ube, jackfruit, and plain coconut, creating a visually striking tricolor dessert. Sapin-sapin is a celebration rice cake common at Guam''s Filipino-CHamoru fiestas.', TRUE),
('chamorro_sweet_potato_soup_guamanian', 'Chamorro Sweet Potato Soup', 95, 2.2, 19.5, 1.8, 2.5, 6.5, 250, NULL, 'research', ARRAY['chamorro sweet potato soup', 'kamuti soup chamoru', 'sweet potato coconut soup guam'], 'traditional', NULL, 1, 'GU', 'Cubed sweet potato (kamuti) simmered in coconut milk with ginger and onion until soft and fragrant, a naturally sweet and nourishing soup. Sweet potatoes have been grown in Guam since pre-contact times and this simple soup bridges ancient staple ingredients with coconut milk cooking techniques.', TRUE),
('chamorro_cooked_banana_blossom_guamanian', 'Chamorro Cooked Banana Blossom', 48, 1.8, 9.0, 0.6, 2.8, 2.5, 200, NULL, 'research', ARRAY['chamorro cooked banana blossom', 'banana heart saute chamoru', 'puso ng saging guisado guam'], 'traditional', NULL, 1, 'GU', 'Banana blossom (puso ng saging) outer petals removed, inner florets braised in coconut milk or stir-fried with garlic and shrimp paste until tender. The banana blossom''s meaty texture makes it a popular vegetable and meat substitute preparation across Guam''s Filipino-CHamoru kitchens.', TRUE),
('taro_corm_chips_suni_chips_thick_cut_guamanian', 'Taro Corm Chips (Suni Chips Thick Cut)', 355, 3.5, 55.0, 14.5, 5.5, 1.2, 50, NULL, 'research', ARRAY['taro corm chips (suni chips thick cut)', 'thick taro fries chamoru', 'suni thick chips'], 'traditional', NULL, 1, 'GU', 'Thick-cut taro corm slices deep-fried until crispy outside and fluffy inside, a heartier version of taro chips popular as a side dish substitute for french fries. Locally grown taro chips are a point of cultural pride in Guam''s food scene and are increasingly available at restaurants.', TRUE),
('guam_style_macaroni_soup_guamanian', 'Guam Style Macaroni Soup', 118, 5.5, 18.5, 3.5, 1.0, 2.5, 250, NULL, 'research', ARRAY['guam style macaroni soup', 'sopas macaroni chamoru', 'noodle soup guam style', 'macaroni sopas'], 'traditional', NULL, 1, 'GU', 'Elbow macaroni in a savory chicken broth with vegetables, hot dogs or Vienna sausage, and evaporated milk, a comforting CHamoru soup eaten as a light meal. Macaroni soup is a childhood staple in CHamoru households, frequently prepared for school mornings and rainy-day meals.', TRUE),
('kamaboko_fish_cake_guam_style_guamanian', 'Kamaboko (Fish Cake Guam Style)', 95, 12.5, 9.5, 1.5, 0.2, 2.0, 100, NULL, 'research', ARRAY['kamaboko (fish cake guam style)', 'fish cake chamoru', 'narutomaki guam', 'japanese fish cake guam'], 'traditional', NULL, 1, 'GU', 'Processed fish cake loaf of Japanese origin sold in pink-and-white half-cylinders, a common ingredient in CHamoru noodle soups and fried rice. Japanese kamaboko became a pantry staple in Guam during and after the Japanese occupation and remains a widely used processed seafood ingredient.', TRUE),
('pickled_cucumber_with_soy_ensaladang_pipino_soy_guamanian', 'Pickled Cucumber with Soy (Ensaladang Pipino Soy)', 22, 0.8, 4.0, 0.2, 0.5, 2.5, 100, NULL, 'research', ARRAY['pickled cucumber with soy (ensaladang pipino soy)', 'soy pickled cucumber guam', 'quick pickle chamoru', 'pipino soy salad'], 'traditional', NULL, 1, 'GU', 'Sliced cucumber lightly pickled in soy sauce, rice vinegar, sesame oil, and crushed garlic, a quick-pickle condiment served alongside grilled meats. This preparation combines Japanese soy and sesame influences with the CHamoru love of bright, acidic condiments.', TRUE),
('chamorro_mango_pudding_guamanian', 'Chamorro Mango Pudding', 145, 3.5, 28.0, 3.0, 1.0, 22.0, 120, NULL, 'research', ARRAY['chamorro mango pudding', 'mango gelatin chamoru', 'mango pudding guam', 'mango jelly chamoru'], 'traditional', NULL, 1, 'GU', 'Fresh ripe mango pureed with gelatin, condensed milk, and coconut milk then chilled until set into a smooth pudding, a popular homemade dessert in Guam. Local Philippine and Carabao mangoes grown across Guam are sweet and aromatic, making mango pudding a naturally vibrant dessert.', TRUE),
('taro_ice_cream_suni_ice_cream_guamanian', 'Taro Ice Cream (Suni Ice Cream)', 195, 3.5, 28.0, 8.5, 1.0, 18.0, 100, NULL, 'research', ARRAY['taro ice cream (suni ice cream)', 'suni ice cream', 'taro flavor ice cream guam'], 'traditional', NULL, 1, 'GU', 'Creamy ice cream flavored with cooked taro puree giving it a pale purple hue and subtly earthy-sweet flavor, sold at local Guam ice cream shops and markets. Taro ice cream represents a modern adaptation of the ancient CHamoru taro crop into contemporary dessert formats popular with both locals and tourists.', TRUE),
('coconut_ice_cream_niyok_ice_cream_guamanian', 'Coconut Ice Cream (Niyok Ice Cream)', 205, 2.8, 24.0, 12.0, 1.5, 20.0, 100, NULL, 'research', ARRAY['coconut ice cream (niyok ice cream)', 'niyok ice cream guam', 'coconut gelato chamoru', 'fresh coconut ice cream'], 'traditional', NULL, 1, 'GU', 'Rich creamy ice cream made with fresh coconut milk and shredded coconut, a natural flavor that reflects the island''s primary crop. Coconut ice cream is widely available at local shops and roadside stands in Guam, sometimes served inside a young coconut shell for presentation.', TRUE),
('ube_ice_cream_guamanian', 'Ube Ice Cream', 188, 3.2, 26.5, 8.0, 1.2, 18.5, 100, NULL, 'research', ARRAY['ube ice cream', 'purple yam ice cream guam', 'ube gelato chamoru'], 'traditional', NULL, 1, 'GU', 'Vivid purple ice cream made with ube (purple yam) extract or puree, producing a striking violet color and sweet earthy flavor. Ube ice cream is one of the most visually recognizable Filipino-CHamoru foods and has become internationally popular, with Guam''s local shops among the earliest adopters.', TRUE),
('buko_pandan_coconut_pandan_dessert_guamanian', 'Buko Pandan (Coconut Pandan Dessert)', 165, 2.5, 28.0, 5.5, 1.5, 20.0, 150, NULL, 'research', ARRAY['buko pandan (coconut pandan dessert)', 'coconut pandan salad chamoru', 'buko pandan guam'], 'traditional', NULL, 1, 'GU', 'Strips of young coconut (buko) tossed with pandan-flavored gelatin cubes, cream, condensed milk, and coconut cream, served chilled as a dessert salad. Buko pandan is a beloved Filipino dessert deeply embedded in Guam''s food culture, its green and white colors making it a visually appealing fiesta dessert.', TRUE),
('fruit_salad_filipino_chamoru_style_guamanian', 'Fruit Salad Filipino-CHamoru Style', 145, 3.0, 26.0, 5.0, 1.5, 20.5, 150, NULL, 'research', ARRAY['fruit salad filipino-chamoru style', 'creamy fruit salad guam', 'fiesta fruit salad chamoru'], 'traditional', NULL, 1, 'GU', 'Canned fruit cocktail mixed with cream cheese, condensed milk, nata de coco, and kaong (sugar palm fruit), a rich and sweet Filipino-origin dessert fixture at CHamoru fiestas. This creamy fruit salad is one of the most anticipated fiesta desserts and is prepared in large quantities for community gatherings.', TRUE),
('halo_halo_mixed_shaved_ice_dessert_guamanian', 'Halo-Halo (Mixed Shaved Ice Dessert)', 185, 4.5, 38.0, 4.0, 1.5, 28.0, 300, NULL, 'research', ARRAY['halo-halo (mixed shaved ice dessert)', 'mix-mix dessert guam', 'halo halo chamoru', 'shaved ice filipino guam'], 'traditional', NULL, 1, 'GU', 'Shaved ice layered with sweetened beans, coconut jelly, leche flan, ube halaya, jackfruit, and evaporated milk, a Filipino-origin summer dessert extremely popular in Guam. Halo-halo (meaning mix-mix) is a beloved treat at Guam''s local halo-halo shops and is eaten year-round given the tropical climate.', TRUE),
('ginatan_sweet_coconut_milk_dessert_soup_guamanian', 'Ginatan (Sweet Coconut Milk Dessert Soup)', 155, 2.5, 28.5, 5.5, 2.5, 16.0, 250, NULL, 'research', ARRAY['ginatan (sweet coconut milk dessert soup)', 'ginataan bilo-bilo guam', 'sweet coconut soup chamoru', 'binignit chamoru'], 'traditional', NULL, 1, 'GU', 'A warm sweet soup of coconut milk with chunks of sweet potato, taro, saba banana, jackfruit, and bilo-bilo (glutinous rice balls), served as a dessert or snack. Ginatan is a Filipino-origin dessert deeply woven into CHamoru snack culture, particularly popular during cold rainy evenings.', TRUE),
('chamorro_garlic_butter_corn_guamanian', 'Chamorro Garlic Butter Corn', 128, 3.8, 22.5, 4.5, 2.5, 5.0, 150, NULL, 'research', ARRAY['chamorro garlic butter corn', 'garlic corn guam', 'mais guisado chamoru', 'soy garlic corn'], 'traditional', NULL, 1, 'GU', 'Fresh corn kernels sauteed in garlic butter with a splash of soy sauce and green onion, a popular side dish at CHamoru family cookouts. The combination of garlic, butter, and soy creates a savory-umami flavored corn that pairs naturally with CHamoru grilled meats.', TRUE),
('spinach_and_taro_leaf_stir_fry_guamanian', 'Spinach and Taro Leaf Stir-Fry', 55, 3.5, 6.0, 2.0, 2.8, 1.5, 150, NULL, 'research', ARRAY['spinach and taro leaf stir-fry', 'mixed greens chamoru', 'spinach taro stir fry guam'], 'traditional', NULL, 1, 'GU', 'A mix of fresh spinach and young taro leaves stir-fried with garlic, onion, and coconut oil until wilted and tender, a nutrient-dense vegetable side. Combining two leafy greens is a practical CHamoru home cooking approach that maximizes the use of garden-grown vegetables.', TRUE),
('long_bean_and_pork_adobo_guamanian', 'Long Bean and Pork Adobo', 115, 9.5, 8.5, 5.5, 3.0, 2.5, 200, NULL, 'research', ARRAY['long bean and pork adobo', 'sitaw at baboy adobo', 'long bean pork guam', 'boonchi adobo chamoru'], 'traditional', NULL, 1, 'GU', 'Yard-long beans (sitaw) cut into segments and braised with diced pork in vinegar, soy sauce, garlic, and peppercorns in the classic adobo style. Long bean adobo is a hearty vegetable-meat combined dish that serves as both vegetable and protein component in a CHamoru meal.', TRUE),
('chamorro_coconut_vinegar_dressing_guamanian', 'Chamorro Coconut Vinegar Dressing', 18, 0.2, 3.5, 0.2, 0.0, 2.5, 30, NULL, 'research', ARRAY['chamorro coconut vinegar dressing', 'tuba vinegar dressing', 'coconut vinegar chamoru'], 'traditional', NULL, 1, 'GU', 'Tuba coconut vinegar sweetened lightly with sugar and seasoned with salt and donne chili, used as a salad dressing and dipping sauce for fried foods. Coconut vinegar from Guam''s local tuba is sharper and more aromatic than cane or rice vinegar, imparting a distinctly tropical tang.', TRUE),
('chamorro_onion_and_tomato_achote_side_guamanian', 'Chamorro Onion and Tomato Achote Side', 42, 1.2, 8.5, 0.8, 2.0, 5.0, 150, NULL, 'research', ARRAY['chamorro onion and tomato achote side', 'achote tomato side chamoru', 'onion tomato guisado guam'], 'traditional', NULL, 1, 'GU', 'Sliced onions and tomatoes sauteed briefly in achote oil with garlic and salt, served warm as a simple vegetable side that doubles as a sauce for rice. The achote oil gives the vegetables a vivid orange color and mild earthy flavor characteristic of CHamoru everyday cooking.', TRUE),
('papaya_in_coconut_milk_papaya_ginata_guamanian', 'Papaya in Coconut Milk (Papaya Ginata)', 82, 1.5, 14.5, 3.5, 2.0, 9.5, 200, NULL, 'research', ARRAY['papaya in coconut milk (papaya ginata)', 'papaya coconut guam', 'ginataang papaya chamoru'], 'traditional', NULL, 1, 'GU', 'Semi-ripe papaya cubes simmered in coconut milk with a pinch of salt and shrimp paste until tender and creamy, a simple vegetable preparation common in CHamoru households. The semi-ripe papaya retains texture while absorbing the rich coconut milk, creating a gentle balance of sweet and savory.', TRUE),
('chamorro_sweet_corn_cake_guamanian', 'Chamorro Sweet Corn Cake', 245, 4.5, 40.0, 8.5, 2.0, 18.0, 100, 80, 'research', ARRAY['chamorro sweet corn cake', 'mais cake chamoru', 'cornbread guam style', 'sweet corn bread chamoru'], 'traditional', NULL, 1, 'GU', 'A moist baked cake made with creamed corn, cornmeal, butter, eggs, and a touch of sugar, producing a dense tender cake eaten as a snack or side. Sweet corn cake draws on the CHamoru cultural significance of corn (mais) while applying American-influenced baking techniques.', TRUE),
('chamorro_scrambled_eggs_with_vegetables_guamanian', 'Chamorro Scrambled Eggs with Vegetables', 138, 9.5, 6.5, 9.0, 1.5, 2.5, 150, NULL, 'research', ARRAY['chamorro scrambled eggs with vegetables', 'egg vegetable scramble guam', 'torta gulay chamoru'], 'traditional', NULL, 1, 'GU', 'Eggs scrambled with diced tomato, onion, bell pepper, and green onion in a lightly oiled pan, a versatile breakfast or quick dinner preparation. This vegetable scramble is a common weekday breakfast in CHamoru households before a plate of rice and finadene.', TRUE),
('chamorro_pandan_cake_guamanian', 'Chamorro Pandan Cake', 285, 5.5, 44.0, 11.0, 0.8, 24.0, 100, NULL, 'research', ARRAY['chamorro pandan cake', 'pandan chiffon cake guam', 'green pandan cake chamoru'], 'traditional', NULL, 1, 'GU', 'A soft chiffon-style cake flavored and colored with fresh pandan leaf juice and topped with coconut cream frosting, a popular festive cake in Guam. Pandan cake represents the Japanese-Filipino influence on Guam''s baking culture and is a common birthday and celebration cake at CHamoru gatherings.', TRUE),
('pancit_palabok_guam_style_guamanian', 'Pancit Palabok Guam Style', 165, 8.5, 28.0, 4.0, 1.5, 3.0, 200, NULL, 'research', ARRAY['pancit palabok guam style', 'palabok guam style', 'orange noodle chamoru', 'pancit palabok chamoru'], 'traditional', NULL, 1, 'GU', 'Rice noodles topped with a rich shrimp-based orange sauce, hard-boiled egg, tinapa flakes, pork crackling, green onion, and calamansi. Palabok is a popular Filipino-CHamoru fiesta noodle dish distinguished by its bright orange shrimp sauce, often served alongside pancit bihon at major celebrations.', TRUE),
('chamoru_avocado_salad_guamanian', 'CHamoru Avocado Salad', 95, 1.5, 8.5, 7.5, 4.5, 2.5, 150, NULL, 'research', ARRAY['chamoru avocado salad', 'abokado salad chamoru', 'avocado finadene salad'], 'traditional', NULL, 1, 'GU', 'Ripe avocado cubed and tossed with diced onion, tomato, calamansi juice, salt, and donne pepper, a simple tropical salad reflecting Guam''s fruit abundance. Avocado trees grow throughout Guam and ripe avocados are eaten in both sweet preparations with milk and sugar and savory salads.', TRUE),
('chamorro_steamed_cassava_cake_pichi_pichi_guamanian', 'Chamorro Steamed Cassava Cake (Pichi-Pichi)', 165, 1.5, 38.0, 1.5, 1.5, 18.0, 80, 30, 'research', ARRAY['chamorro steamed cassava cake (pichi-pichi)', 'cassava pichi pichi guam', 'steamed cassava sweet chamoru'], 'traditional', NULL, 1, 'GU', 'Steamed grated cassava cakes sweetened with sugar and flavored with pandan or coconut, rolled in grated coconut when served. Pichi-pichi is a Filipino-origin cassava sweet embedded in Guam''s kakanin culture and sold at local markets and fiesta stalls alongside other sticky rice treats.', TRUE),
('chamorro_fried_tofu_with_finadene_guamanian', 'Chamorro Fried Tofu with Finadene', 135, 10.5, 5.5, 8.5, 0.5, 1.5, 150, NULL, 'research', ARRAY['chamorro fried tofu with finadene', 'fried tofu finadene guam', 'tokwa chamoru style'], 'traditional', NULL, 1, 'GU', 'Firm tofu cut into cubes and pan-fried until golden crispy on the outside, served with a finadene dipping sauce of soy sauce, lemon, and donne chili. Fried tofu with finadene is a popular vegetarian protein option at CHamoru households influenced by Filipino and Japanese tofu-eating traditions.', TRUE),
('coconut_biko_sticky_rice_cake_guamanian', 'Coconut Biko (Sticky Rice Cake)', 265, 3.5, 50.0, 7.0, 1.5, 25.0, 100, NULL, 'research', ARRAY['coconut biko (sticky rice cake)', 'biko guam', 'sticky rice cake coconut chamoru', 'kakanin biko'], 'traditional', NULL, 1, 'GU', 'Glutinous rice cooked in coconut milk and brown sugar until sticky, spread into a pan and topped with latik (coconut caramel curds) before cooling and cutting into squares. Biko is one of the most popular Filipino-origin rice cakes in Guam and appears at virtually every CHamoru fiesta dessert table.', TRUE),
('chamorro_okra_stir_fry_with_egg_guamanian', 'Chamorro Okra Stir-Fry with Egg', 62, 4.5, 7.0, 2.5, 3.0, 2.2, 150, NULL, 'research', ARRAY['chamorro okra stir-fry with egg', 'okra egg saute chamoru', 'okra torta guam'], 'traditional', NULL, 1, 'GU', 'Sliced okra stir-fried with beaten eggs and garlic until the egg is just set and the okra is bright green and tender, a quick and nourishing side dish. Okra with egg is an economical everyday vegetable dish in CHamoru households that can be prepared in under ten minutes using garden-grown okra.', TRUE),
('guam_achote_oil_guamanian', 'Guam Achote Oil', 120, 0.0, 0.5, 13.5, 0.2, 0.0, 15, NULL, 'research', ARRAY['guam achote oil', 'annatto oil chamoru', 'atsuete oil guam', 'achote cooking oil'], 'traditional', NULL, 1, 'GU', 'Neutral cooking oil (canola or coconut) infused by gently heating with annatto seeds until vivid orange, the foundation fat used in CHamoru cooking for color and flavor. Achote oil is prepared in batches in CHamoru kitchens and used as the cooking fat for red rice, tamales, and braised meats.', TRUE),
('chamorro_pineapple_and_cucumber_salad_guamanian', 'Chamorro Pineapple and Cucumber Salad', 42, 0.8, 10.0, 0.2, 1.2, 7.5, 150, NULL, 'research', ARRAY['chamorro pineapple and cucumber salad', 'pineapple cucumber salad guam', 'tropical fruit salad chamoru'], 'traditional', NULL, 1, 'GU', 'Cubed fresh pineapple and sliced cucumber tossed with a light dressing of calamansi juice, salt, and a pinch of donne chili, a refreshing tropical salad. Pineapples are grown commercially in Guam and this sweet-tart salad is a cooling accompaniment to the rich, spicy dishes of a CHamoru fiesta.', TRUE),
('chamorro_tapioca_pudding_mendioka_puding_guamanian', 'Chamorro Tapioca Pudding (Mendi''oka Puding)', 148, 2.5, 30.0, 3.0, 0.5, 16.0, 150, NULL, 'research', ARRAY['chamorro tapioca pudding (mendi''oka puding)', 'tapioca coconut pudding chamoru', 'mañihok pudding guam', 'sago pudding guam'], 'traditional', NULL, 1, 'GU', 'Small tapioca pearls cooked in coconut milk and sugar until translucent and creamy, served warm or chilled as a comforting dessert. Tapioca (from cassava starch) has deep CHamoru roots given that cassava (mañihok) was introduced to Guam via the Galleon trade and became a widely cultivated crop.', TRUE),
('latiya_chamoru_custard_cake_guamanian', 'Latiya (CHamoru Custard Cake)', 280, 5.5, 42.0, 10.0, 0.3, 28.0, 120, 120, 'research', ARRAY['latiya (chamoru custard cake)', 'natiya', 'latiha', 'chamoru custard cake', 'fina''mames latiya'], 'dessert', NULL, 1, 'GU', 'Guam''s most beloved dessert, a vanilla sponge cake topped with creamy custard and dusted with cinnamon; descended from Spanish natillas custard introduced during the colonial era.', TRUE),
('bunelos_dagu_taro_yam_donuts_guamanian', 'Buñelos Dågu (Taro/Yam Donuts)', 310, 4.0, 44.0, 13.0, 2.0, 10.0, 80, 40, 'research', ARRAY['buñelos dågu (taro/yam donuts)', 'bonelos dago', 'bonelos dagu', 'buñelos dago', 'yam donuts'], 'street_food', NULL, 1, 'GU', 'Traditional CHamoru fried donuts made from grated dågu (yam or taro), flour, and sugar; strongly associated with Christmas celebrations and holiday gatherings on Guam.', TRUE),
('bunelos_aga_banana_fritters_guamanian', 'Buñelos Åga (Banana Fritters)', 290, 3.5, 45.0, 11.0, 1.5, 18.0, 80, 35, 'research', ARRAY['buñelos åga (banana fritters)', 'buñuelos aga', 'bonelos aga', 'banana donuts', 'mado''ya'], 'street_food', NULL, 1, 'GU', 'Fried dough balls made from mashed ripe bananas, flour, and baking powder; a popular CHamoru snack and dessert served at fiestas and roadside stands across Guam.', TRUE),
('bunelos_manglo_air_donuts_guamanian', 'Buñelos Månglo (Air Donuts)', 330, 4.5, 48.0, 14.0, 0.8, 12.0, 70, 35, 'research', ARRAY['buñelos månglo (air donuts)', 'bonelos manglo', 'typhoon donuts', 'air donuts', 'buñuelos manglo'], 'street_food', NULL, 1, 'GU', 'CHamoru fried dough fritters made with coconut milk and flour, called ''air donuts'' or ''typhoon donuts''; a comfort food traditionally eaten during stormy or cool weather on Guam.', TRUE),
('bunelos_lemmai_breadfruit_fritters_guamanian', 'Buñelos Lemmai (Breadfruit Fritters)', 295, 3.0, 47.0, 12.0, 2.5, 8.0, 80, 40, 'research', ARRAY['buñelos lemmai (breadfruit fritters)', 'bonelos lemmai', 'breadfruit donuts', 'lemmai fritters'], 'street_food', NULL, 1, 'GU', 'Fried fritters made from mashed breadfruit (lemmai) mixed with flour and coconut milk; breadfruit has been a staple CHamoru food for centuries, described by early Spanish missionaries.', TRUE),
('bunelos_uhang_shrimp_fritters_guamanian', 'Buñelos Uhang (Shrimp Fritters)', 245, 12.0, 22.0, 12.0, 0.8, 1.5, 100, 45, 'research', ARRAY['buñelos uhang (shrimp fritters)', 'bonelos uhang', 'shrimp patties', 'chamoru shrimp fritters'], 'street_food', NULL, 1, 'GU', 'Deep-fried shrimp and vegetable patties adapted from American fritters; a festive CHamoru snack made with shrimp, evaporated milk, eggs, onions, and green beans.', TRUE),
('empanada_chamorra_fried_achote_pastry_guamanian', 'Empanåda CHamorra (Fried Achote Pastry)', 305, 9.5, 38.0, 13.0, 1.5, 2.0, 110, 110, 'research', ARRAY['empanåda chamorra (fried achote pastry)', 'empanada chamorra', 'chamoru empanada', 'achote empanada', 'fiesta empanada'], 'street_food', NULL, 1, 'GU', 'Distinctive orange-hued deep-fried pastry made with achote-colored masa dough, filled with seasoned ground meat, onion, and garlic; a CHamoru fiesta staple with Spanish-Mexican origins via the Manila Galleon trade.', TRUE),
('spam_musubi_guam_style_guamanian', 'Spam Musubi Guam Style', 205, 6.5, 33.0, 6.0, 0.5, 2.5, 130, 130, 'research', ARRAY['spam musubi guam style', 'spam onigiri', 'musubi', 'guam musubi'], 'street_food', NULL, 1, 'GU', 'Rice block topped with a slice of grilled Spam and wrapped in nori seaweed; a ubiquitous Guam convenience store and street food snack reflecting the deep post-WWII American military influence on the island.', TRUE),
('rosketti_chamoru_shortbread_cookies_guamanian', 'Rosketti (CHamoru Shortbread Cookies)', 450, 5.0, 65.0, 18.5, 0.5, 20.0, 40, 15, 'research', ARRAY['rosketti (chamoru shortbread cookies)', 'roskette', 'rosquetti', 'chamoru shortbread', 'cornstarch cookies'], 'dessert', NULL, 1, 'GU', 'Crumbly CHamoru shortbread-style cookies made primarily with cornstarch, flour, and butter; melt-in-the-mouth texture similar to South American alfajores, a legacy of Spanish colonial influence.', TRUE),
('candy_niyok_coconut_candy_balls_guamanian', 'Candy Niyok (Coconut Candy Balls)', 415, 3.5, 55.0, 22.0, 3.0, 48.0, 30, 20, 'research', ARRAY['candy niyok (coconut candy balls)', 'kekin niyok', 'coconut candy', 'chamoru coconut balls', 'niyok candy'], 'dessert', NULL, 1, 'GU', 'Traditional CHamoru confection made by cooking freshly grated coconut with sugar until caramelized, then rolling into balls; a childhood favorite often called kekin niyok, reflecting the centrality of coconut (niyok) in CHamoru culture.', TRUE),
('rikamado_chamoru_caramel_candy_guamanian', 'Rikamado (CHamoru Caramel Candy)', 390, 2.5, 68.0, 12.0, 0.0, 60.0, 30, 15, 'research', ARRAY['rikamado (chamoru caramel candy)', 'caramel candy guam', 'chamoru caramel', 'fina''mames rikamado'], 'dessert', NULL, 1, 'GU', 'A traditional CHamoru caramel-style candy made by cooking sugar and condensed milk to a firm caramel consistency; often made during fiestas and rosary gatherings as a homemade sweet.', TRUE),
('kalamai_corn_coconut_pudding_guamanian', 'Kalamai (Corn Coconut Pudding)', 215, 2.5, 38.0, 6.5, 1.0, 18.0, 150, NULL, 'research', ARRAY['kalamai (corn coconut pudding)', 'kalamai dessert', 'corn coconut pudding', 'chamoru corn pudding', 'chalakiles pudding'], 'dessert', NULL, 1, 'GU', 'A traditional CHamoru pudding made from masa harina (or cornstarch), coconut milk, and sugar, often tinted pink and sprinkled with cinnamon; sets firm like jello and is sliced into squares for serving.', TRUE),
('apigige_cassava_coconut_tamale_guamanian', 'Apigige'' (Cassava Coconut Tamale)', 250, 2.5, 38.0, 10.5, 2.0, 14.0, 90, 90, 'research', ARRAY['apigige'' (cassava coconut tamale)', 'apigigi', 'apigigi''', 'cassava tamale', 'sweet chamoru tamale', 'månha apigige'], 'dessert', NULL, 1, 'GU', 'A sweet CHamoru tamale made from grated cassava, young coconut meat (månha), coconut milk, and sugar, grilled in banana leaves; a labor-intensive traditional dessert served at fiestas and special occasions.', TRUE),
('potu_tuba_rice_cakes_guamanian', 'Potu (Tuba Rice Cakes)', 200, 3.5, 38.0, 3.0, 0.5, 8.0, 80, 40, 'research', ARRAY['potu (tuba rice cakes)', 'poto', 'tuba rice cakes', 'chamoru rice cakes', 'potu tuba'], 'dessert', NULL, 1, 'GU', 'Steamed rice cakes leavened with tuba (fermented coconut sap), giving them a subtle tangy-sweet flavor; introduced to Guam by Filipino migrants during the Spanish era, now a beloved CHamoru specialty.', TRUE),
('chalakiles_chicken_toasted_rice_soup_guamanian', 'Chalakiles (Chicken Toasted Rice Soup)', 130, 9.0, 16.0, 3.5, 0.8, 1.5, 250, NULL, 'research', ARRAY['chalakiles (chicken toasted rice soup)', 'chalakilis', 'chamorro rice soup', 'toasted rice porridge'], 'street_food', NULL, 1, 'GU', 'A CHamoru comfort soup made by thickening chicken broth with toasted ground rice, coconut milk, achote, and chili; originated from the tradition of rehydrating dried rice stuck to cooking pots, influenced by Mexican chilaquiles via Spanish colonial trade.', TRUE),
('champuladu_chocolate_rice_porridge_guamanian', 'Champulådu (Chocolate Rice Porridge)', 175, 4.0, 32.0, 4.5, 1.0, 12.0, 200, NULL, 'research', ARRAY['champulådu (chocolate rice porridge)', 'champalado', 'champorado guam style', 'chocolate rice pudding', 'champulado'], 'dessert', NULL, 1, 'GU', 'A CHamoru-style chocolate rice porridge made with rice, cocoa powder, evaporated milk, and sugar; adapted from Filipino champorado and often eaten as a sweet breakfast or dessert on Guam.', TRUE),
('titiyas_maies_corn_flatbread_guamanian', 'Titiyas Mai''es (Corn Flatbread)', 295, 5.5, 54.0, 7.0, 2.5, 3.0, 80, 60, 'research', ARRAY['titiyas mai''es (corn flatbread)', 'corn titiyas', 'masa titiyas', 'chamoru corn flatbread'], 'street_food', NULL, 1, 'GU', 'Traditional CHamoru corn tortilla-style flatbread made from masa harina (corn flour) and coconut milk; one of the oldest forms of titiyas on Guam, with corn cultivation documented as early as 1602 by Spanish friar Juan Pobre de Zamora.', TRUE),
('titiyas_manha_young_coconut_flatbread_guamanian', 'Titiyas Månha (Young Coconut Flatbread)', 320, 5.0, 50.0, 11.0, 2.0, 7.0, 80, 60, 'research', ARRAY['titiyas månha (young coconut flatbread)', 'manha titiyas', 'young coconut flatbread'], 'street_food', NULL, 1, 'GU', 'A special CHamoru flatbread incorporating the juice and soft meat of young coconut (månha) into the dough; the young coconut gives it a naturally sweet, rich flavor distinct from regular flour titiyas.', TRUE),
('konsetba_candied_green_papaya_guamanian', 'Konsetba (Candied Green Papaya)', 270, 0.5, 68.0, 0.2, 1.5, 62.0, 50, 25, 'research', ARRAY['konsetba (candied green papaya)', 'conserva', 'candied papaya', 'green papaya candy', 'chamoru papaya sweet'], 'dessert', NULL, 1, 'GU', 'A traditional CHamoru sweet made by slow-cooking strips of unripe green papaya in a heavy sugar syrup until translucent and candied; a Spanish colonial-era preservation technique still popular at CHamoru fiestas.', TRUE),
('shave_ice_guam_style_guamanian', 'Shave Ice Guam Style', 95, 0.0, 24.0, 0.0, 0.0, 23.0, 200, NULL, 'research', ARRAY['shave ice guam style', 'raspa', 'shaved ice', 'snow cone guam', 'ice shavings'], 'street_food', NULL, 1, 'GU', 'Finely shaved ice doused in sweet flavored syrups (often mango, tamarind, or tropical fruit flavors); a wildly popular street food on Guam blending Hawaiian, Japanese, and local CHamoru flavor preferences.', TRUE),
('shave_ice_with_condensed_milk_guamanian', 'Shave Ice with Condensed Milk', 135, 1.5, 30.0, 1.8, 0.0, 28.0, 220, NULL, 'research', ARRAY['shave ice with condensed milk', 'shave ice kakigori style', 'condensed milk shave ice'], 'street_food', NULL, 1, 'GU', 'Guam-style shave ice drizzled with sweet condensed milk in addition to flavored syrups; the condensed milk version is a local favorite that adds richness to the refreshing island treat.', TRUE),
('lumpia_guisado_vegetable_spring_roll_guam_guamanian', 'Lumpia Guisado (Vegetable Spring Roll Guam)', 240, 6.5, 26.0, 13.0, 2.0, 2.5, 100, 30, 'research', ARRAY['lumpia guisado (vegetable spring roll guam)', 'vegetable lumpia guam', 'veggie spring rolls chamoru', 'fried vegetable rolls'], 'street_food', NULL, 1, 'GU', 'Fried spring rolls filled with a sautéed mix of vegetables (cabbage, carrot, bean sprouts, green beans) and tofu; a vegetable-forward lumpia variation popular at CHamoru potlucks and market stalls across Guam.', TRUE),
('banana_lumpia_turon_guam_style_guamanian', 'Banana Lumpia (Turon Guam Style)', 260, 2.5, 42.0, 10.0, 1.5, 22.0, 90, 70, 'research', ARRAY['banana lumpia (turon guam style)', 'turon', 'banana spring roll', 'sweet lumpia', 'fried banana lumpia'], 'dessert', NULL, 1, 'GU', 'Sweet fried lumpia filled with ripe banana (saba), sugar, and cinnamon; a Filipino-influenced dessert widely adopted into CHamoru cuisine and sold as a popular snack at Guam flea markets.', TRUE),
('bibingka_chamoru_style_rice_cake_guamanian', 'Bibingka CHamoru Style (Rice Cake)', 300, 5.5, 48.0, 10.0, 0.5, 20.0, 100, 80, 'research', ARRAY['bibingka chamoru style (rice cake)', 'bibingka', 'rice cake', 'chamoru coconut rice cake'], 'dessert', NULL, 1, 'GU', 'A baked coconut rice cake made from rice flour, coconut milk, eggs, and sugar; a Filipino-origin specialty embraced in CHamoru cuisine, traditionally cooked in clay pots lined with banana leaves over charcoal.', TRUE),
('puto_chamoru_steamed_rice_muffins_guamanian', 'Puto CHamoru (Steamed Rice Muffins)', 215, 4.0, 40.0, 4.0, 0.5, 12.0, 80, 30, 'research', ARRAY['puto chamoru (steamed rice muffins)', 'puto', 'steamed rice cakes', 'chamoru rice muffins'], 'dessert', NULL, 1, 'GU', 'Soft, fluffy steamed rice flour cakes sweetened with sugar and often topped with salted cheese or butter; a Filipino-influenced CHamoru specialty traditionally served alongside savory dinuguan soup.', TRUE),
('kalamay_sticky_coconut_rice_sweet_guamanian', 'Kalamay (Sticky Coconut Rice Sweet)', 310, 3.0, 55.0, 9.0, 1.0, 28.0, 100, NULL, 'research', ARRAY['kalamay (sticky coconut rice sweet)', 'kalamay hati', 'sticky rice cake', 'biko guam style'], 'dessert', NULL, 1, 'GU', 'A dense, sticky sweet made from glutinous rice flour, coconut milk, and brown sugar; popular in CHamoru and Filipino communities on Guam, often prepared during fiestas and religious celebrations.', TRUE),
