('pinipig_crunch_toasted_rice_flake_snack_guamanian', 'Pinipig Crunch (Toasted Rice Flake Snack)', 365, 5.5, 70.0, 7.0, 1.5, 18.0, 50, NULL, 'research', ARRAY['pinipig crunch (toasted rice flake snack)', 'pinipig', 'toasted rice flakes', 'crispy rice snack'], 'snack', NULL, 1, 'GU', 'Toasted flattened immature rice grains (pinipig) eaten as a crunchy snack or used as a topping for halo-halo and ice cream; a Filipino-origin ingredient and snack widely used in Guam''s Filipino-CHamoru dessert culture.', TRUE),
('maiz_kon_yelo_corn_with_shaved_ice_guamanian', 'Maiz Kon Yelo (Corn with Shaved Ice)', 130, 2.5, 30.0, 2.0, 1.5, 20.0, 250, NULL, 'research', ARRAY['maiz kon yelo (corn with shaved ice)', 'corn with ice', 'mais yelo', 'sweet corn shave ice'], 'street_food', NULL, 1, 'GU', 'A Filipino-style refreshment of sweet canned or fresh corn kernels topped with shaved ice, condensed milk, and evaporated milk; a popular cooling street dessert in Guam''s tropical climate, sold at local snack stalls and fairs.', TRUE),
('pichi_pichi_cassava_pandan_jelly_cake_guamanian', 'Pichi-Pichi (Cassava Pandan Jelly Cake)', 190, 1.5, 40.0, 3.0, 1.0, 16.0, 80, 30, 'research', ARRAY['pichi-pichi (cassava pandan jelly cake)', 'cassava jelly cake', 'pandan pichi pichi', 'coconut cassava cake'], 'dessert', NULL, 1, 'GU', 'A soft, chewy steamed cassava cake infused with pandan flavor and coated in grated coconut; a Filipino-origin delicacy popular at Guam''s local stores and fiesta dessert tables, enjoyed for its bouncy, jelly-like texture.', TRUE),
