('bukayo_sweetened_coconut_strips_guamanian', 'Bukayo (Sweetened Coconut Strips)', 430, 3.0, 60.0, 22.0, 4.0, 52.0, 40, 20, 'research', ARRAY['bukayo (sweetened coconut strips)', 'coconut strip candy', 'sweetened coconut', 'chewy coconut sweet'], 'dessert', NULL, 1, 'GU', 'Long strips of mature coconut meat cooked in sugar syrup until chewy and caramelized; a traditional Filipino-CHamoru sweet sold at Guam markets, related to the CHamoru candy niyok tradition of coconut confections.', TRUE),
('yuca_frita_fried_cassava_sticks_guamanian', 'Yuca Frita (Fried Cassava Sticks)', 280, 2.0, 42.0, 12.0, 2.0, 2.0, 100, NULL, 'research', ARRAY['yuca frita (fried cassava sticks)', 'fried cassava', 'yuca fries', 'cassava fries', 'kamoteng kahoy frita'], 'street_food', NULL, 1, 'GU', 'Boiled cassava (yuca) cut into sticks and deep-fried until golden, served with dipping sauce; a Latin American-origin street snack with strong resonance in Guam due to shared Spanish colonial heritage with the Philippines and Mexico.', TRUE),
('koko_balls_chocolate_coconut_energy_balls_guamanian', 'Koko Balls (Chocolate Coconut Energy Balls)', 440, 5.0, 52.0, 24.0, 3.5, 38.0, 40, 20, 'research', ARRAY['koko balls (chocolate coconut energy balls)', 'coconut chocolate balls', 'no-bake energy balls', 'koko snack balls'], 'dessert', NULL, 1, 'GU', 'No-bake energy balls made from rolled oats, grated coconut, cocoa powder, honey, and peanut butter; a modern health-trend snack popularized on Guam blending American wellness culture with the island''s coconut-forward flavor profile.', TRUE),
('guava_cake_guam_style_guamanian', 'Guava Cake Guam Style', 315, 4.5, 50.0, 11.0, 1.5, 34.0, 100, 100, 'research', ARRAY['guava cake guam style', 'guava butter cake', 'guayaba cake guam', 'local guava cake'], 'dessert', NULL, 1, 'GU', 'A moist butter cake flavored with fresh guava purée and often frosted with guava cream cheese icing; guava grows wild and cultivated across Guam, making it a natural and beloved local cake flavor at bakeries and potlucks.', TRUE),
('mango_cheesecake_guam_style_guamanian', 'Mango Cheesecake Guam Style', 350, 5.5, 38.0, 20.0, 0.5, 30.0, 110, 110, 'research', ARRAY['mango cheesecake guam style', 'mango cream cake', 'tropical cheesecake guam', 'mango topped cheesecake'], 'dessert', NULL, 1, 'GU', 'A rich no-bake or baked cheesecake topped with fresh mango glaze or Carabao mango slices; an American-influenced dessert format adapted with Guam''s prized tropical fruits, sold at local restaurants and special event bakeries.', TRUE),
('tapioca_pudding_sago_pudding_guam_style_guamanian', 'Tapioca Pudding (Sago Pudding Guam Style)', 150, 2.0, 28.0, 4.0, 0.3, 18.0, 150, NULL, 'research', ARRAY['tapioca pudding (sago pudding guam style)', 'sago pudding', 'tapioca coconut pudding', 'pearl pudding'], 'dessert', NULL, 1, 'GU', 'Creamy chilled pudding made from small tapioca pearls cooked in sweetened coconut milk or evaporated milk; a simple, widely enjoyed dessert in Guam households blending American pudding culture with the island''s coconut traditions.', TRUE),
('baked_macaroni_guam_style_mac_salad_guamanian', 'Baked Macaroni Guam Style (Mac Salad)', 220, 6.5, 28.0, 9.5, 1.0, 3.5, 150, NULL, 'research', ARRAY['baked macaroni guam style (mac salad)', 'macaroni salad guam', 'mac salad chamoru', 'tuna mac salad'], 'street_food', NULL, 1, 'GU', 'A creamy American-style macaroni salad enriched with tuna, sweet pickle relish, and mayonnaise; a ubiquitous CHamoru fiesta side dish reflecting Guam''s strong American cultural influence, present at virtually every BBQ and potluck.', TRUE),
('pancit_sotanghon_guam_style_glass_noodle_stir_fry_guamanian', 'Pancit Sotanghon Guam Style (Glass Noodle Stir-Fry)', 155, 7.5, 22.0, 4.0, 1.0, 2.5, 200, NULL, 'research', ARRAY['pancit sotanghon guam style (glass noodle stir-fry)', 'sotanghon noodles guam', 'glass noodle stir-fry chamoru', 'cellophane noodles fiesta'], 'street_food', NULL, 1, 'GU', 'Stir-fried clear glass noodles (cellophane noodles) with chicken, mushrooms, vegetables, and soy sauce; a Filipino noodle dish popular at CHamoru fiestas and birthday parties on Guam, distinct from bihon due to its silky, translucent noodle texture.', TRUE),
('kueh_lapis_spiced_layer_cake_guamanian', 'Kueh Lapis (Spiced Layer Cake)', 305, 5.0, 44.0, 13.0, 0.5, 28.0, 80, 60, 'research', ARRAY['kueh lapis (spiced layer cake)', 'spekkoek', 'layered spice cake', 'indonesian layer cake guam'], 'dessert', NULL, 1, 'GU', 'A rich multi-layered spiced cake made from butter, eggs, flour, and warm spices (cinnamon, cloves, cardamom); introduced via Dutch-Indonesian influence through the Pan-Pacific trade networks that connected Guam to Southeast Asia.', TRUE),
('coconut_milk_ice_cream_sorbetes_niyok_guamanian', 'Coconut Milk Ice Cream (Sorbetes Niyok)', 195, 2.0, 25.0, 10.0, 1.0, 20.0, 100, NULL, 'research', ARRAY['coconut milk ice cream (sorbetes niyok)', 'coconut ice cream', 'niyok ice cream', 'dairy-free coconut sorbet guam'], 'dessert', NULL, 1, 'GU', 'Creamy dairy-free ice cream made entirely from coconut milk, sugar, and vanilla; a natural Guam-style frozen dessert that highlights the island''s beloved coconut ingredient, served in cones or cups at local dessert shops.', TRUE),
('mango_pudding_filipino_chamoru_style_guamanian', 'Mango Pudding (Filipino-CHamoru Style)', 165, 3.0, 28.0, 5.5, 0.8, 22.0, 150, NULL, 'research', ARRAY['mango pudding (filipino-chamoru style)', 'mango jelly pudding', 'chilled mango dessert', 'mango gelatin'], 'dessert', NULL, 1, 'GU', 'A chilled gelatin-set mango pudding made from fresh or canned Carabao mango, evaporated milk, and sugar; a popular Filipino restaurant dessert widely available across Guam''s dining establishments, especially during mango season.', TRUE),
('sigua_sponge_gourd_fritters_guamanian', 'Sigua (Sponge Gourd) Fritters', 185, 4.0, 26.0, 7.5, 2.5, 3.0, 100, 30, 'research', ARRAY['sigua (sponge gourd) fritters', 'luffa fritters', 'sponge gourd fritters', 'sigua chamoru', 'patola fritters'], 'street_food', NULL, 1, 'GU', 'Sliced sponge gourd (sigua/luffa) dipped in a seasoned batter and fried; an underutilized vegetable fritter in CHamoru cooking, sigua grows abundantly across Guam and is used in both savory dishes and innovative fritter preparations.', TRUE),
('fried_taro_cakes_dagu_patties_guamanian', 'Fried Taro Cakes (Dågu Patties)', 225, 4.0, 32.0, 9.0, 3.0, 2.5, 80, 40, 'research', ARRAY['fried taro cakes (dågu patties)', 'taro patties', 'dagu cakes', 'fried taro fritters'], 'street_food', NULL, 1, 'GU', 'Mashed taro mixed with onion, garlic, and seasoning, shaped into patties and pan-fried until golden; a savory CHamoru snack showcasing taro (dågu), one of the most ancient cultivated crops of the indigenous CHamoru people.', TRUE),
('latiya_brownies_chocolate_custard_bars_guamanian', 'Latiya Brownies (Chocolate Custard Bars)', 340, 5.0, 48.0, 15.0, 1.0, 32.0, 80, 60, 'research', ARRAY['latiya brownies (chocolate custard bars)', 'custard brownies guam', 'chocolate latiya bars', 'chamoru fusion brownie'], 'dessert', NULL, 1, 'GU', 'A modern CHamoru fusion dessert combining the classic latiya custard topping with a chocolate brownie base; an innovative local bakery creation that marries CHamoru culinary heritage with American chocolate brownie culture.', TRUE),
('pandanus_jelly_pandan_gulaman_guamanian', 'Pandanus Jelly (Pandan Gulaman)', 70, 1.5, 16.0, 0.0, 0.0, 14.0, 120, NULL, 'research', ARRAY['pandanus jelly (pandan gulaman)', 'pandan jelly', 'gulaman pandan', 'green coconut jelly'], 'dessert', NULL, 1, 'GU', 'A bright green jelly dessert made from agar-agar set with sweetened pandan (pandanus) leaf extract; pandan (pahong) grows across Guam and the fragrant leaf is used extensively in CHamoru and Filipino desserts for color and flavor.', TRUE),
('corn_ice_cream_mais_flavor_ice_cream_guamanian', 'Corn Ice Cream (Mais Flavor Ice Cream)', 200, 3.5, 28.0, 8.5, 0.5, 22.0, 100, NULL, 'research', ARRAY['corn ice cream (mais flavor ice cream)', 'mais ice cream', 'sweet corn ice cream', 'corn sorbetes'], 'dessert', NULL, 1, 'GU', 'Sweet corn-flavored ice cream made with real corn kernels blended into a creamy base; a Filipino-origin ice cream flavor extremely popular in Guam''s ice cream shops, reflecting the island''s deep affection for corn-based foods.', TRUE),
('quezo_de_bola_red_wax_cheese_snack_guamanian', 'Quezo de Bola (Red Wax Cheese Snack)', 350, 22.0, 1.5, 28.0, 0.0, 0.5, 40, NULL, 'research', ARRAY['quezo de bola (red wax cheese snack)', 'edam cheese guam', 'christmas cheese', 'red wax cheese', 'queso de bola'], 'snack', NULL, 1, 'GU', 'Edam cheese encased in red wax, a Spanish colonial-era import tradition; quezo de bola is a CHamoru Christmas staple sliced and served with ensaymada or local sweet bread at holiday gatherings on Guam.', TRUE),
('puto_cheese_steamed_rice_cake_with_cheese_guamanian', 'Puto Cheese (Steamed Rice Cake with Cheese)', 235, 6.0, 38.0, 6.5, 0.3, 12.0, 80, 30, 'research', ARRAY['puto cheese (steamed rice cake with cheese)', 'cheese puto', 'steamed rice muffin with cheese', 'puto with quezo'], 'dessert', NULL, 1, 'GU', 'Soft steamed rice flour muffins topped with a slice of cheddar or Edam cheese; the sweet-salty combination is a defining CHamoru-Filipino flavor pairing beloved across Guam''s bakeries and home kitchens.', TRUE),
