('latiya_mini_cups_individual_custard_cups_guamanian', 'Latiya Mini Cups (Individual Custard Cups)', 265, 5.0, 40.0, 9.5, 0.3, 26.0, 100, 80, 'research', ARRAY['latiya mini cups (individual custard cups)', 'latiya cups', 'individual custard dessert', 'mini latiya'], 'dessert', NULL, 1, 'GU', 'Individual-sized CHamoru latiya served in disposable cups with sponge cake base and custard topping; a modern serving innovation popular at school fundraisers, party catering, and Guam''s Chamorro Village market.', TRUE),
('bread_pudding_guam_style_guamanian', 'Bread Pudding Guam Style', 290, 6.5, 44.0, 10.0, 0.8, 26.0, 120, NULL, 'research', ARRAY['bread pudding guam style', 'chamoru bread pudding', 'local bread custard', 'sweet bread pudding guam'], 'dessert', NULL, 1, 'GU', 'Local sweet bread soaked in a custard mixture of eggs, milk, sugar, and vanilla then baked until golden; an American-influenced dessert adapted in CHamoru kitchens using Guam''s distinctive local sweet bread, often served with a rum or vanilla sauce.', TRUE),
('papaya_shake_fresh_papaya_smoothie_guamanian', 'Papaya Shake (Fresh Papaya Smoothie)', 85, 1.0, 21.0, 0.5, 1.5, 17.0, 300, NULL, 'research', ARRAY['papaya shake (fresh papaya smoothie)', 'papaya smoothie', 'blended papaya drink', 'papaya milkshake guam'], 'street_food', NULL, 1, 'GU', 'A thick, creamy smoothie made from blended ripe papaya, evaporated milk, and sugar over ice; papaya grows abundantly across Guam and the blended fruit shake is a popular refreshment at roadside stands and local juice bars.', TRUE),
('mango_shake_fresh_mango_smoothie_guamanian', 'Mango Shake (Fresh Mango Smoothie)', 130, 1.5, 32.0, 0.5, 1.5, 28.0, 300, NULL, 'research', ARRAY['mango shake (fresh mango smoothie)', 'mango smoothie guam', 'mango milkshake', 'blended mango drink'], 'street_food', NULL, 1, 'GU', 'A thick blended drink made from ripe Carabao mango, ice, and sometimes condensed milk; Guam''s most popular fresh fruit shake, sold at roadside stands and restaurants, showcasing the island''s world-renowned Philippine-variety mangoes.', TRUE),
('donne_sali_bird_pepper_snack_guamanian', 'Donne'' Sali (Bird Pepper Snack)', 40, 1.5, 8.5, 0.5, 3.0, 4.0, 30, NULL, 'research', ARRAY['donne'' sali (bird pepper snack)', 'bird pepper guam', 'donne pepper', 'chamoru hot pepper', 'sili labuyo guam'], 'snack', NULL, 1, 'GU', 'Tiny fiery bird peppers (donne'' sali) eaten fresh, pickled, or as a garnish; the hottest and most culturally significant chili on Guam, donne'' sali is essential to finadene sauce and is believed by some CHamoru families to hold medicinal properties.', TRUE),
('roasted_peanuts_mani_asadu_guamanian', 'Roasted Peanuts (Mani Asadu)', 565, 25.0, 16.0, 49.0, 8.5, 4.0, 30, NULL, 'research', ARRAY['roasted peanuts (mani asadu)', 'roasted mani', 'salted peanuts guam', 'chamoru peanut snack'], 'snack', NULL, 1, 'GU', 'Dry-roasted or oil-roasted peanuts seasoned with salt; a simple, affordable snack sold at Guam''s flea markets and tienda stores, peanuts (mani) were introduced via Spanish colonial trade from Mexico and South America.', TRUE),
('pork_empanada_savory_baked_pork_pastry_guamanian', 'Pork Empanada (Savory Baked Pork Pastry)', 285, 10.0, 35.0, 12.0, 1.0, 2.5, 110, 110, 'research', ARRAY['pork empanada (savory baked pork pastry)', 'baked pork empanada', 'pork pastry guam', 'savory pork turnover'], 'street_food', NULL, 1, 'GU', 'A baked (not fried) pork-filled pastry in a flaky dough crust; the baked version of CHamoru empanada is sold at local bakeries as an alternative to the traditional deep-fried variety, popular as a quick lunch or snack on Guam.', TRUE),
