('koko_pandan_cake_coconut_pandan_layer_cake_guamanian', 'Koko Pandan Cake (Coconut Pandan Layer Cake)', 310, 4.5, 46.0, 12.5, 1.0, 30.0, 110, 110, 'research', ARRAY['koko pandan cake (coconut pandan layer cake)', 'pandan coconut cake', 'green pandan layer cake', 'coconut pandan celebration cake'], 'dessert', NULL, 1, 'GU', 'A light, fragrant green layer cake flavored with pandan extract and filled with coconut cream; a popular celebratory cake at Guam bakeries combining the island''s two most beloved tropical flavors — coconut (niyok) and pandan.', TRUE),
('adobo_fried_rice_guam_style_guamanian', 'Adobo Fried Rice Guam Style', 195, 6.5, 32.0, 5.5, 0.8, 1.5, 200, NULL, 'research', ARRAY['adobo fried rice guam style', 'adobo sinangag', 'chamoru fried rice', 'adobo garlic rice'], 'street_food', NULL, 1, 'GU', 'Leftover adobo meat chopped and fried with day-old rice, garlic, soy sauce, and eggs; a practical and flavorful CHamoru-Filipino staple sold at local eateries and roadside BBQ stands as a complete, satisfying snack meal.', TRUE),
('sinigaw_chamoru_grilled_corn_husked_guamanian', 'Sinigaw (CHamoru Grilled Corn Husked)', 110, 3.5, 22.0, 2.0, 2.5, 5.0, 150, 120, 'research', ARRAY['sinigaw (chamoru grilled corn husked)', 'grilled corn in husk', 'chamoru mais grilled', 'roasted husk corn'], 'street_food', NULL, 1, 'GU', 'Whole corn ears grilled in their husks over open coals until slightly charred, then husked and eaten plain or with finadene; a traditional CHamoru preparation honoring the island''s centuries-long corn cultivation heritage.', TRUE),
