('pistachio_cookies_guam_local_bakery_guamanian', 'Pistachio Cookies Guam Local Bakery', 465, 7.5, 55.0, 24.0, 2.0, 22.0, 40, 15, 'research', ARRAY['pistachio cookies guam local bakery', 'pistachio nut cookies', 'green cookie guam', 'local bakery pistachio'], 'dessert', NULL, 1, 'GU', 'Buttery cookies studded with pistachio nuts; an American-influenced bakery item popular in Guam''s diverse bakery scene, reflecting the island''s exposure to American and military food culture that brought a wide variety of nut-based baked goods.', TRUE),
('mango_sinigang_sour_mango_tamarind_snack_guamanian', 'Mango Sinigang (Sour Mango Tamarind Snack)', 60, 0.8, 14.5, 0.3, 2.0, 9.0, 100, NULL, 'research', ARRAY['mango sinigang (sour mango tamarind snack)', 'sour mango snack', 'green mango sourer', 'manggang pang-asim'], 'snack', NULL, 1, 'GU', 'Green mango pieces used to sour sinigang broth or eaten as a tart fresh snack; a cross-cultural snack on Guam reflecting Filipino sinigang tradition where sour unripe mango acts as the acidifier, also enjoyed raw with salt.', TRUE),
('chammorro_night_market_plate_mixed_snack_plate_guamanian', 'Chammorro Night Market Plate (Mixed Snack Plate)', 420, 18.0, 42.0, 20.0, 2.5, 6.0, 250, NULL, 'research', ARRAY['chammorro night market plate (mixed snack plate)', 'night market plate guam', 'chamoru mixed plate', 'chamorro village sampler'], 'street_food', NULL, 1, 'GU', 'A mixed plate sold at Guam''s famous Chamorro Village Wednesday Night Market combining items like red rice, kelaguen, BBQ meat, titiyas, and lumpia; the night market is a cultural institution showcasing CHamoru food at its most festive.', TRUE),
('inalahan_pepper_jelly_donne_preserve_guamanian', 'Inalahan Pepper Jelly (Donne'' Preserve)', 230, 0.5, 58.0, 0.0, 1.5, 52.0, 30, NULL, 'research', ARRAY['inalahan pepper jelly (donne'' preserve)', 'chamoru pepper jelly', 'hot pepper preserve', 'inalahan chili jelly'], 'snack', NULL, 1, 'GU', 'A sweet-hot pepper jelly made from Inalahan peppers (a local CHamoru chili variety), sugar, and pectin; a prized artisanal condiment from the village of Inalahan in southern Guam, sold as a local specialty food gift.', TRUE),
('coconut_cream_pie_guam_style_guamanian', 'Coconut Cream Pie Guam Style', 310, 4.5, 36.0, 17.0, 1.5, 24.0, 120, 120, 'research', ARRAY['coconut cream pie guam style', 'niyok cream pie', 'coconut custard pie', 'chamoru coconut pie'], 'dessert', NULL, 1, 'GU', 'A classic pie shell filled with rich coconut custard and topped with whipped cream and toasted coconut flakes; an American-origin dessert deeply embraced in Guam''s bakery culture, adapted to use fresh local coconut milk.', TRUE),
