('soursop_nectar_bottled_guamanian', 'Soursop Nectar Bottled', 62, 0.5, 15.5, 0.1, 0.3, 14.0, 240, NULL, 'research', ARRAY['soursop nectar bottled', 'guyabano nectar guam', 'bottled soursop drink', 'commercial soursop juice'], 'beverage', NULL, 1, 'GU', 'Commercially bottled soursop nectar sold throughout Guam; a convenient way to enjoy the beloved guyabano flavor year-round when fresh fruit is unavailable or expensive.', TRUE),
('mango_nectar_packaged_guamanian', 'Mango Nectar Packaged', 68, 0.4, 17.0, 0.1, 0.2, 15.8, 240, NULL, 'research', ARRAY['mango nectar packaged', 'manga nectar guam', 'packaged mango drink', 'del monte mango nectar guam'], 'beverage', NULL, 1, 'GU', 'Thick sweetened mango nectar in cans and bottles; widely available in Guam''s convenience stores and sari-sari shops as a popular commercial alternative to fresh mango juice.', TRUE),
('calamansi_soda_carbonated_guamanian', 'Calamansi Soda Carbonated', 42, 0.1, 10.8, 0.0, 0.0, 10.5, 355, NULL, 'research', ARRAY['calamansi soda carbonated', 'kalamansi soda guam', 'calamansi fizz', 'carbonated citrus drink island'], 'beverage', NULL, 1, 'GU', 'Commercially carbonated calamansi-flavored soda sold in Guam; a modern fizzy take on the island''s most essential citrus flavor, popular with younger consumers as a local soda alternative.', TRUE),
('preserved_coconut_honey_guamanian', 'Preserved Coconut Honey', 290, 0.3, 74.5, 0.5, 0.0, 73.5, 20, NULL, 'research', ARRAY['preserved coconut honey', 'coconut palm honey', 'niyok honey chamoru', 'sweet palm sap syrup'], 'condiment', NULL, 1, 'GU', 'Thick golden syrup made from reduced coconut palm sap; a traditional CHamoru natural sweetener used before cane sugar arrived, sometimes called coconut honey for its texture and amber color.', TRUE),
('spam_sauce_chamoru_fusion_guamanian', 'Spam Sauce CHamoru Fusion', 35, 2.0, 3.5, 1.5, 0.2, 1.8, 15, NULL, 'research', ARRAY['spam sauce chamoru fusion', 'spam hot sauce guam', 'spam chili condiment', 'chamoru spam sauce'], 'condiment', NULL, 1, 'GU', 'A Guam-specific condiment blending pureed Spam with hot peppers and vinegar; a humorous yet beloved local creation celebrating the island''s deep cultural attachment to Spam as a food icon.', TRUE),
('adobo_bottled_sauce_guam_guamanian', 'Adobo Bottled Sauce Guam', 28, 1.2, 4.5, 0.5, 0.2, 2.5, 30, NULL, 'research', ARRAY['adobo bottled sauce guam', 'adobo sauce bottle guam', 'premade adobo guam', 'chamoru adobo condiment'], 'condiment', NULL, 1, 'GU', 'Ready-to-use adobo seasoning sauce sold in Guam supermarkets; a convenience version of the traditional soy-vinegar braise, used by CHamoru cooks for quick weeknight adobo preparations.', TRUE),
('donne_pepper_brine_finadene_base_guamanian', 'Donne Pepper Brine Finadene Base', 10, 0.8, 1.5, 0.1, 0.3, 0.5, 20, NULL, 'research', ARRAY['donne pepper brine finadene base', 'donne brine', 'pepper jar liquid guam', 'chamoru hot brine'], 'condiment', NULL, 1, 'GU', 'The strained liquid brine left from jarred donne peppers, used as a concentrated pepper-vinegar seasoning added to soups and sauces; a zero-waste CHamoru pantry practice turning every drop of the prized condiment jar to good use.', TRUE),
('coconut_leaf_tea_niyok_leaf_infusion_guamanian', 'Coconut Leaf Tea (Niyok Leaf Infusion)', 3, 0.1, 0.6, 0.0, 0.1, 0.2, 240, NULL, 'research', ARRAY['coconut leaf tea (niyok leaf infusion)', 'palm leaf tea guam', 'niyok leaf infusion', 'coconut frond tea'], 'beverage', NULL, 1, 'GU', 'Herbal tea brewed from young tender coconut palm leaves, used in traditional CHamoru folk medicine as a mild diuretic and calming tisane. The tea represents one of the most ancient uses of the coconut palm extending beyond food and drink to medicinal plant traditions.', TRUE)

